const recipes = [
// ==================== 荤菜（海鲜类） ====================
{id:1,name:"蚝烙",category:"meat",ingredients:["鲜蚝","番薯粉","鸡蛋","葱花","香菜","胡椒粉","鱼露"],steps:"鲜蚝洗净沥干。番薯粉加水调成浆，加入蚝、葱花拌匀。平底锅热油，倒入蚝浆摊平，煎至两面金黄。淋上蛋液再煎至酥脆，撒胡椒粉、香菜，蘸鱼露食用。"},
{id:2,name:"白灼虾",category:"meat",ingredients:["鲜虾","姜片","葱段","料酒","生抽","蒜蓉","花生油"],steps:"虾剪去须脚挑虾线。水烧开加姜葱料酒，放入虾煮至变红卷曲（约2-3分钟），捞出过冰水使肉质紧实。蘸料：生抽加蒜蓉淋热油即可。"},
{id:3,name:"清蒸金鲳鱼",category:"meat",ingredients:["金鲳鱼","姜丝","葱丝","蒸鱼豉油","花生油","红椒丝"],steps:"鱼洗净划花刀，铺姜丝。水开上锅大火蒸8-10分钟。倒掉蒸出的腥水，铺上葱丝红椒丝，淋热油激香，最后淋蒸鱼豉油。"},
{id:4,name:"蒜蓉粉丝蒸扇贝",category:"meat",ingredients:["扇贝","粉丝","蒜蓉","葱花","生抽","蚝油","花生油","小米辣"],steps:"粉丝泡软剪段，扇贝洗净留壳。蒜蓉用油炒香加生抽蚝油调汁。壳中铺粉丝、放扇贝、浇蒜蓉汁，大火蒸5分钟，撒葱花淋热油。"},
{id:5,name:"潮州冻蟹",category:"meat",ingredients:["花蟹","姜片","葱段","料酒","陈醋","姜丝"],steps:"蟹洗净，冷水下锅加姜葱料酒煮15分钟至熟。取出自然放凉后入冰箱冷藏2小时。取出斩件，蘸姜丝陈醋食用，蟹肉紧实鲜甜。"},
{id:6,name:"咸梅蒸乌耳鳗",category:"meat",ingredients:["乌耳鳗","咸梅","姜丝","蒜蓉","生抽","花生油","葱花"],steps:"鳗鱼处理干净切段但不断开。咸梅捣碎加生抽调成酱，均匀抹在鳗鱼上。铺姜丝蒜蓉，大火蒸12分钟，出锅撒葱花淋热油。"},
{id:7,name:"蒜蓉蒸虾",category:"meat",ingredients:["大虾","蒜蓉","粉丝","生抽","蚝油","葱花","花生油"],steps:"虾开背去虾线，粉丝泡软铺底。蒜蓉炒香加生抽蚝油调汁。虾铺粉丝上浇蒜蓉汁，大火蒸5分钟，撒葱花淋热油。"},
{id:8,name:"酥炸殿鱼",category:"meat",ingredients:["殿鱼（豆腐鱼）","脆炸粉","鸡蛋","盐","胡椒粉","椒盐"],steps:"殿鱼去头去内脏洗净切段，加盐胡椒粉腌制。裹上脆炸粉蛋液糊，六成热油温炸至金黄酥脆捞出。撒椒盐趁热食用。"},
{id:9,name:"芋头蟹",category:"meat",ingredients:["花蟹","芋头","姜片","葱段","生抽","蚝油","盐","花生油"],steps:"芋头去皮切片铺砂锅底。花蟹洗净斩件铺芋头上。加姜葱、生抽、蚝油、少许水，大火煮开转小火焖15分钟至芋头软糯蟹肉入味。"},
{id:10,name:"芥末虾球",category:"meat",ingredients:["大虾","蛋黄","玉米淀粉","蜂蜜芥末酱","沙拉酱","盐","白胡椒粉"],steps:"虾去壳开背去虾线，用盐、白胡椒粉、蛋黄、淀粉抓拌上浆。中小火炸3-5分钟至酥脆。蜂蜜芥末酱、沙拉酱加芥末调匀，与虾球翻拌均匀。"},
{id:11,name:"酱油王焗虾",category:"meat",ingredients:["鲜虾","生抽","老抽","蚝油","糖","姜片","葱段","料酒"],steps:"虾剪须挑线。热锅下油爆香姜葱，放入虾两面煎至变红。加生抽、老抽、蚝油、糖、料酒和少许水，大火收汁至浓稠即可。"},
{id:12,name:"香煎马鲛鱼",category:"meat",ingredients:["马鲛鱼","盐","姜片","花生油","柠檬"],steps:"马鲛鱼切厚片，用盐和姜片腌制15分钟。平底锅热油，中小火慢煎，每面煎3-4分钟至金黄。挤柠檬汁提鲜，外酥里嫩。"},
{id:13,name:"豆酱蒸鱼",category:"meat",ingredients:["鲜鱼（鲈鱼/黄花鱼）","普宁豆酱","姜丝","葱丝","花生油","红椒丝"],steps:"鱼洗净划花刀，均匀抹上普宁豆酱。铺姜丝，水开大火蒸8-10分钟。出锅倒掉多余汁水，铺葱丝红椒丝，淋热油即可。"},
{id:14,name:"姜葱炒花蟹",category:"meat",ingredients:["花蟹","姜片","葱段","蒜蓉","料酒","生抽","蚝油","盐","淀粉"],steps:"蟹洗净斩件，蟹钳拍裂。热油爆香姜蒜，下蟹大火翻炒至变色。加料酒、生抽、蚝油、盐调味，加少许水焖3分钟，勾薄芡撒葱段出锅。"},
{id:15,name:"白灼鱿鱼",category:"meat",ingredients:["鲜鱿鱼","姜片","葱段","料酒","生抽","芥末","蒜蓉"],steps:"鱿鱼去膜去内脏切圈。水开加姜葱料酒，下鱿鱼焯30秒至卷起变白即捞出（不可久煮）。蘸料：生抽加芥末和蒜蓉。"},
{id:16,name:"砂锅虾蟹粥",category:"meat",ingredients:["膏蟹","鲜虾","大米","干贝","姜丝","冬菜","香菜","胡椒粉","花生酱"],steps:"大米泡30分钟，干贝泡发撕丝。砂锅水开下米和干贝煮至米开花。加入蟹块和虾煮5分钟，加冬菜、花生酱、姜丝、胡椒粉调味，撒香菜。"},
{id:17,name:"紫菜煎蛋",category:"meat",ingredients:["紫菜","鸡蛋","葱花","盐","鱼露","花生油"],steps:"紫菜撕碎用温水泡软挤干。鸡蛋打散加紫菜、葱花、盐、鱼露拌匀。平底锅热油，倒入蛋液摊平，中小火煎至两面金黄即可。"},
{id:18,name:"银鱼煎蛋",category:"meat",ingredients:["银鱼","鸡蛋","葱花","盐","白胡椒粉","花生油"],steps:"银鱼洗净沥干。鸡蛋打散加银鱼、葱花、盐、胡椒粉拌匀。平底锅热油倒入，中小火煎至两面金黄，银鱼的鲜和蛋的香完美融合。"},
{id:19,name:"潮汕鱼丸煮",category:"meat",ingredients:["潮汕鱼丸","生菜","芹菜末","蒜头油","盐","高汤","胡椒粉"],steps:"高汤煮开，放入鱼丸煮至浮起变大。加入生菜烫软，撒芹菜末、蒜头油、盐和胡椒粉调味。鱼丸弹牙鲜美，汤清味醇。"},
{id:20,name:"海鲜粉丝煲",category:"meat",ingredients:["龙口粉丝","虾仁","鱿鱼","干贝","生抽","老抽","蚝油","蒜蓉","葱花"],steps:"粉丝泡30分钟剪短，拌入蛋黄、生抽、老抽、油。砂锅热油爆香蒜蓉，码入粉丝，铺虾仁、鱿鱼、干贝，淋蚝油，盖上焖8分钟，撒葱花。"},
{id:21,name:"潮汕鱼饭",category:"meat",ingredients:["鲜海鱼（巴浪鱼/黄墙）","粗盐","普宁豆酱"],steps:"鱼不去鳞不去内脏，用粗盐抹匀腌制30分钟。放入竹篮中，大锅水开后隔水蒸15分钟。取出放凉，配普宁豆酱蘸食。"},
{id:22,name:"虾枣",category:"meat",ingredients:["虾仁","猪肥肉","马蹄","鸡蛋","腐皮","盐","胡椒粉","五香粉"],steps:"虾仁剁泥，肥肉切小丁，马蹄切碎。混合加鸡蛋、调料拌匀成馅。腐皮包卷成枣形，中温油炸至金黄，外酥里嫩。"},
{id:23,name:"炒薄壳",category:"meat",ingredients:["薄壳（海瓜子）","金不换（九层塔）","蒜蓉","姜丝","辣椒","鱼露","花生油"],steps:"薄壳洗净沥干。热油爆香蒜姜辣椒，下薄壳大火爆炒。壳开时加入金不换和鱼露，快速翻炒几下即可出锅。"},
{id:24,name:"椒盐濑尿虾",category:"meat",ingredients:["濑尿虾（皮皮虾）","椒盐","蒜蓉","辣椒","葱花","料酒","淀粉"],steps:"濑尿虾洗净沥干，拍薄淀粉。六成热油炸至酥脆捞出。热锅少许油炒香蒜蓉辣椒，放入炸好的虾，撒椒盐和葱花翻炒均匀。"},
{id:25,name:"冬菜蒸鱼",category:"meat",ingredients:["鲜鱼","潮汕冬菜","姜丝","葱丝","生抽","花生油"],steps:"鱼洗净，冬菜切碎铺鱼身上，加姜丝。大火蒸8-10分钟。出锅倒掉汁水，铺葱丝淋热油，淋少许生抽。"},
{id:26,name:"红焖海参",category:"meat",ingredients:["水发海参","香菇","虾米","蚝油","生抽","老抽","糖","姜片","葱段"],steps:"海参切块焯水。热油爆香姜葱虾米香菇，下海参翻炒。加蚝油、生抽、老抽、糖和清水，小火焖30分钟至入味，收汁出锅。"},
{id:27,name:"血蚌",category:"meat",ingredients:["血蚌","蒜蓉","生抽","陈醋","辣椒","香油","香菜"],steps:"血蚌刷洗干净，用滚水烫5-8秒即刻捞起（切勿久烫）。蘸料：蒜蓉、生抽、陈醋、辣椒、香油调匀。掰开直接食用，鲜嫩多汁。"},
{id:28,name:"香煎沙尖鱼",category:"meat",ingredients:["沙尖鱼","盐","姜片","花生油","柠檬"],steps:"沙尖鱼去鳞去内脏洗净，盐和姜片腌制15分钟。平底锅热油，中火煎至两面金黄酥脆。挤柠檬汁，连骨头都可以吃。"},
{id:29,name:"虾仁炒蛋",category:"meat",ingredients:["虾仁","鸡蛋","葱花","盐","白胡椒粉","料酒","花生油"],steps:"虾仁用料酒和胡椒粉腌制。鸡蛋打散加盐。热油炒虾仁至变色盛出。锅中加油倒蛋液，半凝固时加入虾仁和葱花，翻炒至嫩滑出锅。"},
{id:30,name:"鲍鱼捞饭",category:"meat",ingredients:["鲜鲍鱼","米饭","蚝油","生抽","老抽","糖","姜片","西兰花"],steps:"鲍鱼刷洗干净刻花刀。热油爆姜，加蚝油、生抽、老抽、糖和少许水煮汁。放入鲍鱼焖5分钟入味。饭上浇鲍鱼和酱汁，配烫好的西兰花。"},
{id:31,name:"潮式蒸鱼腩",category:"meat",ingredients:["鱼腩（鲩鱼/草鱼腩）","豆豉","姜丝","蒜蓉","生抽","花生油","葱花"],steps:"鱼腩切块，豆豉剁碎。鱼腩铺盘，撒豆豉、姜丝、蒜蓉。大火蒸8分钟。出锅倒掉汁水，撒葱花淋热油和生抽。"},
{id:32,name:"芹菜炒鱿鱼",category:"meat",ingredients:["鲜鱿鱼","芹菜","姜丝","蒜蓉","盐","蚝油","料酒"],steps:"鱿鱼切花刀切片，芹菜切段。鱿鱼焯水5秒捞出。热油爆香姜蒜，下鱿鱼大火翻炒，加芹菜、蚝油、料酒、盐快速翻炒出锅。"},
{id:33,name:"烙鱼",category:"meat",ingredients:["小鱼（凤尾鱼/池鱼）","番薯粉","鸡蛋","葱花","盐","胡椒粉"],steps:"小鱼去内脏洗净。番薯粉调浆，加鸡蛋、葱花、盐拌匀。平底锅热油，小鱼裹浆入锅摊平，煎至两面金黄酥脆。"},
{id:34,name:"清蒸大闸蟹",category:"meat",ingredients:["大闸蟹","姜片","紫苏叶","陈醋","姜丝","糖"],steps:"蟹刷洗干净，肚朝上放姜片和紫苏叶。水开大火蒸15-20分钟。蘸料：陈醋加姜丝和少许糖调匀。原汁原味，蟹黄鲜美。"},
{id:35,name:"蒜香炸排骨",category:"meat",ingredients:["排骨","蒜蓉","生抽","蚝油","料酒","糖","淀粉","鸡蛋"],steps:"排骨斩小段，加蒜蓉、生抽、蚝油、料酒、糖腌制30分钟。加鸡蛋和淀粉抓匀。六成热油温炸至金黄捞出，复炸一遍更酥脆。"},
{id:36,name:"五香炸鸡翅",category:"meat",ingredients:["鸡中翅","五香粉","生抽","蚝油","蒜蓉","料酒","淀粉"],steps:"鸡翅划两刀，加五香粉、生抽、蚝油、蒜蓉、料酒腌制1小时。裹淀粉，六成热油炸至金黄，捞出复炸至酥脆。"},
{id:37,name:"沙茶牛肉",category:"meat",ingredients:["牛肉","沙茶酱","洋葱","青椒","生抽","蚝油","糖","淀粉"],steps:"牛肉逆纹切片，加生抽、淀粉腌制。热油爆香洋葱，下牛肉大火滑炒至变色盛出。锅中加沙茶酱、蚝油、糖炒香，倒回牛肉和青椒快速翻炒。"},
{id:38,name:"薯仔焖鸡",category:"meat",ingredients:["鸡肉","土豆","姜片","蒜","生抽","老抽","蚝油","八角","糖"],steps:"鸡斩块焯水，土豆切滚刀块。热油爆香姜蒜八角，下鸡块炒至金黄。加生抽、老抽、蚝油、糖和清水，大火煮开转小火焖20分钟，加土豆再焖15分钟至软烂。"},
{id:39,name:"红烧牛腩",category:"meat",ingredients:["牛腩","白萝卜","姜","八角","桂皮","生抽","老抽","蚝油","冰糖"],steps:"牛腩切块焯水。热油爆香姜和香料，下牛腩翻炒。加生抽、老抽、蚝油、冰糖和足量热水，小火炖1.5小时。加入白萝卜块再炖30分钟至软烂。"},
{id:40,name:"咕噜肉",category:"meat",ingredients:["猪梅花肉","菠萝","青椒","红椒","番茄酱","白醋","糖","淀粉","鸡蛋"],steps:"猪肉切块，加蛋液和淀粉抓匀。六成热油炸至金黄。糖醋汁：番茄酱、白醋、糖、水调匀煮开。倒入肉块、菠萝、青红椒翻炒均匀即可。"},
{id:41,name:"咸菜炒猪肉",category:"meat",ingredients:["猪五花肉","潮汕咸菜","姜丝","蒜","生抽","糖","花生油"],steps:"五花肉切片，咸菜切丝泡水去咸。热锅不放油，五花肉煎出油盛出。用肉油炒咸菜出香味，倒回肉片，加糖、生抽翻炒均匀。"},
{id:42,name:"榨菜炒肉丝",category:"meat",ingredients:["猪瘦肉","榨菜","青椒","姜丝","生抽","蚝油","料酒","淀粉"],steps:"瘦肉切丝，加生抽、料酒、淀粉腌制。榨菜切丝冲水去咸。热油滑炒肉丝变色盛出。爆香姜丝，下榨菜和青椒翻炒，倒回肉丝，加蚝油调味。"},
{id:43,name:"瘦肉炒青瓜",category:"meat",ingredients:["猪瘦肉","青瓜","蒜蓉","盐","蚝油","料酒","淀粉"],steps:"瘦肉切片腌制备用。青瓜切片。热油滑肉片变色盛出。爆香蒜蓉，下青瓜翻炒，倒回肉片，加蚝油、盐调味出锅。"},
{id:44,name:"蒜蓉南瓜蒸排骨",category:"meat",ingredients:["排骨","南瓜","蒜蓉","生抽","蚝油","淀粉","糖","豆豉"],steps:"排骨斩小块，加蒜蓉、生抽、蚝油、糖、豆豉、淀粉腌制30分钟。南瓜去皮切块铺盘底，码上腌好的排骨。大火蒸25分钟至排骨软烂。"},
{id:45,name:"肉沫炒吊瓜",category:"meat",ingredients:["猪肉末","吊瓜（黄瓜）","蒜蓉","生抽","蚝油","盐","花生油"],steps:"吊瓜去皮切片。热油炒肉末至变白，加蒜蓉炒香。下吊瓜大火翻炒，加生抽、蚝油、盐调味，翻炒至瓜软熟即可。"},
{id:46,name:"春菜猪肉",category:"meat",ingredients:["猪五花肉","春菜","盐","蒜蓉","花生油"],steps:"五花肉切片煎出油至微焦，加盐捞出。锅中留底油，放春菜大火翻炒至出香味。倒回肉片，加少许水和盐，盖盖焖8分钟至春菜软烂。"},
{id:47,name:"梅菜扣肉",category:"meat",ingredients:["猪五花肉","梅菜干","老抽","生抽","冰糖","料酒","姜片","八角"],steps:"五花肉整块煮至七成熟，皮戳孔抹老抽炸至金黄。切片皮朝下码碗中。梅菜泡软切碎炒香铺肉上，加调料蒸2小时。倒扣盘中。"},
{id:48,name:"蒜苗炒腊肉",category:"meat",ingredients:["腊肉","蒜苗","姜片","干辣椒","生抽","糖"],steps:"腊肉温水洗净切片。蒜苗切斜段。热锅少油，腊肉煎出油透明卷起。下姜片干辣椒爆香，加蒜苗大火翻炒，加少许糖和生抽调味。"},
{id:49,name:"菠萝猪排",category:"meat",ingredients:["猪排","菠萝","蒜片","白胡椒粉","盐","生抽","淀粉"],steps:"猪排剁松，加蒜片、白胡椒粉、盐、生抽、淀粉水腌制。煎至两面金黄。加入菠萝块翻炒均匀，酸甜开胃。"},
{id:50,name:"莲藕焖猪手",category:"meat",ingredients:["猪手","莲藕","姜","八角","桂皮","生抽","老抽","蚝油","冰糖"],steps:"猪手斩块焯水。莲藕去皮切滚刀块。热油爆香姜和香料，下猪手炒至微焦。加生抽老抽蚝油冰糖和足量水，大火煮开转小火焖1小时，加莲藕再焖40分钟。"},
{id:51,name:"干炒牛河",category:"meat",ingredients:["牛肉","河粉","豆芽","韭黄","葱段","生抽","老抽","蚝油"],steps:"牛肉切片腌制滑油盛出。热锅多油下河粉煎至微焦。加豆芽、韭黄翻炒，加生抽老抽调味。倒回牛肉和葱段，大火翻炒均匀。"},
{id:52,name:"牛肉炒芥蓝",category:"meat",ingredients:["牛肉","芥蓝","姜丝","蒜蓉","沙茶酱","生抽","蚝油","料酒","淀粉"],steps:"牛肉逆纹切片，加沙茶酱、生抽、料酒、淀粉腌制。芥蓝去老叶切段。热油大火滑牛肉变色盛出。爆香姜蒜，下芥蓝大火翻炒，倒回牛肉，加蚝油炒匀。"},
{id:53,name:"牛肉炒口蘑",category:"meat",ingredients:["牛肉","口蘑","蒜蓉","生抽","蚝油","黑胡椒","料酒","淀粉"],steps:"牛肉切片腌制，口蘑切片。热油滑牛肉变色盛出。蒜蓉爆香，下口蘑炒至出水变软。倒回牛肉，加蚝油、黑胡椒翻炒均匀。"},
{id:54,name:"腐竹焖牛腩",category:"meat",ingredients:["牛腩","腐竹","姜","八角","桂皮","香叶","生抽","老抽","蚝油","冰糖"],steps:"牛腩焯水，腐竹泡软。热油爆香姜和香料，下牛腩翻炒。加调料和热水，小火炖1.5小时。加入腐竹再焖15分钟至入味。"},
{id:55,name:"西芹炒牛肉",category:"meat",ingredients:["牛肉","西芹","红椒","蒜蓉","生抽","蚝油","料酒","淀粉"],steps:"牛肉逆纹切丝腌制。西芹去筋切斜段。热油滑牛肉变色盛出。爆香蒜蓉，下西芹红椒翻炒，倒回牛肉加蚝油大火翻炒出锅。"},
{id:56,name:"猪脚炖花生",category:"meat",ingredients:["猪脚","花生","姜","八角","生抽","老抽","蚝油","冰糖","料酒"],steps:"猪脚斩块焯水，花生提前泡2小时。热油爆香姜八角，下猪脚翻炒。加调料和足量水，大火煮开转小火炖1.5-2小时至软烂入味。"},
{id:57,name:"酸甜排骨",category:"meat",ingredients:["排骨","番茄酱","白醋","糖","菠萝","青红椒","淀粉","鸡蛋"],steps:"排骨斩块焯水煮20分钟。裹蛋液和淀粉，油炸至金黄。糖醋汁煮开：番茄酱+白醋+糖+水。加入排骨、菠萝、青红椒翻炒均匀。"},
{id:58,name:"蒜香排骨",category:"meat",ingredients:["排骨","蒜蓉","生抽","蚝油","料酒","蜂蜜","黑胡椒"],steps:"排骨加调料和大量蒜蓉腌制2小时。烤箱200度烤25分钟，或空气炸锅180度20分钟，中途翻面刷蜂蜜。蒜香浓郁，外焦里嫩。"},
{id:59,name:"猪肉丸煮紫菜",category:"meat",ingredients:["潮汕猪肉丸","紫菜","芹菜末","蒜头油","盐","胡椒粉"],steps:"清水煮开，下猪肉丸煮至浮起。紫菜撕碎放入，加盐、胡椒粉调味。撒芹菜末和蒜头油即可。"},
{id:60,name:"麻油猪腰",category:"meat",ingredients:["猪腰","麻油","姜片","米酒","枸杞","生抽","盐"],steps:"猪腰对剖去筋膜，切花刀片成薄片，反复泡水去腥。水开烫10秒捞出。麻油爆香姜片，下腰花大火翻炒，加米酒、枸杞、生抽和盐快速出锅。"},
{id:61,name:"牛肉丸煮生菜",category:"meat",ingredients:["潮汕牛肉丸","生菜","芹菜末","蒜头油","盐","胡椒粉","高汤"],steps:"高汤煮开，放入牛肉丸煮至浮起变大。生菜洗净撕块放入烫软。加盐、胡椒粉调味，撒芹菜末和蒜头油。"},
{id:62,name:"香菇焖猪蹄",category:"meat",ingredients:["猪蹄","干香菇","姜","八角","桂皮","生抽","老抽","蚝油","冰糖"],steps:"猪蹄焯水，香菇泡发。热油爆香姜和香料，下猪蹄翻炒至微焦。加调料和泡香菇水，大火煮开转小火焖1.5小时至软烂脱骨。"},
{id:63,name:"芥菜煲排骨",category:"meat",ingredients:["排骨","大芥菜","姜片","蒜","盐","胡椒粉"],steps:"排骨焯水。砂锅加水煮排骨30分钟。大芥菜切块放入，继续煮20分钟至芥菜软烂。加盐和胡椒粉调味，汤鲜菜甜。"},
{id:64,name:"洋葱炒牛肉",category:"meat",ingredients:["牛肉","洋葱","青椒","生抽","蚝油","黑胡椒","料酒","淀粉"],steps:"牛肉逆纹切片腌制。洋葱切丝。热油滑牛肉变色盛出。炒香洋葱至透明，下青椒翻炒，倒回牛肉，加蚝油黑胡椒大火炒匀。"},
{id:65,name:"豆豉蒸排骨",category:"meat",ingredients:["排骨","豆豉","蒜蓉","姜丝","生抽","蚝油","糖","淀粉","辣椒"],steps:"排骨斩小块，加剁碎的豆豉、蒜蓉、姜丝、生抽、蚝油、糖、淀粉腌制30分钟。大火蒸20分钟，撒葱花即可。"},
{id:66,name:"青椒炒牛肉",category:"meat",ingredients:["牛肉","青椒","蒜","姜","生抽","蚝油","料酒","淀粉","黑胡椒"],steps:"牛肉切片逆纹腌制。青椒切块。热油滑牛肉变色盛出。爆香姜蒜，下青椒翻炒，倒回牛肉，加蚝油黑胡椒大火快速翻炒。"},
{id:67,name:"咸菜炒牛肉",category:"meat",ingredients:["牛肉","潮汕咸菜","姜丝","辣椒","生抽","蚝油","糖","淀粉"],steps:"牛肉切片腌制，咸菜切丝泡水。热油滑牛肉变色盛出。爆香姜丝辣椒，下咸菜炒香，倒回牛肉，加糖和蚝油大火翻炒。"},
{id:68,name:"肉沫茄子煲",category:"meat",ingredients:["猪肉末","茄子","蒜蓉","生抽","蚝油","老抽","糖","葱花","辣椒"],steps:"茄子切条不油炸，干锅煸软。肉末炒香加蒜蓉辣椒。放入茄子，加生抽老抽蚝油糖和少许水，焖5分钟入味。撒葱花出锅。"},
{id:69,name:"豉汁蒸排骨",category:"meat",ingredients:["排骨","豆豉","蒜蓉","姜丝","生抽","蚝油","糖","淀粉","花生油"],steps:"排骨斩小块，豆豉剁碎。所有调料混合腌制排骨30分钟。大火蒸20分钟。豉香浓郁，排骨嫩滑。"},
{id:70,name:"虾酱蒸猪肉",category:"meat",ingredients:["猪五花肉","虾酱","姜丝","糖","料酒","花生油"],steps:"五花肉切薄片，加虾酱、姜丝、糖、料酒拌匀腌制20分钟。大火蒸15分钟。虾酱咸鲜，配饭绝佳。"},
{id:71,name:"咸蛋蒸肉饼",category:"meat",ingredients:["猪肉末","咸鸭蛋","姜末","生抽","蚝油","糖","淀粉","葱花"],steps:"肉末加姜末、生抽、蚝油、糖、淀粉拌匀。铺入盘中压平，中间压一个凹放咸蛋黄。大火蒸15分钟，出锅撒葱花。"},
{id:72,name:"菜脯蛋",category:"meat",ingredients:["菜脯（萝卜干）","鸡蛋","葱花","花生油"],steps:"菜脯切细粒泡水去咸挤干。鸡蛋打散加菜脯和葱花。平底锅热油，倒入蛋液，中小火煎至两面金黄。咸香下饭，潮汕经典。"},
{id:73,name:"卤水猪大肠",category:"meat",ingredients:["猪大肠","卤水料包","生抽","老抽","冰糖","姜","蒜"],steps:"猪大肠用面粉和盐反复搓洗去异味。焯水后放入卤水中，大火煮开转小火卤40分钟。捞出切段，可配蒜泥醋蘸食。"},
{id:74,name:"冬菇蒸鸡",category:"meat",ingredients:["鸡肉","干香菇","姜丝","红枣","生抽","蚝油","糖","料酒","淀粉"],steps:"干香菇泡发切片，红枣去核。鸡肉斩块加所有调料腌制30分钟。大火蒸20分钟，香菇香和鸡鲜融合，汤汁拌饭一绝。"},
{id:75,name:"萝卜焖牛腩",category:"meat",ingredients:["牛腩","白萝卜","姜","八角","桂皮","香叶","柱候酱","生抽","老抽","冰糖"],steps:"牛腩焯水，萝卜去皮切块。热油爆姜和香料，下牛腩和柱候酱炒香。加调料和热水，小火焖1.5小时，加萝卜再焖40分钟。"},
{id:76,name:"香煎猪排",category:"meat",ingredients:["猪排","生抽","蚝油","料酒","糖","蒜","黑胡椒","黄油"],steps:"猪排用刀背剁松，加调料腌制30分钟。平底锅加黄油，中大火每面煎2-3分钟至金黄。静置2分钟后切片，外焦里嫩。"},
{id:77,name:"花生焖猪尾",category:"meat",ingredients:["猪尾","花生","姜","八角","生抽","老抽","蚝油","冰糖"],steps:"猪尾斩段焯水去毛。花生提前泡2小时。热油爆香姜八角，下猪尾翻炒。加调料和水，焖1.5小时至软烂，胶原蛋白丰富。"},
{id:78,name:"沙茶炒牛肉",category:"meat",ingredients:["牛肉","沙茶酱","洋葱","青椒","蒜","生抽","蚝油","料酒","淀粉"],steps:"牛肉逆纹切片，加沙茶酱、生抽、料酒、淀粉腌制。热油滑牛肉变色盛出。炒香洋葱，下青椒，倒回牛肉加蚝油大火翻炒。"},
{id:79,name:"豉汁蒸鱼头",category:"meat",ingredients:["大鱼头","豆豉","蒜蓉","姜丝","辣椒","生抽","蚝油","糖","淀粉"],steps:"鱼头洗净斩开。豆豉剁碎加蒜蓉姜丝辣椒和调料拌匀。均匀抹在鱼头上腌制15分钟。大火蒸12分钟，淋热油撒葱花。"},
{id:80,name:"干煎马友鱼",category:"meat",ingredients:["马友鱼","盐","姜","花生油","柠檬"],steps:"鱼处理干净划花刀，盐和姜腌制20分钟。平底锅热油，中火慢煎至两面金黄酥脆。挤柠檬汁，皮脆肉嫩。"},
{id:81,name:"潮汕卤鹅",category:"meat",ingredients:["狮头鹅","卤水料包","生抽","老抽","冰糖","南姜","蒜","香菜头"],steps:"整鹅处理干净焯水。卤水：老卤加南姜、蒜、香菜头、生抽老抽冰糖和香料包。鹅放入卤水，大火煮开转小火浸卤40-60分钟。捞出晾凉斩件。"},
{id:82,name:"白切鸡",category:"meat",ingredients:["三黄鸡","姜","葱","料酒","沙姜","生抽","花生油"],steps:"水开加姜葱料酒。鸡三提三浸（提着鸡脖子浸入滚水再提起，重复三次），然后完全浸入，小火浸煮25分钟。捞出过冰水，斩件。蘸料：沙姜末+生抽+热油。"},
{id:83,name:"盐焗鸡",category:"meat",ingredients:["三黄鸡","盐焗鸡粉","姜","葱","沙姜粉","花生油"],steps:"鸡处理干净擦干，内外抹盐焗鸡粉和沙姜粉腌制2小时。电饭煲底铺姜葱，放入鸡，煮饭模式两次。取出撕成条，淋蒸出的鸡汁。"},
{id:84,name:"照烧鸡排",category:"meat",ingredients:["鸡大腿","料酒","生抽","老抽","蚝油","蜂蜜","姜蒜"],steps:"鸡腿去骨剁松肉筋。调料混合成照烧汁。鸡皮朝下煎至金黄翻面，倒入照烧汁，中小火收汁至浓稠挂在鸡排上。切块装盘。"},
{id:85,name:"砂锅鸡煲",category:"meat",ingredients:["鸡肉","香菇","洋葱","姜","蒜","葱段","生抽","老抽","蚝油","料酒"],steps:"鸡肉斩块腌制。砂锅热油爆香姜蒜洋葱，码入鸡块和香菇。淋生抽老抽蚝油料酒，盖盖中火焖15分钟。开盖撒葱段，香气四溢。"},
{id:86,name:"酱油鸡",category:"meat",ingredients:["整鸡","生抽","老抽","冰糖","姜","葱","八角","桂皮"],steps:"鸡处理干净。锅中加生抽、老抽、冰糖、姜葱、八角和适量水煮开。放入鸡，小火煮20分钟，中途翻面几次。收汁上色，斩件淋酱汁。"},
{id:87,name:"姜葱炒鸡",category:"meat",ingredients:["鸡肉","姜片","葱段","蒜","生抽","蚝油","料酒","糖","淀粉"],steps:"鸡斩块加调料腌制。热油爆香姜蒜，下鸡块煎至两面金黄。加料酒、生抽、蚝油、糖和少许水，焖5分钟，加葱段大火收汁。"},
{id:88,name:"香菇滑鸡",category:"meat",ingredients:["鸡腿肉","干香菇","姜丝","红枣","生抽","蚝油","糖","料酒","淀粉"],steps:"鸡腿肉切块，香菇泡发切片，红枣去核。所有材料加调料拌匀腌制20分钟。大火蒸15-18分钟。鸡肉嫩滑，香菇鲜香。"},
{id:89,name:"苦瓜炒鸡蛋",category:"meat",ingredients:["苦瓜","鸡蛋","蒜蓉","盐","糖","花生油"],steps:"苦瓜对剖去瓤切片，用盐腌制10分钟挤去苦水。鸡蛋打散先炒熟盛出。炒香蒜蓉，下苦瓜大火翻炒至软，倒回鸡蛋，加糖和盐调味。"},
{id:90,name:"韭菜花炒鸡蛋",category:"meat",ingredients:["韭菜花","鸡蛋","盐","花生油","鱼露"],steps:"韭菜花洗净切段。鸡蛋打散加少许盐炒熟盛出。热油下韭菜花大火翻炒至断生。倒回鸡蛋，加鱼露调味翻炒均匀。"},
{id:91,name:"潮州卤水鸭",category:"meat",ingredients:["鸭子","卤水料包","生抽","老抽","冰糖","南姜","蒜"],steps:"鸭处理干净焯水。卤水煮开放入鸭，小火浸卤40-50分钟。捞出晾凉斩件，淋少许卤汁和香油。"},
{id:92,name:"咖喱鸡",category:"meat",ingredients:["鸡肉","土豆","洋葱","咖喱粉","椰浆","生抽","盐","糖"],steps:"鸡块腌制煎黄。炒香洋葱，加咖喱粉炒出香味。加入鸡块、土豆、椰浆和水，煮开后小火炖20分钟至土豆软烂，汤汁浓稠。"},
{id:93,name:"蜜汁叉烧",category:"meat",ingredients:["猪梅花肉","叉烧酱","生抽","蚝油","蜂蜜","南乳","五香粉","蒜"],steps:"肉切长条，加所有调料腌制过夜。烤箱200度每面烤15分钟，中途刷蜂蜜水。或空气炸锅180度20分钟。切片配饭一流。"},
{id:94,name:"红焖羊肉",category:"meat",ingredients:["羊肉","白萝卜","姜","当归","八角","桂皮","生抽","老抽","蚝油","冰糖"],steps:"羊肉焯水去膻。热油爆姜和香料，下羊肉翻炒。加调料和水，大火煮开转小火焖1.5小时。加白萝卜再焖30分钟至软烂。"},
{id:95,name:"豆酱焖鸡",category:"meat",ingredients:["鸡肉","普宁豆酱","姜","蒜","生抽","蚝油","料酒","糖"],steps:"鸡斩块，豆酱捣碎。热油爆姜蒜，下鸡块煎黄。加豆酱、生抽、蚝油、料酒、糖和少许水，盖盖焖15分钟，收汁出锅。"},
{id:96,name:"沙姜鸡",category:"meat",ingredients:["鸡肉","沙姜","生抽","盐","花生油","葱段"],steps:"鸡肉斩块，沙姜拍碎切末。热油炒香沙姜，下鸡块大火翻炒至变色，加生抽盐调味，加少许水焖熟。出锅前撒葱段。"},
{id:97,name:"可乐鸡翅",category:"meat",ingredients:["鸡中翅","可乐","生抽","老抽","姜片","料酒","芝麻"],steps:"鸡翅划两刀，焯水去腥。热油煎鸡翅至两面金黄。加生抽老抽姜片，倒入可乐没过鸡翅。大火煮开转中火收汁至浓稠，撒芝麻。"},
{id:98,name:"芝麻鸡",category:"meat",ingredients:["鸡胸肉","白芝麻","生抽","蚝油","料酒","蜂蜜","姜蒜"],steps:"鸡胸肉切条加调料腌制。裹上白芝麻。空气炸锅180度10分钟或烤箱烤至金黄。外酥里嫩，芝麻焦香。"},
{id:99,name:"腊味合蒸",category:"meat",ingredients:["腊肉","腊肠","腊鸭腿","姜丝","生抽","料酒"],steps:"腊肉腊肠腊鸭腿温水洗净切片。码入盘中，撒姜丝，淋少许生抽和料酒。大火蒸15分钟。腊味咸香，油脂浸润米饭。"},
{id:100,name:"蚝油草菇牛肉",category:"meat",ingredients:["牛肉","草菇","姜","蒜","蚝油","生抽","料酒","淀粉","糖"],steps:"牛肉切片腌制，草菇对半切焯水。热油滑牛肉变色盛出。爆香姜蒜，下草菇翻炒，加蚝油、糖和少量水。倒回牛肉大火翻炒均匀。"},
{id:101,name:"潮汕卤水拼盘",category:"meat",ingredients:["猪耳","鹅掌","鹅翼","豆腐","卤水料包","生抽","老抽","冰糖","南姜"],steps:"各种食材分别处理干净焯水。卤水煮开，依次放入鹅掌、鹅翼（卤40分钟）、猪耳（卤30分钟）、豆腐（卤15分钟）。捞出切件摆盘，淋卤汁。"},
{id:102,name:"香芋扣肉",category:"meat",ingredients:["芋头","猪五花肉","南乳","生抽","老抽","蚝油","糖","八角","蒜"],steps:"五花肉整块煮至七成熟，皮戳孔炸至金黄。切厚片与芋头片相间码入碗中。南乳、生抽等调料调成酱汁淋入。蒸2小时至软烂，倒扣盘中。"},
{id:103,name:"香菇蒸鸡",category:"meat",ingredients:["鸡肉","干香菇","木耳","金针菇","姜丝","生抽","蚝油","料酒","淀粉"],steps:"香菇木耳泡发，金针菇去根。鸡块加调料腌制30分钟。所有食材拌匀，大火蒸20分钟。鸡肉嫩滑多汁，菌菇增鲜。"},
{id:104,name:"潮汕牛肉火锅",category:"meat",ingredients:["鲜牛肉","牛肉丸","牛百叶","白萝卜","芹菜末","沙茶酱","蒜头油"],steps:"牛骨熬汤底，白萝卜切块同煮。牛肉逆纹切薄片，汤滚后涮8-10秒即可。蘸沙茶酱配芹菜末和蒜头油。牛肉丸久煮更弹牙。"},
{id:105,name:"猪肚鸡汤",category:"meat",ingredients:["猪肚","整鸡","白胡椒粒","姜片","红枣","枸杞","盐"],steps:"猪肚用面粉和盐反复搓洗去腥。整鸡塞入猪肚内，加白胡椒粒、姜片。大火煮开转小火煲2小时。取出猪肚鸡斩件，汤加枸杞红枣，加盐调味。"},
{id:106,name:"糯米蒸排骨",category:"meat",ingredients:["排骨","糯米","生抽","蚝油","料酒","糖","姜","蒜","荷叶"],steps:"糯米泡4小时沥干。排骨加调料腌制1小时。荷叶铺蒸笼，排骨裹糯米摆入。大火蒸40分钟至糯米软糯排骨脱骨。荷叶清香扑鼻。"},
{id:107,name:"葱油鸡",category:"meat",ingredients:["三黄鸡","葱","姜","生抽","花生油","盐"],steps:"鸡白切做法煮熟斩件。大量葱花和姜末铺在鸡上。热油浇在葱姜上激香。淋生抽即可。葱香浓郁，鸡肉嫩滑。"},
{id:108,name:"黑椒牛肉粒",category:"meat",ingredients:["牛里脊","黑胡椒","生抽","蚝油","料酒","糖","黄油","蒜"],steps:"牛肉切2厘米方粒，加调料腌制。黄油热锅，大火煎牛肉粒表面焦香内里粉嫩（每面约1分钟）。加蒜片和现磨黑胡椒翻炒出锅。"},

// ==================== 素菜类 ====================
{id:109,name:"白灼菜心",category:"vegetable",ingredients:["菜心","蒜蓉","生抽","蚝油","花生油"],steps:"菜心洗净去老叶。水开加盐和油，放入菜心焯1-2分钟至翠绿。捞出摆盘淋生抽蚝油，铺蒜蓉，淋热油激香。清甜脆嫩。"},
{id:110,name:"蒜蓉炒春菜",category:"vegetable",ingredients:["春菜","蒜蓉","盐","蚝油","花生油"],steps:"春菜洗净切段。热油大蒜爆香，下春菜大火翻炒至变软出水。加盐和蚝油调味，炒至菜叶软熟即可。春菜微苦回甘。"},
{id:111,name:"豆豉鲮鱼油麦菜",category:"vegetable",ingredients:["油麦菜","豆豉鲮鱼罐头","蒜蓉","生抽","花生油"],steps:"油麦菜洗净切段。打开豆豉鲮鱼罐头，鲮鱼撕成小块。热油爆香蒜蓉，下油麦菜大火翻炒至变软。加入豆豉鲮鱼和少许生抽翻炒均匀。"},
{id:112,name:"蒜蓉西兰花",category:"vegetable",ingredients:["西兰花","蒜蓉","盐","蚝油","花生油"],steps:"西兰花切小朵，盐水浸泡洗净。沸水加油盐焯1分钟捞出。热油爆香蒜蓉，下西兰花加蚝油盐大火翻炒均匀即可。"},
{id:113,name:"普宁豆酱炒空心菜",category:"vegetable",ingredients:["空心菜","普宁豆酱","蒜蓉","辣椒","花生油"],steps:"空心菜摘段洗净。热油爆香蒜蓉和辣椒，下空心菜大火爆炒。加入普宁豆酱翻炒均匀。豆酱的咸鲜带出空心菜的清甜。"},
{id:114,name:"潮汕炒麻叶",category:"vegetable",ingredients:["麻叶","普宁豆酱","蒜蓉","花生油"],steps:"嫩麻叶摘好洗净，焯水去涩味挤出水分。热油爆香蒜蓉，下麻叶翻炒，加入普宁豆酱炒匀。麻叶是潮汕经典家常菜，配粥一绝。"},
{id:115,name:"八宝素菜",category:"vegetable",ingredients:["莲子","香菇","干草菇","冬笋","发菜","腐竹","木耳","黄花菜","生抽","蚝油"],steps:"所有干货提前泡发。冬笋切片焯水。热油炒香香菇，加入所有材料翻炒。加生抽蚝油和泡香菇水，小火焖20分钟至入味。汤汁勾芡。"},
{id:116,name:"蒜蓉炒番薯叶",category:"vegetable",ingredients:["番薯叶","蒜蓉","盐","鱼露","花生油"],steps:"番薯叶摘嫩茎叶洗净。热油爆香蒜蓉，下番薯叶大火快速翻炒。加盐和少许鱼露调味。嫩滑可口，最家常的潮汕青菜。"},
{id:117,name:"煎豆腐",category:"vegetable",ingredients:["老豆腐","盐","花生油","葱花","生抽"],steps:"豆腐切厚片用厨房纸吸干水分。平底锅热油，中火煎至两面金黄。撒盐和葱花，淋少许生抽。外焦里嫩，豆香浓郁。"},
{id:118,name:"番茄炒蛋",category:"vegetable",ingredients:["番茄","鸡蛋","葱花","盐","糖","番茄酱","花生油"],steps:"鸡蛋打散炒熟盛出。番茄切块入锅炒出汁，加番茄酱和糖。倒回鸡蛋翻炒均匀，撒葱花。酸甜可口，家常经典。"},
{id:119,name:"蚝油生菜",category:"vegetable",ingredients:["生菜","蚝油","生抽","蒜蓉","糖","花生油","淀粉"],steps:"生菜洗净。水开加油盐，生菜焯10秒捞出摆盘。蚝油、生抽、糖、蒜蓉和水煮开，勾薄芡淋在生菜上。脆嫩鲜甜。"},
{id:120,name:"蒜蓉炒芥蓝",category:"vegetable",ingredients:["芥蓝","蒜蓉","盐","蚝油","花生油","料酒"],steps:"芥蓝去老叶，粗茎对剖。热油爆香蒜蓉，下芥蓝大火翻炒。沿锅边淋少许料酒和水，盖盖焖1分钟。加蚝油和盐调味出锅。"},
{id:121,name:"肉沫茄子",category:"vegetable",ingredients:["茄子","猪肉末","蒜蓉","生抽","老抽","蚝油","糖","葱花","辣椒"],steps:"茄子切条。热油炒肉末至变色，加蒜蓉辣椒炒香。放入茄子，加生抽老抽蚝油糖，大火翻炒至茄子软烂入味。撒葱花。"},
{id:122,name:"咸蛋黄焗南瓜",category:"vegetable",ingredients:["南瓜","咸蛋黄","盐","淀粉","花生油"],steps:"南瓜去皮切条，焯水至半熟沥干拍淀粉油炸至金黄。咸蛋黄蒸熟碾碎。少许油炒咸蛋黄至起泡，放入南瓜条翻炒均匀裹上蛋黄。"},
{id:123,name:"蒜蓉粉丝蒸娃娃菜",category:"vegetable",ingredients:["娃娃菜","粉丝","蒜蓉","生抽","蚝油","葱花","花生油"],steps:"粉丝泡软铺盘底。娃娃菜对剖焯水铺粉丝上。蒜蓉炒香加生抽蚝油调汁淋在菜上。大火蒸8分钟，撒葱花淋热油。"},
{id:124,name:"干煸四季豆",category:"vegetable",ingredients:["四季豆","猪肉末","蒜蓉","干辣椒","生抽","盐","花椒"],steps:"四季豆去筋掰段。热油煸炒四季豆至表面起皱盛出。炒香肉末、蒜蓉、干辣椒和花椒。倒回四季豆，加生抽和盐翻炒均匀。"},
{id:125,name:"潮式炒茄子",category:"vegetable",ingredients:["茄子","普宁豆酱","蒜蓉","辣椒","九层塔","花生油"],steps:"茄子切条。热油爆香蒜蓉辣椒，下茄子翻炒。加普宁豆酱和少许水，焖至茄子软烂。出锅前撒九层塔翻炒几下，潮味十足。"},
{id:126,name:"蚝油冬瓜",category:"vegetable",ingredients:["冬瓜","蚝油","生抽","蒜蓉","葱花","花生油","高汤"],steps:"冬瓜去皮去瓤切厚片。热油爆香蒜蓉，下冬瓜翻炒。加蚝油、生抽和高汤（或清水），大火煮开转中火焖至冬瓜透明软烂。撒葱花。"},
{id:127,name:"炒土豆丝",category:"vegetable",ingredients:["土豆","青椒","干辣椒","蒜","白醋","盐","花椒"],steps:"土豆去皮切细丝泡水去淀粉沥干。热油爆香蒜、干辣椒和花椒。下土豆丝大火爆炒，沿锅边淋白醋。加青椒丝和盐，翻炒至断生即可。"},
{id:128,name:"红烧豆腐",category:"vegetable",ingredients:["老豆腐","木耳","胡萝卜","葱段","生抽","老抽","蚝油","糖","蒜蓉"],steps:"豆腐切三角块煎至两面金黄。木耳泡发撕小朵，胡萝卜切片。爆香蒜蓉，加豆腐、木耳、胡萝卜，加水调料焖10分钟。勾芡撒葱段。"},
{id:129,name:"清炒莴笋",category:"vegetable",ingredients:["莴笋","蒜蓉","盐","蚝油","花生油","枸杞"],steps:"莴笋去皮切片。沸水加盐焯30秒捞出。热油爆香蒜蓉，下莴笋大火翻炒。加蚝油和盐调味，撒几粒枸杞点缀。清脆爽口。"},
{id:130,name:"豆酱炒豆角",category:"vegetable",ingredients:["豆角","普宁豆酱","蒜蓉","花生油"],steps:"豆角去头尾掰段，焯水至断生。热油爆香蒜蓉，下豆角翻炒。加普宁豆酱调味，翻炒均匀。简单快手，咸香下饭。"},
{id:131,name:"醋溜白菜",category:"vegetable",ingredients:["大白菜","干辣椒","蒜","白醋","生抽","盐","糖","淀粉"],steps:"白菜帮和叶分开，帮斜切片。热油爆香蒜和干辣椒，先下白菜帮炒软。加白菜叶、生抽、白醋、盐、糖翻炒。勾薄芡出锅，酸辣开胃。"},
{id:132,name:"韭菜炒豆芽",category:"vegetable",ingredients:["韭菜","绿豆芽","蒜","盐","蚝油","花生油"],steps:"韭菜切段，豆芽洗净沥干。热油爆香蒜，下豆芽大火翻炒至微软。加入韭菜快速翻炒。加蚝油和盐调味，大火翻炒十几秒出锅。"},
{id:133,name:"清炒丝瓜",category:"vegetable",ingredients:["丝瓜","蒜蓉","盐","花生油","枸杞"],steps:"丝瓜去皮切滚刀块。热油爆香蒜蓉，下丝瓜翻炒。加少许水煮2-3分钟至丝瓜变软出水。加盐调味，撒枸杞。清甜滑嫩。"},
{id:134,name:"蒜蓉炒苋菜",category:"vegetable",ingredients:["红苋菜","蒜蓉","盐","鱼露","花生油"],steps:"苋菜摘嫩茎叶洗净。热油爆香蒜蓉，下苋菜大火翻炒至软。加盐和少许鱼露调味。汤汁红润，拌饭绝美。"},
{id:135,name:"上汤娃娃菜",category:"vegetable",ingredients:["娃娃菜","皮蛋","咸鸭蛋","火腿","蒜蓉","高汤","盐"],steps:"皮蛋咸蛋切丁，火腿切丝。热油炒香蒜蓉，加高汤煮开。放入对剖的娃娃菜煮软。加入皮蛋咸蛋火腿煮2分钟，加盐调味。"},
{id:136,name:"西芹炒百合",category:"vegetable",ingredients:["西芹","鲜百合","红椒","蒜蓉","盐","蚝油","花生油"],steps:"西芹去筋切斜段，百合剥片洗净。西芹焯水30秒。热油爆香蒜蓉，下西芹和红椒翻炒。加百合（易熟后放），加盐蚝油快速炒匀。"},
{id:137,name:"蒜蓉炒菠菜",category:"vegetable",ingredients:["菠菜","蒜蓉","盐","蚝油","花生油"],steps:"菠菜洗净去根。沸水加油盐焯30秒捞出挤干（去草酸）。热油爆香蒜蓉，下菠菜快速翻炒。加蚝油和盐调味出锅。"},
{id:138,name:"红烧冬瓜",category:"vegetable",ingredients:["冬瓜","生抽","老抽","蚝油","糖","蒜蓉","葱花"],steps:"冬瓜去皮切大块。热油煎冬瓜两面微黄。加生抽老抽蚝油糖，加水焖煮15分钟至冬瓜透明入味。大火收汁撒葱花。"},
{id:139,name:"酸辣土豆丝",category:"vegetable",ingredients:["土豆","干辣椒","花椒","蒜","白醋","盐","葱段"],steps:"土豆切细丝泡水去淀粉沥干。热油爆香花椒干辣椒蒜。下土豆丝大火爆炒。沿锅边淋白醋，加盐和葱段。翻炒至断生出锅，脆爽酸辣。"},
{id:140,name:"榄菜炒四季豆",category:"vegetable",ingredients:["四季豆","橄榄菜","蒜蓉","盐","花生油"],steps:"四季豆去筋切粒。沸水焯至断生捞出。热油爆香蒜蓉，下四季豆翻炒。加橄榄菜翻炒均匀。橄榄菜咸香，配粥下饭皆宜。"},
{id:141,name:"潮汕丝瓜烙",category:"vegetable",ingredients:["丝瓜","虾仁","腊肠","菜脯","葱花","红薯淀粉","盐","白胡椒粉"],steps:"丝瓜去皮切条，虾仁切丁，腊肠和菜脯切碎。所有材料加红薯淀粉和水拌成糊。平底锅热油，倒入面糊摊平，煎至两面金黄。"},
{id:142,name:"玉米烙",category:"vegetable",ingredients:["玉米粒","红薯淀粉","糖","花生油"],steps:"玉米粒拌红薯淀粉裹匀。平底锅热油，玉米粒铺平压实。中小火煎至底部金黄，翻面继续煎。出锅撒糖，香甜酥脆。"},
{id:143,name:"南瓜烙",category:"vegetable",ingredients:["南瓜","红薯淀粉","糖","花生油","芝麻"],steps:"南瓜去皮刨丝。加红薯淀粉、少许糖和水拌匀。平底锅热油，南瓜丝铺平压实。煎至两面金黄，撒芝麻和糖。"},
{id:144,name:"萝卜干炒蛋",category:"vegetable",ingredients:["萝卜干","鸡蛋","葱花","花生油"],steps:"萝卜干切碎泡水去咸挤干。鸡蛋打散加萝卜干和葱花。平底锅热油倒入，中小火煎至两面金黄。咸香酥脆，配粥经典。"},
{id:145,name:"咸菜炒豆芽",category:"vegetable",ingredients:["潮汕咸菜","绿豆芽","蒜","韭菜","盐","花生油"],steps:"咸菜切丝泡水。热油爆香蒜，下咸菜翻炒出香。加入豆芽大火爆炒。加韭菜段和少许盐翻炒至断生。脆嫩咸香。"},
{id:146,name:"橄榄菜炒饭",category:"vegetable",ingredients:["隔夜饭","橄榄菜","鸡蛋","葱花","花生油","生抽"],steps:"鸡蛋炒散盛出。热油炒散米饭，加橄榄菜翻炒均匀。加入鸡蛋和葱花，淋少许生抽。橄榄菜独特的咸香让炒饭升华。"},
{id:147,name:"萝卜糕",category:"vegetable",ingredients:["白萝卜","粘米粉","虾米","腊肠","香菇","盐","胡椒粉"],steps:"萝卜刨丝煮软。粘米粉调浆。虾米腊肠香菇切碎炒香。所有材料混合调味，倒入模具蒸40分钟。凉后切片煎至两面金黄。"},
{id:148,name:"芋头糕",category:"vegetable",ingredients:["芋头","粘米粉","虾米","腊肠","五香粉","盐","花生油"],steps:"芋头去皮切小丁。粘米粉调浆。虾米腊肠切碎炒香，加芋头丁翻炒。混合粉浆和调料，倒入模具蒸45分钟。凉后切片香煎。"},
{id:149,name:"菜头粿",category:"vegetable",ingredients:["白萝卜","粘米粉","红薯粉","虾米","芹菜","盐","胡椒粉"],steps:"白萝卜刨丝加盐挤出水分。粘米粉和红薯粉混合调浆。加入萝卜丝、虾米、芹菜末和调料。倒入模具蒸40分钟。凉后切片煎至焦香。"},
{id:150,name:"荷兰豆炒腊肠",category:"vegetable",ingredients:["荷兰豆","腊肠","蒜蓉","盐","蚝油","花生油"],steps:"荷兰豆去筋洗净焯水。腊肠切片。热油炒腊肠出油，加蒜蓉炒香。下荷兰豆大火翻炒，加蚝油盐调味。清脆咸甜。"},
{id:151,name:"清炒豆苗",category:"vegetable",ingredients:["豆苗","蒜蓉","盐","蚝油","花生油","料酒"],steps:"豆苗摘去老茎洗净沥干。热油爆香蒜蓉，下豆苗大火快炒。沿锅边淋料酒，加盐和蚝油翻炒十几秒出锅。鲜嫩爽脆。"},
{id:152,name:"咸菜炒豆干",category:"vegetable",ingredients:["潮汕咸菜","豆干","蒜","辣椒","生抽","糖","花生油"],steps:"咸菜切丝泡水，豆干切片。热油煎豆干至两面金黄盛出。炒香蒜和辣椒，下咸菜翻炒。倒回豆干，加生抽糖翻炒均匀。"},
{id:153,name:"上汤苋菜",category:"vegetable",ingredients:["红苋菜","皮蛋","咸鸭蛋","蒜","高汤","盐"],steps:"皮蛋咸蛋切丁，蒜拍扁。热油炸香蒜至金黄，加高汤煮开。下皮蛋咸蛋煮2分钟。放入苋菜煮软，加盐调味。汤汁鲜美红润。"},
{id:154,name:"虾酱炒通菜",category:"vegetable",ingredients:["空心菜","虾酱","蒜蓉","辣椒","蚝油","花生油"],steps:"空心菜摘段洗净。虾酱用少许水调开。热油爆香蒜蓉辣椒，下虾酱炒香。放入空心菜大火爆炒，加蚝油，快速翻炒出锅。"},
{id:155,name:"鱼香茄子",category:"vegetable",ingredients:["茄子","猪肉末","蒜蓉","姜末","豆瓣酱","生抽","陈醋","糖","葱花"],steps:"茄子切条过油或干煸。炒肉末至变色，加豆瓣酱炒出红油。加姜蒜末、生抽、陈醋、糖调成鱼香味。放入茄子翻炒入味，撒葱花。"},
{id:156,name:"凉拌黄瓜",category:"vegetable",ingredients:["黄瓜","蒜蓉","陈醋","生抽","糖","香油","辣椒油","香菜"],steps:"黄瓜拍碎切段。所有调料混合成酱汁。浇在黄瓜上拌匀，腌制10分钟入味。清爽开胃，夏日必备。"},
{id:157,name:"素炒合菜",category:"vegetable",ingredients:["绿豆芽","韭菜","粉丝","鸡蛋","生抽","盐","蒜"],steps:"粉丝泡软，鸡蛋炒散。热油炒豆芽至微软。加韭菜和粉丝大火翻炒。加鸡蛋、生抽和盐，快速翻炒均匀出锅。"},
{id:158,name:"蒜蓉炒大芥菜",category:"vegetable",ingredients:["大芥菜","蒜蓉","盐","蚝油","花生油","姜片"],steps:"大芥菜洗净切段。沸水焯1分钟去苦味捞出。热油爆香蒜蓉姜片，下芥菜大火翻炒。加蚝油和盐调味，炒至软熟。"},
{id:159,name:"素炒平菇",category:"vegetable",ingredients:["平菇","青椒","红椒","蒜","蚝油","生抽","盐","花生油"],steps:"平菇撕小朵焯水挤干。青红椒切丝。热油爆香蒜，下平菇大火翻炒至微焦。加青红椒、蚝油、生抽、盐翻炒均匀。"},
{id:160,name:"炒南瓜",category:"vegetable",ingredients:["南瓜","蒜蓉","葱","盐","蚝油","花生油"],steps:"南瓜去皮去瓤切薄片。热油爆香蒜蓉，下南瓜片翻炒。加少许水焖3-5分钟至南瓜软糯。加蚝油和盐调味，撒葱花。"},
{id:161,name:"凉拌木耳",category:"vegetable",ingredients:["干木耳","蒜蓉","陈醋","生抽","糖","香油","辣椒油","香菜","芝麻"],steps:"木耳泡发洗净撕小朵，沸水焯2分钟捞出过凉水。所有调料混合成酱汁浇在木耳上，撒香菜和芝麻拌匀。爽脆开胃。"},
{id:162,name:"白灼秋葵",category:"vegetable",ingredients:["秋葵","蒜蓉","生抽","蚝油","花生油","芥末"],steps:"秋葵用盐搓去绒毛洗净。水开加油盐焯2分钟捞出过冰水。切去蒂头摆盘。蒜蓉生抽蚝油调汁，淋热油。蘸芥末酱油更佳。"},
{id:163,name:"清炒藕片",category:"vegetable",ingredients:["莲藕","蒜","盐","白醋","葱花","花生油"],steps:"莲藕去皮切薄片泡水防氧化。沸水加白醋焯30秒捞出。热油爆香蒜，下藕片大火翻炒。加盐和少许白醋，撒葱花出锅。清脆爽口。"},
{id:164,name:"素炒西兰花",category:"vegetable",ingredients:["西兰花","胡萝卜","木耳","蒜蓉","盐","蚝油","花生油"],steps:"西兰花切小朵，胡萝卜切片，木耳泡发。所有蔬菜焯水1分钟。热油爆香蒜蓉，下蔬菜大火翻炒，加蚝油盐调味。"},
{id:165,name:"花生拌芹菜",category:"vegetable",ingredients:["芹菜","花生米","胡萝卜","盐","生抽","香油","陈醋","花椒油"],steps:"花生米煮熟。芹菜切段和胡萝卜丁焯水。所有材料混合，加调料拌匀。清爽脆口，下酒下饭。"},
{id:166,name:"普宁豆酱炒豆苗",category:"vegetable",ingredients:["豆苗","普宁豆酱","蒜蓉","花生油"],steps:"豆苗摘去老茎洗净。热油爆香蒜蓉，下豆苗大火快炒。加普宁豆酱调味，翻炒十几秒出锅。豆酱咸鲜配豆苗清甜。"},
{id:167,name:"蒜蓉炒娃娃菜",category:"vegetable",ingredients:["娃娃菜","蒜蓉","盐","蚝油","花生油"],steps:"娃娃菜对剖洗净。热油爆香蒜蓉，下娃娃菜大火翻炒。加少许水焖2分钟至软。加蚝油和盐调味出锅。"},
{id:168,name:"潮汕芥蓝炒粿条",category:"vegetable",ingredients:["粿条","芥蓝","蒜蓉","生抽","老抽","蚝油","花生油"],steps:"粿条撕散。热油煎粿条至微焦盛出。爆香蒜蓉，下芥蓝大火翻炒。加粿条、生抽、老抽、蚝油翻炒均匀。锅气十足。"},
{id:169,name:"炒地瓜叶",category:"vegetable",ingredients:["番薯叶","蒜蓉","盐","鱼露","花生油","辣椒"],steps:"番薯叶摘嫩茎叶，撕去外皮。热油爆香蒜蓉辣椒，下番薯叶大火快速翻炒。加盐和少许鱼露。嫩滑可口，潮汕家常青菜首选。"},
{id:170,name:"煎酿豆腐",category:"vegetable",ingredients:["老豆腐","猪肉末","香菇","葱花","生抽","蚝油","淀粉","盐"],steps:"豆腐切三角块中间挖小洞。肉末加香菇碎和调料拌匀酿入豆腐。平底锅煎至两面金黄。加少许水生抽焖3分钟，勾芡出锅。"},
{id:171,name:"蒜蓉炒苦瓜",category:"vegetable",ingredients:["苦瓜","蒜蓉","豆豉","盐","糖","蚝油","花生油"],steps:"苦瓜对剖去瓤切薄片，盐腌10分钟挤去苦水。热油爆香蒜蓉豆豉，下苦瓜大火翻炒。加糖和蚝油调味。苦中回甘，清热下火。"},
{id:172,name:"潮汕炒粿",category:"vegetable",ingredients:["粿条","鸡蛋","豆芽","韭菜","生抽","老抽","蚝油","蒜蓉"],steps:"粿条撕散。鸡蛋炒散。热油爆香蒜蓉，下粿条煎至微焦。加豆芽韭菜、鸡蛋、生抽老抽蚝油大火翻炒。经典潮汕炒粿。"},
{id:173,name:"菜脯炒饭",category:"vegetable",ingredients:["隔夜饭","菜脯","鸡蛋","葱花","生抽","花生油"],steps:"菜脯切碎泡水挤干。鸡蛋炒散。热油炒菜脯出香，下米饭炒散。加鸡蛋、葱花、生抽翻炒均匀。菜脯咸香，简单美味。"},
{id:174,name:"腐乳炒通菜",category:"vegetable",ingredients:["空心菜","腐乳","蒜蓉","辣椒","糖","花生油"],steps:"空心菜摘段洗净。腐乳压碎加少许水和糖调开。热油爆香蒜蓉辣椒，下空心菜大火爆炒。淋腐乳汁快速翻炒均匀出锅。"},
{id:175,name:"素炒三丝",category:"vegetable",ingredients:["土豆","青椒","胡萝卜","蒜","盐","白醋","蚝油","花生油"],steps:"土豆、青椒、胡萝卜切丝。土豆丝泡水去淀粉。热油爆香蒜，下胡萝卜丝和土豆丝大火翻炒。加青椒丝、盐、白醋、蚝油炒匀。"},
{id:176,name:"蒜蓉蒸茄子",category:"vegetable",ingredients:["茄子","蒜蓉","生抽","蚝油","糖","葱花","花生油","辣椒"],steps:"茄子洗净整条蒸10分钟至软。取出撕成条摆盘。蒜蓉炒香加生抽蚝油糖调汁淋上。撒葱花辣椒，淋热油激香。"},
{id:177,name:"猪油渣炒菜心",category:"vegetable",ingredients:["菜心","猪油渣","蒜蓉","盐","蚝油","花生油"],steps:"菜心洗净切段。猪油渣切碎。热油炒香猪油渣和蒜蓉，下菜心大火翻炒。加蚝油和盐调味。猪油渣的焦香让菜心更美味。"},
{id:178,name:"金银蛋上汤菠菜",category:"vegetable",ingredients:["菠菜","皮蛋","咸鸭蛋","蒜","高汤","盐","枸杞"],steps:"菠菜焯水去草酸。皮蛋咸蛋切丁。热油炸香蒜，加高汤煮开。下皮蛋咸蛋煮2分钟，放入菠菜和枸杞，加盐调味。"},
{id:179,name:"沙茶酱炒豆角",category:"vegetable",ingredients:["豆角","沙茶酱","蒜蓉","盐","花生油"],steps:"豆角去头尾掰段焯水。热油爆香蒜蓉，加沙茶酱炒香。下豆角大火翻炒，加少许水焖2分钟。加盐调味。沙茶风味独特。"},
{id:180,name:"杂菌煲",category:"vegetable",ingredients:["鲜香菇","金针菇","杏鲍菇","蟹味菇","蒜蓉","蚝油","生抽","葱"],steps:"各种菇类洗净。砂锅热油爆香蒜蓉，码入所有菇类。淋蚝油生抽和少许水，盖盖焖8分钟。开盖撒葱花。"},

// ==================== 汤品类 ====================
{id:181,name:"苦瓜排骨黄豆汤",category:"soup",ingredients:["苦瓜","排骨","黄豆","咸菜","姜片","盐"],steps:"黄豆提前泡2小时。排骨焯水洗净。苦瓜去瓤切块。所有材料放入砂锅，加水大火煮开转小火煲1.5-2小时。加盐调味，甘甜回甘。"},
{id:182,name:"牛肉丸生菜汤",category:"soup",ingredients:["潮汕牛肉丸","生菜","芹菜末","蒜头油","盐","胡椒粉","高汤"],steps:"高汤或清水煮开，放入牛肉丸煮至浮起变大（约8分钟）。生菜洗净撕块放入烫软。加盐、胡椒粉调味，撒芹菜末和蒜头油。"},
{id:183,name:"莲角排骨汤",category:"soup",ingredients:["排骨","莲角（菱角）","胡萝卜","姜片","盐","蜜枣"],steps:"排骨焯水，莲角去壳，胡萝卜切滚刀块。所有材料放入砂锅，加足量水、姜片和蜜枣。大火煮开转小火煲1.5小时，加盐调味。"},
{id:184,name:"紫菜牛肉丸汤",category:"soup",ingredients:["牛肉丸","紫菜","芹菜末","蒜头油","盐","胡椒粉"],steps:"清水煮开，下牛肉丸煮至浮起。紫菜撕碎放入，煮1分钟。加盐、胡椒粉调味，撒芹菜末和蒜头油。简单快手，鲜美无比。"},
{id:185,name:"猪肚胡椒汤",category:"soup",ingredients:["猪肚","白胡椒粒","姜片","红枣","枸杞","盐","咸菜"],steps:"猪肚用面粉和盐反复搓洗干净。开水烫一下刮去白膜。胡椒粒拍碎。所有材料放入砂锅，加水大火煮开转小火煲2小时。猪肚捞出切条，汤加盐和咸菜片调味。"},
{id:186,name:"冬瓜薏米排骨汤",category:"soup",ingredients:["冬瓜","排骨","薏米","姜片","盐","蜜枣"],steps:"薏米提前泡2小时。排骨焯水。冬瓜去皮去瓤切大块。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，清热祛湿。"},
{id:187,name:"鱼丸紫菜汤",category:"soup",ingredients:["潮汕鱼丸","紫菜","芹菜末","蒜头油","盐","胡椒粉","高汤"],steps:"高汤煮开，下鱼丸煮至浮起。紫菜撕碎放入煮1分钟。加盐、胡椒粉调味，撒芹菜末和蒜头油。清爽鲜美。"},
{id:188,name:"玉米胡萝卜排骨汤",category:"soup",ingredients:["排骨","甜玉米","胡萝卜","姜片","盐","蜜枣"],steps:"排骨焯水，玉米切段，胡萝卜切滚刀块。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，汤甜味美。"},
{id:189,name:"老火莲藕汤",category:"soup",ingredients:["莲藕","猪骨","花生","章鱼干","姜片","盐","蜜枣"],steps:"莲藕去皮切厚片。猪骨焯水，花生泡水，章鱼干泡软。所有材料放入砂锅，加水大火煮开转小火煲2小时。汤色乳白，藕香浓郁。"},
{id:190,name:"橄榄猪肺汤",category:"soup",ingredients:["猪肺","青橄榄","猪骨","姜片","盐","蜜枣"],steps:"猪肺反复灌水挤压洗净至变白，切块焯水。青橄榄拍裂。所有材料放入砂锅，加水大火煮开转小火煲2小时。加盐调味，润肺止咳。"},
{id:191,name:"枸杞叶猪肝汤",category:"soup",ingredients:["枸杞叶","猪肝","姜丝","盐","料酒","花生油","枸杞"],steps:"猪肝切薄片用料酒姜丝腌制去腥。水开下姜丝和枸杞，放入猪肝煮至变色（约30秒）。放入枸杞叶烫软，加盐和少许油调味。"},
{id:192,name:"番茄薯仔排骨汤",category:"soup",ingredients:["番茄","土豆","排骨","姜片","盐","蜜枣"],steps:"排骨焯水，番茄切块，土豆去皮切块。热油炒番茄出汁。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，酸甜开胃。"},
{id:193,name:"虫草花鸡汤",category:"soup",ingredients:["鸡肉","虫草花","红枣","枸杞","姜片","盐"],steps:"鸡肉斩块焯水。虫草花泡发。所有材料放入炖盅或砂锅，加水隔水炖2-3小时或砂锅煲1.5小时。加盐调味，滋补养颜。"},
{id:194,name:"淮山枸杞排骨汤",category:"soup",ingredients:["排骨","铁棍山药","枸杞","红枣","姜片","盐"],steps:"排骨焯水。山药去皮切段（戴手套防过敏）。所有材料放入砂锅，加水大火煮开转小火煲1小时。加盐调味，健脾养胃。"},
{id:195,name:"鲫鱼豆腐汤",category:"soup",ingredients:["鲫鱼","嫩豆腐","姜片","葱段","盐","白胡椒粉","花生油"],steps:"鲫鱼处理干净擦干水分。热油煎至两面金黄。加足量开水（一定要开水），加姜片葱段大火煮10分钟至汤变白。加入豆腐再煮5分钟，加盐和胡椒粉调味。"},
{id:196,name:"菜干猪骨汤",category:"soup",ingredients:["白菜干","猪骨","胡萝卜","蜜枣","姜片","盐","南北杏"],steps:"菜干提前泡软洗净切段。猪骨焯水。所有材料放入砂锅，加水大火煮开转小火煲2小时。加盐调味，清热润肺。"},
{id:197,name:"苦瓜黄豆排骨汤",category:"soup",ingredients:["苦瓜","排骨","黄豆","咸菜","姜片","盐"],steps:"黄豆提前泡2小时。排骨焯水。苦瓜去瓤切大块。所有材料放入砂锅，加水大火煮开转小火煲1.5-2小时。加盐调味，甘甜清热。"},
{id:198,name:"花胶鸡汤",category:"soup",ingredients:["花胶","鸡肉","红枣","枸杞","姜片","盐","料酒"],steps:"花胶提前泡发2天（每天换水）。鸡肉焯水。所有材料放入炖盅，加水隔水炖2-3小时。加盐调味，胶原蛋白丰富。"},
{id:199,name:"鱼丸肉饼吊瓜汤",category:"soup",ingredients:["潮汕鱼丸","肉饼","吊瓜","芹菜末","蒜头油","盐","胡椒粉"],steps:"水煮开，下鱼丸和切片的肉饼煮至浮起。吊瓜去皮切片放入煮3分钟。加盐、胡椒粉调味，撒芹菜末和蒜头油。"},
{id:200,name:"萝卜排骨汤",category:"soup",ingredients:["白萝卜","排骨","姜片","枸杞","盐","芹菜末"],steps:"排骨焯水，白萝卜去皮切滚刀块。材料放入砂锅加水大火煮开转小火煲1小时至萝卜透明。加盐和枸杞，撒芹菜末。清甜润肺。"},
{id:201,name:"石斛麦冬瘦肉汤",category:"soup",ingredients:["猪瘦肉","石斛","麦冬","蜜枣","姜片","盐"],steps:"瘦肉切块焯水。石斛和麦冬洗净。所有材料放入炖盅，加水隔水炖2小时。加盐调味。滋阴清热，熬夜必备。"},
{id:202,name:"老黄瓜猪骨汤",category:"soup",ingredients:["老黄瓜","猪骨","赤小豆","扁豆","蜜枣","姜片","盐"],steps:"老黄瓜去皮去瓤切大块。猪骨焯水，赤小豆扁豆泡水。所有材料放入砂锅，加水大火煮开转小火煲2小时。加盐调味，清热祛湿。"},
{id:203,name:"番茄豆腐鱼汤",category:"soup",ingredients:["番茄","嫩豆腐","鲜鱼片","姜丝","葱花","盐","胡椒粉","花生油"],steps:"番茄切块炒出汁。加开水煮开，放入豆腐煮3分钟。放入鱼片滑散，煮至鱼片变白（约1分钟）。加盐和胡椒粉调味，撒葱花。"},
{id:204,name:"苹果雪梨瘦肉汤",category:"soup",ingredients:["苹果","雪梨","猪瘦肉","南北杏","蜜枣","姜片","盐"],steps:"苹果雪梨去核切块。瘦肉切块焯水。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，润肺生津。"},
{id:205,name:"芥菜咸蛋汤",category:"soup",ingredients:["大芥菜","咸鸭蛋","姜片","瘦肉","盐","花生油"],steps:"瘦肉切片，芥菜切段焯水。水开加姜片和瘦肉煮5分钟。放入芥菜和打散的咸蛋续煮3分钟。加盐和少许油调味，清热下火。"},
{id:206,name:"茶树菇鸡汤",category:"soup",ingredients:["鸡肉","干茶树菇","红枣","枸杞","姜片","盐"],steps:"茶树菇泡发去根。鸡肉焯水。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，菌香浓郁。"},
{id:207,name:"沙参玉竹排骨汤",category:"soup",ingredients:["排骨","沙参","玉竹","百合","蜜枣","姜片","盐"],steps:"排骨焯水。沙参玉竹百合洗净。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，滋阴润燥。"},
{id:208,name:"冬瓜薏米老鸭汤",category:"soup",ingredients:["老鸭","冬瓜","薏米","陈皮","姜片","盐","蜜枣"],steps:"老鸭斩块焯水。冬瓜去瓤连皮切大块。薏米泡水，陈皮泡软刮去白瓤。所有材料放入砂锅，加水大火煮开转小火煲2小时。加盐调味，祛湿清热。"},
{id:209,name:"西洋菜猪骨汤",category:"soup",ingredients:["西洋菜","猪骨","蜜枣","南北杏","姜片","盐"],steps:"猪骨焯水。西洋菜洗净（最后20分钟才放）。猪骨、蜜枣、南北杏、姜片加水煲1.5小时。放入西洋菜煲20分钟。加盐调味，清润降火。"},
{id:210,name:"竹蔗茅根马蹄水",category:"soup",ingredients:["竹蔗","茅根","马蹄","胡萝卜","冰糖"],steps:"竹蔗劈开，茅根洗净，马蹄去皮，胡萝卜切块。所有材料加水大火煮开转小火煲1小时。加冰糖调味。清甜解暑，广东凉茶。"},
{id:211,name:"豆苗瘦肉汤",category:"soup",ingredients:["豆苗","猪瘦肉","姜丝","盐","花生油","枸杞"],steps:"瘦肉切片。水开加姜丝和瘦肉煮3分钟。放入豆苗烫软（约30秒）。加盐、枸杞和少许油调味。清新爽口。"},
{id:212,name:"花生鸡脚汤",category:"soup",ingredients:["鸡脚","花生","眉豆","姜片","盐","蜜枣"],steps:"鸡脚剪去趾甲焯水。花生眉豆泡水。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，胶原蛋白满满。"},
{id:213,name:"紫菜蛋花汤",category:"soup",ingredients:["紫菜","鸡蛋","葱花","盐","胡椒粉","香油"],steps:"水烧开，紫菜撕碎放入煮1分钟。鸡蛋打散沿筷子缓缓倒入锅中形成蛋花。加盐、胡椒粉和香油调味，撒葱花。简单快手。"},
{id:214,name:"莲藕绿豆排骨汤",category:"soup",ingredients:["莲藕","排骨","绿豆","章鱼干","陈皮","姜片","盐"],steps:"莲藕去皮切厚块。排骨焯水，绿豆泡水，章鱼干泡软。所有材料放入砂锅，加水大火煮开转小火煲2小时。加盐调味，清热解暑。"},
{id:215,name:"芫荽皮蛋汤",category:"soup",ingredients:["香菜","皮蛋","豆腐","姜丝","盐","胡椒粉","高汤"],steps:"皮蛋切丁，豆腐切块。高汤煮开加姜丝。放入皮蛋和豆腐煮3分钟。放入香菜烫软，加盐和胡椒粉调味。清热下火。"},
{id:216,name:"粉葛赤小豆鲮鱼汤",category:"soup",ingredients:["粉葛","赤小豆","鲮鱼","猪骨","蜜枣","陈皮","姜片","盐"],steps:"粉葛去皮切块。鲮鱼煎至两面金黄用纱布袋装好。猪骨焯水，赤小豆泡水。所有材料放入砂锅，加水煲2.5小时。加盐调味，祛湿健脾。"},
{id:217,name:"肉丸豆腐汤",category:"soup",ingredients:["猪肉丸","嫩豆腐","生菜","芹菜末","蒜头油","盐","胡椒粉"],steps:"水煮开，下肉丸和豆腐煮至肉丸浮起。放入生菜烫软。加盐、胡椒粉调味，撒芹菜末和蒜头油。"},
{id:218,name:"南瓜瘦肉汤",category:"soup",ingredients:["南瓜","猪瘦肉","姜片","红枣","盐","枸杞"],steps:"南瓜去皮去瓤切块。瘦肉切片焯水。所有材料放入砂锅，加水大火煮开转小火煲30分钟至南瓜软烂。加盐和枸杞调味，清甜可口。"},
{id:219,name:"胡椒猪肚鸡",category:"soup",ingredients:["猪肚","整鸡","白胡椒粒","姜片","红枣","枸杞","盐","料酒"],steps:"猪肚用面粉和醋反复搓洗去腥。整鸡焯水后塞入猪肚，加胡椒粒和姜片缝好。加水大火煮开转小火煲2.5小时。取出切件，汤加枸杞红枣和盐。"},
{id:220,name:"番茄蛋花汤",category:"soup",ingredients:["番茄","鸡蛋","葱花","盐","糖","花生油","姜丝"],steps:"番茄切块热油炒出汁。加开水煮开，加姜丝煮3分钟。鸡蛋打散倒入锅中形成蛋花。加盐和少许糖调味，撒葱花。"},
{id:221,name:"青红萝卜煲猪骨",category:"soup",ingredients:["青萝卜","胡萝卜","猪骨","蜜枣","南北杏","姜片","盐"],steps:"青萝卜和胡萝卜去皮切块。猪骨焯水。所有材料放入砂锅，加水大火煮开转小火煲2小时。加盐调味，滋润清甜。"},
{id:222,name:"芡实淮山排骨汤",category:"soup",ingredients:["排骨","芡实","淮山","莲子","薏米","姜片","盐"],steps:"排骨焯水，芡实莲子薏米泡水。淮山去皮切段。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，健脾祛湿。"},
{id:223,name:"冬瓜咸蛋汤",category:"soup",ingredients:["冬瓜","咸鸭蛋","瘦肉","姜丝","盐","葱花"],steps:"冬瓜去皮切片。瘦肉切片。水开加姜丝，放入冬瓜和瘦肉煮5分钟至冬瓜透明。咸蛋打散倒入，加盐调味撒葱花。清爽快手汤。"},
{id:224,name:"石斛花旗参瘦肉汤",category:"soup",ingredients:["猪瘦肉","石斛","花旗参","麦冬","蜜枣","姜片","盐"],steps:"瘦肉切块焯水。石斛花旗参麦冬洗净。所有材料放入炖盅，加水隔水炖2小时。加盐调味。滋阴降火，熬夜人士首选。"},
{id:225,name:"海带排骨汤",category:"soup",ingredients:["海带","排骨","姜片","盐","蜜枣","白醋"],steps:"海带泡发洗净切条。排骨焯水。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加几滴白醋促钙溶出。加盐调味。"},
{id:226,name:"菜心瘦肉汤",category:"soup",ingredients:["菜心","猪瘦肉","姜丝","盐","花生油","枸杞"],steps:"瘦肉切片。水开加姜丝和瘦肉煮3分钟。菜心洗净切段放入烫2分钟至翠绿。加盐、枸杞和少许油调味。清甜简单。"},
{id:227,name:"椰子鸡汤",category:"soup",ingredients:["鸡肉","椰子","红枣","枸杞","姜片","盐"],steps:"椰子取汁刮肉切条。鸡肉焯水。所有材料放入砂锅，加椰子水和清水，大火煮开转小火煲1.5小时。加盐调味，椰香浓郁。"},
{id:228,name:"冬瓜海带瘦肉汤",category:"soup",ingredients:["冬瓜","海带","猪瘦肉","姜片","盐","蜜枣"],steps:"冬瓜去皮去瓤切块，海带泡发切条，瘦肉焯水。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，清热祛湿消暑。"},
{id:229,name:"冬菇鸡汤",category:"soup",ingredients:["鸡肉","干香菇","红枣","枸杞","姜片","盐","料酒"],steps:"干香菇泡发去蒂。鸡肉焯水。所有材料放入砂锅，加水大火煮开转小火煲1.5小时。加盐调味，菇香鸡鲜。"},
{id:230,name:"苦瓜咸菜猪骨汤",category:"soup",ingredients:["苦瓜","潮汕咸菜","猪骨","黄豆","姜片","盐"],steps:"黄豆提前泡2小时。猪骨焯水。苦瓜去瓤切块，咸菜切丝泡水。所有材料放入砂锅，加水煲1.5小时。加盐调味，甘咸回甘。"},
{id:231,name:"鱼头豆腐汤",category:"soup",ingredients:["大鱼头","嫩豆腐","姜片","葱段","盐","白胡椒粉","料酒","花生油"],steps:"鱼头洗净对半剖开。热油煎至两面金黄。加料酒和足量开水，大火煮10分钟至汤白。放入豆腐煮5分钟，加盐和胡椒粉调味，撒葱段。"},
{id:232,name:"螺片瘦肉汤",category:"soup",ingredients:["干螺片","猪瘦肉","淮山","枸杞","蜜枣","姜片","盐"],steps:"干螺片提前泡发。瘦肉焯水。所有材料放入炖盅，加水隔水炖2-3小时。加盐调味，滋阴补肾。"},
{id:233,name:"春菜排骨汤",category:"soup",ingredients:["春菜","排骨","姜片","蒜","盐","花生油"],steps:"排骨焯水后加水煲40分钟。春菜洗净切段。热油爆香蒜，下春菜翻炒至软。倒入排骨汤中再煮15分钟。加盐调味，春菜回甘。"},
{id:234,name:"番茄金针菇瘦肉汤",category:"soup",ingredients:["番茄","金针菇","猪瘦肉","姜丝","盐","葱花","花生油"],steps:"番茄切块炒出汁，加开水煮开。瘦肉切片和金针菇去根放入煮3分钟。加盐调味，撒葱花。酸甜开胃。"},
{id:235,name:"冬瓜薏米水鸭汤",category:"soup",ingredients:["水鸭","冬瓜","薏米","芡实","陈皮","姜片","盐"],steps:"水鸭斩块焯水。冬瓜连皮去瓤切大块。薏米芡实泡水。所有材料放入砂锅，加水煲2小时。加盐调味，消暑祛湿。"},
{id:236,name:"白萝卜鱼头汤",category:"soup",ingredients:["白萝卜","大鱼头","姜片","葱段","盐","白胡椒粉","料酒"],steps:"鱼头煎至两面金黄。加料酒和开水大火煮10分钟至汤白。白萝卜切丝放入煮5分钟。加盐和胡椒粉调味，撒葱段。"},
{id:237,name:"清补凉排骨汤",category:"soup",ingredients:["排骨","淮山","莲子","百合","芡实","薏米","沙参","玉竹","蜜枣","盐"],steps:"排骨焯水。所有药材洗净泡水。全部材料放入砂锅，加水大火煮开转小火煲2小时。加盐调味，清补滋润。"},
{id:238,name:"丝瓜瘦肉汤",category:"soup",ingredients:["丝瓜","猪瘦肉","姜丝","盐","花生油","枸杞"],steps:"丝瓜去皮切滚刀块。瘦肉切片。水开加姜丝和瘦肉煮3分钟。放入丝瓜煮2分钟至软。加盐和枸杞，淋少许油。清甜爽滑。"},
{id:239,name:"玉米须猪骨汤",category:"soup",ingredients:["玉米须","猪骨","胡萝卜","蜜枣","姜片","盐"],steps:"玉米须洗净（可用新鲜玉米的须和叶）。猪骨焯水。所有材料放入砂锅，加水煲1.5小时。加盐调味，利尿祛湿。"},
{id:240,name:"姜葱鱼头汤",category:"soup",ingredients:["大鱼头","姜片","葱段","豆腐","香菜","盐","胡椒粉","料酒","花生油"],steps:"鱼头洗净煎至两面金黄。加料酒和开水大火煮10分钟。加姜片和豆腐煮5分钟。加盐、胡椒粉，撒葱段和香菜。"},
{id:241,name:"菜干蜜枣猪肺汤",category:"soup",ingredients:["白菜干","猪肺","猪骨","蜜枣","南北杏","姜片","盐"],steps:"菜干泡软洗净。猪肺反复灌洗至变白切块焯水。猪骨焯水。所有材料放入砂锅，加水煲2.5小时。加盐调味，润肺止咳。"},
{id:242,name:"番茄玉米排骨汤",category:"soup",ingredients:["番茄","玉米","排骨","土豆","姜片","盐"],steps:"排骨焯水，番茄切块炒出汁。玉米切段，土豆去皮切块。所有材料放入砂锅，加水煲1.5小时。加盐调味，酸甜浓郁。"},
{id:243,name:"丝瓜豆腐汤",category:"soup",ingredients:["丝瓜","嫩豆腐","姜丝","盐","花生油","葱花"],steps:"丝瓜去皮切滚刀块，豆腐切块。水开加姜丝，放入丝瓜和豆腐煮3分钟。加盐和少许油调味，撒葱花。清甜嫩滑。"},
{id:244,name:"冬瓜排骨汤",category:"soup",ingredients:["冬瓜","排骨","薏米","姜片","盐","蜜枣"],steps:"排骨焯水，薏米泡水，冬瓜去瓤连皮切块。所有材料放入砂锅，加水煲1.5小时。加盐调味，清热祛湿消暑。"},
{id:245,name:"西洋菜陈肾汤",category:"soup",ingredients:["西洋菜","陈肾（腊鸭肾）","猪骨","蜜枣","南北杏","姜片","盐"],steps:"陈肾泡软切片。猪骨焯水。猪骨、陈肾、蜜枣、南北杏、姜片加水煲1.5小时。放入西洋菜煲20分钟。加盐调味，清热润肺。"},
{id:246,name:"莲藕花生猪蹄汤",category:"soup",ingredients:["莲藕","猪蹄","花生","章鱼干","姜片","盐","蜜枣"],steps:"莲藕去皮切厚块。猪蹄焯水，花生泡水，章鱼干泡软。所有材料放入砂锅，加水煲2小时至猪蹄软烂。加盐调味，滋补养颜。"},
{id:247,name:"白萝卜豆腐汤",category:"soup",ingredients:["白萝卜","嫩豆腐","姜丝","盐","白胡椒粉","葱花","花生油"],steps:"白萝卜去皮切丝。水开加姜丝和白萝卜丝煮5分钟至透明。放入豆腐煮3分钟。加盐、胡椒粉和少许油，撒葱花。清爽暖胃。"},
{id:248,name:"萝卜牛腩汤",category:"soup",ingredients:["白萝卜","牛腩","姜","八角","料酒","盐","胡椒粉","芹菜末"],steps:"牛腩切块焯水。压力锅加水、姜、八角、料酒压30分钟。加入白萝卜块再压10分钟。加盐和胡椒粉调味，撒芹菜末。"},
{id:249,name:"芥菜番薯汤",category:"soup",ingredients:["大芥菜","番薯","姜片","盐","花生油"],steps:"番薯去皮切块，芥菜切段。水开加姜片和番薯煮15分钟至番薯软。放入芥菜煮5分钟。加盐和少许油。潮汕经典家常汤。"},
{id:250,name:"潮汕咸菜猪肚汤",category:"soup",ingredients:["猪肚","潮汕咸菜","白胡椒粒","姜片","盐"],steps:"猪肚反复搓洗干净焯水切条。咸菜切丝泡水。猪肚和胡椒粒、姜片加水煲1.5小时。加入咸菜再煲20分钟。加盐调味，咸酸开胃。"},
{id:251,name:"木瓜花生鸡脚汤",category:"soup",ingredients:["木瓜","花生","鸡脚","蜜枣","姜片","盐"],steps:"木瓜去皮去籽切块。鸡脚剪去趾甲焯水。花生泡水。所有材料入砂锅，加水煲1.5小时。加盐调味，胶原蛋白满满。"},
{id:252,name:"豆腐鱼头汤",category:"soup",ingredients:["大鱼头","嫩豆腐","姜片","葱段","香菜","盐","白胡椒粉","料酒"],steps:"鱼头煎至两面金黄。加料酒和开水大火煮10分钟汤白。放入豆腐煮5分钟。加盐、胡椒粉调味，撒葱段和香菜。"},
{id:253,name:"猪骨萝卜汤",category:"soup",ingredients:["猪骨","白萝卜","胡萝卜","玉米","姜片","盐","蜜枣"],steps:"猪骨焯水。萝卜去皮切块，玉米切段。所有材料放入砂锅，加水煲1.5小时。加盐调味，清甜滋润。"},
{id:254,name:"苦瓜瘦肉汤",category:"soup",ingredients:["苦瓜","猪瘦肉","姜片","盐","枸杞"],steps:"苦瓜去瓤切薄片。瘦肉切片。水开加姜片和瘦肉煮5分钟。放入苦瓜煮3分钟。加盐和枸杞调味。简单快手，清热降火。"},
{id:255,name:"霸王花猪骨汤",category:"soup",ingredients:["霸王花（剑花）","猪骨","蜜枣","南北杏","姜片","盐"],steps:"霸王花干提前泡软洗净。猪骨焯水。所有材料放入砂锅，加水煲2小时。加盐调味，清热润肺。"},
{id:256,name:"番茄薯仔鱼汤",category:"soup",ingredients:["番茄","土豆","鲜鱼","姜片","盐","葱花","花生油"],steps:"鱼处理干净煎至两面金黄。番茄和土豆切块炒香。加开水大火煮10分钟至汤白。放入土豆煮15分钟至软，加盐调味撒葱花。"},
{id:257,name:"咸菜猪血汤",category:"soup",ingredients:["猪血","潮汕咸菜","姜丝","韭菜","胡椒粉","盐","花生油"],steps:"猪血切块焯水。咸菜切丝泡水。水开加姜丝，放入猪血和咸菜煮5分钟。加韭菜段、胡椒粉和盐调味。潮汕街边经典。"},
{id:258,name:"清炖鸡汤",category:"soup",ingredients:["老母鸡","姜片","红枣","枸杞","料酒","盐"],steps:"老母鸡处理干净焯水。放入砂锅加足量水、姜片、料酒，大火煮开转小火炖2-3小时。加红枣枸杞再炖30分钟，加盐调味。原汁原味。"},
{id:259,name:"冬瓜瑶柱汤",category:"soup",ingredients:["冬瓜","干贝","瘦肉","姜丝","盐","葱花","花生油"],steps:"干贝泡发撕丝。冬瓜去皮切薄片，瘦肉切片。水开加姜丝和干贝煮5分钟出味。放入冬瓜和瘦肉煮3分钟。加盐和油，撒葱花。"},
{id:260,name:"五指毛桃煲鸡汤",category:"soup",ingredients:["鸡肉","五指毛桃","茯苓","蜜枣","姜片","盐"],steps:"五指毛桃洗净切段。鸡肉焯水。所有材料放入砂锅，加水大火煮开转小火煲2小时。加盐调味，椰香浓郁，健脾祛湿。"},
{id:261,name:"豆腐咸菜汤",category:"soup",ingredients:["嫩豆腐","潮汕咸菜","瘦肉","姜丝","盐","胡椒粉","芹菜末"],steps:"咸菜切丝泡水，瘦肉切片，豆腐切块。水开加姜丝和瘦肉煮3分钟。放入咸菜和豆腐煮5分钟。加盐、胡椒粉，撒芹菜末。"},
{id:262,name:"玉米排骨汤",category:"soup",ingredients:["甜玉米","排骨","胡萝卜","姜片","盐","蜜枣"],steps:"排骨焯水。玉米切段，胡萝卜切滚刀块。所有材料放入砂锅，加水煲1.5小时。加盐调味，清甜鲜美。"},
{id:263,name:"豆苗皮蛋汤",category:"soup",ingredients:["豆苗","皮蛋","蒜","姜丝","盐","高汤","花生油"],steps:"皮蛋切丁，蒜拍扁。热油炸香蒜，加高汤和姜丝煮开。放入皮蛋煮2分钟。放入豆苗烫软，加盐和少许油调味。"},
{id:264,name:"排骨莲藕花生汤",category:"soup",ingredients:["排骨","莲藕","花生","姜片","盐","蜜枣"],steps:"排骨焯水，莲藕去皮切厚块，花生泡水。所有材料放入砂锅，加水煲2小时。加盐调味，藕香浓郁。"},
{id:265,name:"杂鱼汤",category:"soup",ingredients:["小杂鱼","姜片","葱段","豆腐","盐","胡椒粉","花生油"],steps:"杂鱼处理干净。热油煎鱼至两面金黄。加开水大火煮10分钟至汤白。放入豆腐煮5分钟。加盐和胡椒粉，撒葱段。潮汕渔家经典。"},
{id:266,name:"猪杂汤",category:"soup",ingredients:["猪瘦肉","猪肝","猪粉肠","猪心","姜丝","枸杞叶","盐","胡椒粉","料酒"],steps:"各种猪杂洗净切片，粉肠切段。水开加姜丝和料酒，放入粉肠先煮10分钟。加入其他猪杂煮至变色。放入枸杞叶烫软，加盐和胡椒粉调味。"},
{id:267,name:"冬菇花生鸡脚汤",category:"soup",ingredients:["鸡脚","干香菇","花生","眉豆","姜片","盐","蜜枣"],steps:"鸡脚剪去趾甲焯水。香菇泡发，花生眉豆泡水。所有材料放入砂锅，加水煲1.5小时。加盐调味，胶原蛋白丰富。"},
{id:268,name:"萝卜丝鲫鱼汤",category:"soup",ingredients:["鲫鱼","白萝卜","姜片","葱段","盐","白胡椒粉","料酒"],steps:"鲫鱼处理干净擦干，煎至两面金黄。加料酒和开水大火煮10分钟至汤白。白萝卜切丝放入煮5分钟。加盐和胡椒粉，撒葱段。"},
{id:269,name:"底线汤",category:"soup",ingredients:["猪肉末","鸡蛋","紫菜","葱花","盐","胡椒粉","鱼露","番薯粉"],steps:"肉末加鱼露、胡椒粉、番薯粉拌匀。水开将肉末捏成小丸下锅。紫菜撕碎放入，鸡蛋打散淋入成蛋花。加盐调味，撒葱花。潮汕妈妈的味道。"},
{id:270,name:"冬至鸽汤",category:"soup",ingredients:["鸽子","红枣","枸杞","党参","黄芪","姜片","盐","料酒"],steps:"鸽子处理干净焯水。所有材料放入炖盅，加水隔水炖2-3小时。加盐调味。滋补养身，一鸽胜九鸡。"},
// ==================== 追加荤菜（海鲜类）====================
{id:271,name:"沙茶猪肝",category:"meat",ingredients:["猪肝","洋葱","姜","蒜","青葱","沙茶酱","蚝油","番茄酱","酱油","料酒","糖","香油","醋","生粉"],steps:"猪肝切片泡水去血水，洋葱切片。调酱汁：沙茶酱、蚝油、番茄酱、酱油、料酒、糖、香油、醋、清水、生粉混合。猪肝炒至变色盛出，爆香洋葱，放回猪肝淋酱汁翻炒均匀。"},
{id:272,name:"沙茶炒猪肉",category:"meat",ingredients:["猪肉","小葱","青椒","沙茶酱","蚝油","酱油","生粉","蒜头"],steps:"猪肉切片加蚝油、酱油、生粉、沙茶酱腌制10分钟。蒜头切丁炒香，放青椒大火炒，加入猪肉翻炒，加清水焖几十秒出锅。"},
{id:273,name:"潮汕卤鹅",category:"meat",ingredients:["狮头鹅","肥猪肉","上酱油","精盐","南姜","冰糖","川椒","桂皮","丁香","八角","甘草","加饭酒","蒜头","香菇","芫荽头"],steps:"鹅处理干净用盐抹匀，卤料包扎好放入卤水盆，加酱油、色油、冰糖、南姜等，大火煮开后放入鹅卤约1小时30分钟，捞出切厚片淋卤汁。"},
{id:274,name:"豆酱焗鸡",category:"meat",ingredients:["清远鸡","普宁豆酱","胡椒粉","香油","食盐","白糖","姜片","葱段","芹菜","洋葱","青椒"],steps:"鸡处理干净，豆酱加调料拌匀抹在鸡身上腌制，砂锅铺菜放鸡，加清水小火焖熟。"},
{id:275,name:"清蒸膏蟹",category:"meat",ingredients:["青蟹","大葱","姜","醋"],steps:"蟹处理干净切块摆碟，蒸熟后跟姜茸浙醋同上。"},
{id:276,name:"白灼虾",category:"meat",ingredients:["基围虾","红辣椒丝","生抽","芝麻油","精盐","姜块","葱条","花生油"],steps:"虾洗净，沸水煮至变红捞出，蘸料混合淋上。"},
{id:277,name:"干锅牛杂",category:"meat",ingredients:["熟牛杂","洋葱","大蒜","姜","干辣椒","花椒","芹菜","生抽","老抽","蚝油","豆瓣酱","白糖","芝麻","香菜"],steps:"牛杂焯水，砂锅炒香调料，放牛杂翻炒，加调料和水焖煮，收汁撒芝麻香菜。"},
{id:278,name:"香菇焖鸡煲",category:"meat",ingredients:["土鸡","干香菇","姜片","蒜瓣","红葱头","青红椒","生抽","老抽","蚝油","料酒","白糖","白胡椒粉","玉米淀粉"],steps:"鸡肉腌制20分钟，香菇泡发。砂锅煎香鸡块，爆香小料，放回鸡和香菇，加泡香菇水焖15-20分钟。"},
{id:279,name:"薄荷蒜香鸡",category:"meat",ingredients:["鸡肉","薄荷叶","蒜末","盐","生抽","料酒"],steps:"鸡肉切块腌制，蒜末炸至金黄，放鸡肉翻炒，加薄荷叶。"},
{id:280,name:"红烧鱼",category:"meat",ingredients:["鲜鱼","姜","葱","蒜","生抽","老抽","蚝油","糖","醋","料酒"],steps:"鱼处理干净划花刀，两面煎至金黄。爆香姜蒜葱，加调料和清水，大火烧开转小火焖煮至汤汁浓稠。"},
{id:281,name:"清蒸海鱼",category:"meat",ingredients:["海鱼","姜丝","葱丝","生抽","花生油","红椒丝"],steps:"鱼洗净划花刀，水开上锅大火蒸8-10分钟。倒掉蒸出的腥水，铺上葱丝姜丝，淋热油和生抽。"},
{id:282,name:"鱼头豆腐汤",category:"meat",ingredients:["大鱼头","嫩豆腐","姜片","葱段","盐","白胡椒粉","料酒"],steps:"鱼头洗净煎至两面金黄。加料酒和足量开水，大火煮10分钟至汤白。放入豆腐煮5分钟，加盐和胡椒粉调味。"},
{id:283,name:"红烧狮子头",category:"meat",ingredients:["猪肉末","荸荠","鸡蛋","姜末","葱花","生抽","老抽","蚝油","糖","淀粉"],steps:"肉末加切碎的荸荠、蛋液和调料搅拌上劲。搓成大丸子，油炸至定型。红烧汁炖煮1小时至软烂。"},
{id:284,name:"糖醋里脊",category:"meat",ingredients:["猪里脊","番茄酱","白醋","糖","淀粉","鸡蛋","盐"],steps:"里脊切条，裹蛋液和淀粉炸至金黄。糖醋汁煮开：番茄酱+白醋+糖+水。倒入肉条翻炒均匀。"},
{id:285,name:"红烧排骨",category:"meat",ingredients:["排骨","姜","八角","桂皮","生抽","老抽","蚝油","冰糖","料酒"],steps:"排骨焯水。热油爆香姜和香料，下排骨翻炒至微黄。加调料和清水，大火煮开转小火焖40分钟至软烂。"},
{id:286,name:"可乐排骨",category:"meat",ingredients:["排骨","可乐","生抽","老抽","姜片","料酒"],steps:"排骨焯水去腥。热油煎排骨至两面金黄。加生抽老抽姜片，倒入可乐没过排骨。大火煮开转中火收汁。"},
{id:287,name:"无锡排骨",category:"meat",ingredients:["排骨","无锡酱油","冰糖","姜","葱","八角","桂皮","料酒"],steps:"排骨焯水。锅中加酱油、冰糖、香料和料酒，放入排骨大火烧开转小火焖1小时至软烂。"},
{id:288,name:"蒸肉饼",category:"meat",ingredients:["猪肉末","咸鸭蛋","姜末","葱花","生抽","蚝油","糖","淀粉"],steps:"肉末加调料拌匀铺入盘中，压平中间放咸蛋黄。大火蒸15分钟，撒葱花。"},
{id:289,name:"梅菜蒸肉",category:"meat",ingredients:["猪五花肉","梅菜干","老抽","生抽","冰糖","姜片"],steps:"五花肉煮至七成熟切片。梅菜泡软铺底，肉片码在上面。加调料蒸1小时，倒扣盘中。"},
{id:290,name:"红烧肉",category:"meat",ingredients:["猪五花肉","姜","八角","桂皮","香叶","生抽","老抽","蚝油","冰糖","料酒"],steps:"五花肉切块焯水。热油爆香姜和香料，下肉块翻炒至出油。加调料和清水，大火烧开转小火焖1小时至软烂。"},
{id:291,name:"回锅肉",category:"meat",ingredients:["猪五花肉","郫县豆瓣酱","青蒜","姜","蒜","甜面酱","糖"],steps:"五花肉煮至七成熟切片。锅中不放油，肉片煸炒至卷曲出油。加豆瓣酱、甜面酱、姜蒜片和青蒜翻炒。"},
{id:292,name:"木须肉",category:"meat",ingredients:["猪瘦肉","鸡蛋","木耳","黄瓜","姜丝","蒜","生抽","蚝油","料酒","淀粉"],steps:"肉片腌制，鸡蛋炒散。热油滑肉片变色盛出。炒香木耳黄瓜，倒回肉片，加调料翻炒均匀。"},
{id:293,name:"京酱肉丝",category:"meat",ingredients:["猪里脊","甜面酱","葱丝","豆腐皮","黄瓜丝","生抽","蚝油","糖","淀粉"],steps:"肉丝腌制滑油。甜面酱炒香，肉丝回锅翻炒均匀。配葱丝黄瓜丝，用豆腐皮卷食。"},
{id:294,name:"鱼香肉丝",category:"meat",ingredients:["猪里脊","木耳","胡萝卜","青椒","郫县豆瓣酱","姜末","蒜末","生抽","醋","糖","淀粉"],steps:"肉丝腌制滑油。爆香姜蒜末和豆瓣酱，下蔬菜丝翻炒。肉丝回锅，加调料勾芡。"},
{id:295,name:"水煮肉片",category:"meat",ingredients:["猪里脊","豆芽","白菜","郫县豆瓣酱","干辣椒","花椒","姜蒜末","生抽","淀粉"],steps:"肉片腌制。汤底煮豆芽和白菜铺碗底。肉片烫熟铺菜上，淋热油激香干辣椒和花椒。"},
{id:296,name:"锅巴肉片",category:"meat",ingredients:["猪里脊","锅巴","木耳","胡萝卜","青椒","郫县豆瓣酱","姜蒜片","生抽","醋","糖"],steps:"肉片腌制滑油。爆香豆瓣酱和姜蒜，下蔬菜翻炒。肉片回锅，加调料和水淀粉，淋在炸好的锅巴上。"},
{id:297,name:"蚂蚁上树",category:"meat",ingredients:["猪肉末","粉丝","郫县豆瓣酱","姜末","蒜末","葱花","生抽","老抽","糖"],steps:"粉丝泡软。热油炒肉末至出油，加豆瓣酱炒出红油。下粉丝和调料翻炒均匀，撒葱花。"},
{id:298,name:"四喜丸子",category:"meat",ingredients:["猪肉末","荸荠","鸡蛋","葱姜末","生抽","老抽","蚝油","糖","淀粉"],steps:"肉末加荸荠碎、蛋液和调料搅拌上劲。搓成四个大丸子，油炸定型。加高汤蒸40分钟。"},
{id:299,name:"东坡肉",category:"meat",ingredients:["猪五花肉","绍酒","酱油","冰糖","姜","葱","八角"],steps:"五花肉切大方块，用稻草或棉线扎紧。砂锅底铺葱姜，肉块皮朝下码好。加酒和酱油，冰糖，小火焖3小时。"},
{id:300,name:"红烧蹄髈",category:"meat",ingredients:["猪蹄髈","姜","八角","桂皮","香叶","生抽","老抽","蚝油","冰糖","料酒"],steps:"蹄髈焯水去毛。热油爆香姜和香料，下蹄髈翻炒。加调料和足量水，大火烧开转小火焖2小时至软烂。"},
{id:301,name:"黄豆焖猪手",category:"meat",ingredients:["猪手","黄豆","姜","八角","生抽","老抽","蚝油","冰糖","料酒"],steps:"黄豆提前泡2小时。猪手焯水。热油爆香姜八角，下猪手翻炒。加调料和黄豆，大火煮开转小火焖1.5小时。"},
{id:302,name:"红烧牛筋",category:"meat",ingredients:["牛筋","姜","蒜","八角","桂皮","香叶","生抽","老抽","蚝油","冰糖"],steps:"牛筋切段焯水。热油爆香姜蒜和香料，下牛筋翻炒。加调料和清水，大火烧开转小火焖2小时至软糯。"},
{id:303,name:"土豆烧牛肉",category:"meat",ingredients:["牛肉","土豆","胡萝卜","姜","八角","桂皮","生抽","老抽","蚝油","冰糖"],steps:"牛肉切块焯水。土豆胡萝卜切滚刀块。热油爆香姜和香料，下牛肉翻炒。加调料和清水，大火烧开转小火焖1小时，加土豆胡萝卜再焖30分钟。"},
{id:304,name:"咖喱牛肉",category:"meat",ingredients:["牛肉","土豆","洋葱","胡萝卜","咖喱粉","椰浆","生抽","盐","糖"],steps:"牛肉切块腌制煎黄。炒香洋葱，加咖喱粉炒出香味。加入牛肉、土豆、胡萝卜、椰浆和水，煮开后小火炖30分钟。"},
{id:305,name:"黑椒牛柳",category:"meat",ingredients:["牛里脊","黑胡椒","洋葱","青椒","生抽","蚝油","料酒","糖","黄油","蒜"],steps:"牛肉切条腌制。热锅加黄油，大火煎牛肉条至表面焦香。加入蒜片、洋葱、青椒和现磨黑胡椒翻炒。"},
{id:306,name:"铁板牛柳",category:"meat",ingredients:["牛里脊","洋葱","青椒","红椒","黑胡椒","生抽","蚝油","糖","蒜","黄油"],steps:"牛里脊切片腌制。铁板烧热放黄油化开，铺上洋葱丝。牛肉煎至所需熟度铺在洋葱上，淋黑胡椒汁。"},
{id:307,name:"青椒炒牛肉",category:"meat",ingredients:["牛肉","青椒","姜","蒜","生抽","蚝油","料酒","淀粉","黑胡椒"],steps:"牛肉切片逆纹腌制。青椒切块。热油滑牛肉变色盛出。爆香姜蒜，下青椒翻炒，倒回牛肉，加调料大火快速翻炒。"},
{id:308,name:"葱爆牛肉",category:"meat",ingredients:["牛肉","大葱","姜丝","蒜","生抽","蚝油","料酒","淀粉","香油"],steps:"牛肉逆纹切片腌制。大葱切段。热油滑牛肉变色盛出。爆香姜蒜，下大葱翻炒，倒回牛肉，加调料大火快炒。"},
{id:309,name:"芹菜炒牛肉",category:"meat",ingredients:["牛肉","芹菜","红椒","姜丝","蒜","生抽","蚝油","料酒","淀粉"],steps:"牛肉逆纹切片腌制，芹菜切段。热油滑牛肉变色盛出。爆香姜蒜，下芹菜红椒翻炒，倒回牛肉加蚝油大火炒匀。"},
{id:310,name:"番茄炒牛肉",category:"meat",ingredients:["牛肉","番茄","洋葱","姜丝","生抽","蚝油","糖","淀粉","料酒"],steps:"牛肉切片腌制，番茄切块。热油滑牛肉变色盛出。番茄洋葱炒出汁，牛肉回锅，加调料翻炒均匀。"},
{id:311,name:"芥蓝炒牛肉",category:"meat",ingredients:["牛肉","芥蓝","姜丝","蒜蓉","沙茶酱","生抽","蚝油","料酒","淀粉"],steps:"牛肉逆纹切片加沙茶酱、生抽、料酒、淀粉腌制。芥蓝去老叶切段。热油大火滑牛肉变色盛出。爆香姜蒜，下芥蓝大火翻炒，倒回牛肉，加蚝油炒匀。"},
{id:312,name:"金针菇肥牛",category:"meat",ingredients:["肥牛","金针菇","郫县豆瓣酱","姜蒜末","葱花","生抽","蚝油","糖","高汤"],steps:"金针菇去根铺碗底。肥牛卷焯水铺金针菇上。爆香豆瓣酱和姜蒜，加高汤和调料煮开，淋在肥牛上，蒸5分钟。"},
{id:313,name:"酸汤肥牛",category:"meat",ingredients:["肥牛","金针菇","酸笋","泡椒","姜蒜末","野山椒","白醋","盐"],steps:"金针菇焯水铺碗底。肥牛焯水铺金针菇上。酸笋和泡椒炒香，加野山椒和调料煮开，淋在肥牛上。"},
{id:314,name:"水煮牛肉",category:"meat",ingredients:["牛肉","豆芽","白菜","干辣椒","花椒","郫县豆瓣酱","姜蒜末","生抽","淀粉"],steps:"肉片腌制。汤底煮豆芽白菜铺碗底。肉片在汤中烫熟铺菜上。热油激香干辣椒和花椒淋在肉上。"},
{id:315,name:"红烧牛尾",category:"meat",ingredients:["牛尾","姜","八角","桂皮","香叶","生抽","老抽","蚝油","冰糖","料酒"],steps:"牛尾剁段焯水。热油爆香姜和香料，下牛尾翻炒。加调料和足量水，大火烧开转小火焖2.5小时至软烂。"},
{id:316,name:"清炖牛腩",category:"meat",ingredients:["牛腩","姜","葱","八角","桂皮","料酒","盐","白萝卜"],steps:"牛腩切块焯水。加姜葱香料和料酒，大火烧开转小火炖1.5小时。加入白萝卜块再炖30分钟，加盐调味。"},
{id:317,name:"番茄牛腩",category:"meat",ingredients:["牛腩","番茄","洋葱","姜","八角","生抽","老抽","蚝油","冰糖"],steps:"牛腩切块焯水。番茄切块炒出汁。牛腩和番茄一起炖1.5小时至软烂。"},
{id:318,name:"XO酱炒牛肉",category:"meat",ingredients:["牛肉","西芹","红椒","XO酱","生抽","蚝油","料酒","淀粉"],steps:"牛肉切片腌制。热油滑牛肉变色盛出。爆香XO酱，下西芹红椒翻炒，倒回牛肉加调料炒匀。"},
{id:319,name:"沙茶肥牛",category:"meat",ingredients:["肥牛","沙茶酱","洋葱","金针菇","生抽","蚝油","糖","蒜"],steps:"肥牛焯水。炒香洋葱沙茶酱，加金针菇炒软。放肥牛和调料快速翻炒。"},
{id:320,name:"姜葱炒牛肉",category:"meat",ingredients:["牛肉","姜片","葱段","蒜","生抽","蚝油","料酒","糖","淀粉"],steps:"牛肉切片腌制。热油爆香姜蒜，下牛肉大火翻炒至变色。加葱段和调料翻炒均匀。"},
{id:321,name:"白切鸡",category:"meat",ingredients:["三黄鸡","姜","葱","料酒","沙姜","生抽","花生油"],steps:"水开加姜葱料酒。鸡三提三浸，然后完全浸入，小火浸煮25分钟。捞出过冰水，斩件。蘸料：沙姜末+生抽+热油。"},
{id:322,name:"盐焗鸡",category:"meat",ingredients:["三黄鸡","盐焗鸡粉","姜","葱","沙姜粉","花生油"],steps:"鸡处理干净擦干，内外抹盐焗鸡粉和沙姜粉腌制2小时。电饭煲底铺姜葱，放入鸡，煮饭模式两次。取出撕成条，淋蒸出的鸡汁。"},
{id:323,name:"葱油鸡",category:"meat",ingredients:["三黄鸡","葱","姜","生抽","花生油","盐"],steps:"鸡白切做法煮熟斩件。大量葱花和姜末铺在鸡上。热油浇在葱姜上激香。淋生抽即可。"},
{id:324,name:"酱油鸡",category:"meat",ingredients:["整鸡","生抽","老抽","冰糖","姜","葱","八角","桂皮"],steps:"鸡处理干净。锅中加生抽、老抽、冰糖、姜葱、八角和适量水煮开。放入鸡，小火煮20分钟，中途翻面几次。收汁上色，斩件淋酱汁。"},
{id:325,name:"麻辣鸡",category:"meat",ingredients:["鸡肉","花椒","干辣椒","姜","蒜","葱","生抽","老抽","蚝油","糖"],steps:"鸡肉斩块。热油炸香花椒干辣椒姜蒜，下鸡块翻炒。加调料和少许水焖熟，大火收汁。"},
{id:326,name:"口水鸡",category:"meat",ingredients:["鸡肉","花椒","干辣椒","芝麻","花生碎","葱姜蒜末","生抽","醋","糖","辣椒油"],steps:"鸡肉煮熟斩块摆盘。调料混合成红油汁，淋在鸡肉上，撒芝麻和花生碎。"},
{id:327,name:"宫保鸡丁",category:"meat",ingredients:["鸡肉","花生米","干辣椒","花椒","葱段","姜蒜末","生抽","老抽","醋","糖","淀粉"],steps:"鸡肉切丁腌制。调宫保汁：生抽+老抽+醋+糖+淀粉+水。热油炸香花椒干辣椒，下鸡丁大火翻炒，淋汁加花生米葱段。"},
{id:328,name:"辣子鸡",category:"meat",ingredients:["鸡肉","干辣椒","花椒","姜片","蒜","葱段","生抽","老抽","蚝油","糖"],steps:"鸡肉斩块腌制。大量油炸香花椒干辣椒，下鸡块大火翻炒。加调料炒匀，撒葱段。"},
{id:329,name:"板栗烧鸡",category:"meat",ingredients:["鸡肉","板栗","姜","蒜","八角","桂皮","生抽","老抽","蚝油","冰糖"],steps:"鸡肉斩块焯水，板栗去壳。热油爆香姜蒜和香料，下鸡块翻炒。加调料和清水，大火烧开转小火焖20分钟，加板栗再焖15分钟。"},
{id:330,name:"茶树菇炒鸡肉",category:"meat",ingredients:["鸡肉","干茶树菇","青椒","红椒","姜丝","蒜","生抽","蚝油","料酒","淀粉"],steps:"茶树菇泡发，鸡肉切块腌制。热油滑鸡肉变色盛出。爆香姜蒜，下茶树菇和青红椒翻炒，倒回鸡肉加调料。"},
{id:331,name:"三杯鸡",category:"meat",ingredients:["鸡肉","九层塔","姜片","蒜","生抽","老抽","米酒","香油","糖"],steps:"鸡肉斩块。热油爆香姜蒜，下鸡块煎至两面金黄。加生抽老抽米酒香油和糖，大火烧开转小火焖15分钟。加九层塔大火收汁。"},
{id:332,name:"啤酒鸭",category:"meat",ingredients:["鸭肉","啤酒","姜","蒜","八角","桂皮","香叶","生抽","老抽","蚝油"],steps:"鸭肉斩块焯水。热油爆香姜蒜和香料，下鸭块翻炒。加生抽老抽蚝油，倒入啤酒没过鸭肉，大火烧开转小火焖1小时。"},
{id:333,name:"酱鸭",category:"meat",ingredients:["鸭肉","甜面酱","生抽","老抽","冰糖","姜","葱","八角","桂皮","料酒"],steps:"鸭肉斩块焯水。锅中放甜面酱、生抽、老抽、冰糖、香料和料酒，放入鸭块大火烧开转小火焖1小时至软烂。"},
{id:334,name:"卤鸭",category:"meat",ingredients:["鸭子","卤水料包","生抽","老抽","冰糖","南姜","蒜","香菜头"],steps:"鸭处理干净焯水。卤水煮开放入鸭，小火浸卤40-50分钟。捞出晾凉斩件，淋少许卤汁和香油。"},
{id:335,name:"红烧鸭块",category:"meat",ingredients:["鸭肉","姜","蒜","八角","桂皮","生抽","老抽","蚝油","冰糖","料酒"],steps:"鸭肉斩块焯水。热油爆香姜蒜和香料，下鸭块翻炒。加调料和清水，大火烧开转小火焖1小时。"},
{id:336,name:"仔姜炒鸭肉",category:"meat",ingredients:["鸭肉","仔姜","青红椒","蒜","生抽","蚝油","料酒","糖","淀粉"],steps:"鸭肉切丝，仔姜切丝，青红椒切丝。热油滑鸭丝变色盛出。爆香蒜，下仔姜和青红椒，倒回鸭丝加调料翻炒。"},
{id:337,name:"酸萝卜老鸭汤",category:"meat",ingredients:["老鸭","酸萝卜","姜片","葱段","料酒","盐"],steps:"老鸭斩块焯水。锅中加水、姜片、葱段和料酒，放鸭肉大火烧开转小火煲1.5小时。加入酸萝卜再煲30分钟。"},
{id:338,name:"笋干老鸭汤",category:"meat",ingredients:["老鸭","笋干","火腿","姜片","葱段","料酒","盐"],steps:"笋干提前泡发切段，老鸭斩块焯水。所有材料放入砂锅，加水大火煮开转小火煲2小时。"},
{id:339,name:"莲子老鸭汤",category:"meat",ingredients:["老鸭","莲子","芡实","百合","姜片","料酒","盐"],steps:"老鸭斩块焯水。莲子、芡实、百合洗净。所有材料放入砂锅，加水煲2小时。"},
{id:340,name:"冬瓜老鸭汤",category:"meat",ingredients:["老鸭","冬瓜","薏米","陈皮","姜片","盐","蜜枣"],steps:"老鸭斩块焯水。冬瓜去瓤连皮切大块，薏米泡水。所有材料放入砂锅，加水煲2小时。"},
{id:341,name:"烤鸡腿",category:"meat",ingredients:["鸡腿","蜂蜜","生抽","老抽","蚝油","蒜末","黑胡椒","盐"],steps:"鸡腿划几刀，加调料腌制2小时。烤箱200度烤25分钟，中途翻面刷蜂蜜水。"},
{id:342,name:"炸鸡排",category:"meat",ingredients:["鸡胸肉","鸡蛋","面包糠","面粉","盐","黑胡椒","生抽","料酒"],steps:"鸡胸肉片成薄片，腌制10分钟。裹面粉、蛋液、面包糠。油炸至金黄酥脆。"},
{id:343,name:"鸡柳条",category:"meat",ingredients:["鸡胸肉","鸡蛋","淀粉","面包糠","盐","胡椒粉","生抽","料酒"],steps:"鸡肉切条腌制。裹淀粉、蛋液、面包糠。油炸至金黄，配番茄酱或蜂蜜芥末酱。"},
{id:344,name:"香酥鸡块",category:"meat",ingredients:["鸡肉","面粉","淀粉","泡打粉","盐","胡椒粉","五香粉","辣椒粉"],steps:"鸡肉切块加调料腌制。面粉淀粉泡打粉调成炸粉。鸡块裹粉后油炸至金黄。"},
{id:345,name:"鸡米花",category:"meat",ingredients:["鸡胸肉","鸡蛋","面粉","淀粉","盐","胡椒粉","辣椒粉","蒜粉"],steps:"鸡肉切小丁腌制。裹面粉淀粉蛋液糊。油炸至金黄酥脆，撒辣椒粉。"},
{id:346,name:"炸鸡翅",category:"meat",ingredients:["鸡中翅","面粉","淀粉","盐","胡椒粉","五香粉","辣椒粉","蒜粉"],steps:"鸡翅划两刀加调料腌制。裹面粉淀粉混合物。油炸至金黄酥脆。"},
{id:347,name:"香辣炸鸡翅",category:"meat",ingredients:["鸡中翅","辣椒粉","孜然粉","盐","胡椒粉","蒜粉","生抽","料酒"],steps:"鸡翅加调料腌制1小时。裹淀粉和辣椒粉混合物。油炸至金黄，撒孜然粉。"},
{id:348,name:"蜜汁烤翅",category:"meat",ingredients:["鸡中翅","蜂蜜","生抽","老抽","蚝油","蒜末","姜末","五香粉"],steps:"鸡翅加调料腌制2小时。烤箱200度烤20分钟，中途刷蜂蜜水翻面。"},
{id:349,name:"微波鸡翅",category:"meat",ingredients:["鸡中翅","生抽","老抽","蚝油","蜂蜜","蒜末","辣椒粉"],steps:"鸡翅加调料腌制30分钟。高火微波5分钟，翻面再微波3分钟。"},
{id:350,name:"红烧羊排",category:"meat",ingredients:["羊排","姜","八角","桂皮","香叶","生抽","老抽","蚝油","冰糖","料酒"],steps:"羊排斩段焯水。热油爆香姜和香料，下羊排翻炒。加调料和清水，大火烧开转小火焖1小时。"},
{id:351,name:"烤羊排",category:"meat",ingredients:["羊排","迷迭香","百里香","蒜末","盐","黑胡椒","橄榄油","柠檬"],steps:"羊排加调料腌制2小时。烤箱200度烤30分钟，中途翻面撒迷迭香。"},
{id:352,name:"葱爆羊肉",category:"meat",ingredients:["羊肉","大葱","姜丝","蒜","生抽","蚝油","料酒","糖","香油"],steps:"羊肉切片腌制。大葱切段。热油滑羊肉变色盛出。爆香姜蒜，下大葱翻炒，倒回羊肉加调料大火快炒。"},
{id:353,name:"孜然羊肉",category:"meat",ingredients:["羊肉","孜然粉","辣椒粉","盐","葱段","姜丝","蒜","生抽","蚝油"],steps:"羊肉切片腌制。热油爆香姜蒜，下羊肉大火翻炒至变色。加孜然粉、辣椒粉和葱段翻炒均匀。"},
{id:354,name:"红烧狗肉",category:"meat",ingredients:["狗肉","姜","八角","桂皮","香叶","生抽","老抽","蚝油","冰糖","料酒"],steps:"狗肉斩块焯水。热油爆香姜和香料，下狗肉翻炒。加调料和足量水，大火烧开转小火焖2小时。"},
{id:355,name:"狗肉煲",category:"meat",ingredients:["狗肉","姜","蒜","八角","桂皮","香叶","生抽","老抽","蚝油","柱候酱"],steps:"狗肉斩块焯水。砂锅热油爆香姜蒜和香料，下狗肉翻炒。加调料和清水，大火烧开转小火焖1.5小时。"},
{id:356,name:"田鸡煲",category:"meat",ingredients:["田鸡","姜","蒜","青红椒","生抽","老抽","蚝油","料酒","糖","淀粉"],steps:"田鸡处理干净斩块腌制。热油爆香姜蒜，下田鸡翻炒至变色。加调料和青红椒，焖煮10分钟。"},
{id:357,name:"椒盐田鸡",category:"meat",ingredients:["田鸡","椒盐","蒜蓉","辣椒","葱花","料酒","淀粉"],steps:"田鸡处理干净斩块，拍薄淀粉。六成热油炸至酥脆捞出。热锅少许油炒香蒜蓉辣椒，放入田鸡撒椒盐和葱花翻炒均匀。"},
{id:358,name:"清蒸田鸡",category:"meat",ingredients:["田鸡","姜丝","葱丝","生抽","花生油","红椒丝"],steps:"田鸡处理干净斩块摆盘，铺姜丝。大火蒸8分钟。出锅倒掉汁水，铺葱丝红椒丝，淋热油和生抽。"},
{id:359,name:"炒田螺",category:"meat",ingredients:["田螺","紫苏叶","姜丝","蒜蓉","辣椒","豆豉","生抽","蚝油","糖"],steps:"田螺焯水去泥。热油爆香姜蒜辣椒豆豉，下田螺大火翻炒。加调料和紫苏叶，加少许水焖3分钟。"},
{id:360,name:"炒花蛤",category:"meat",ingredients:["花蛤","金不换","蒜蓉","姜丝","辣椒","鱼露","花生油"],steps:"花蛤洗净沥干。热油爆香蒜姜辣椒，下花蛤大火爆炒。壳开时加入金不换和鱼露，快速翻炒出锅。"},
{id:361,name:"辣炒花蛤",category:"meat",ingredients:["花蛤","干辣椒","花椒","姜丝","蒜","葱段","生抽","蚝油","美极鲜"],steps:"花蛤洗净沥干。热油爆香干辣椒花椒姜蒜，下花蛤大火翻炒。加生抽蚝油美极鲜，壳开即可出锅。"},
{id:362,name:"蒜蓉蒸扇贝",category:"meat",ingredients:["扇贝","粉丝","蒜蓉","葱花","生抽","蚝油","花生油","小米辣"],steps:"粉丝泡软剪段，扇贝洗净留壳。蒜蓉用油炒香加生抽蚝油调汁。壳中铺粉丝、放扇贝、浇蒜蓉汁，大火蒸5分钟，撒葱花淋热油。"},
{id:363,name:"粉丝蒸扇贝",category:"meat",ingredients:["扇贝","龙口粉丝","蒜蓉","生抽","蚝油","葱花","红椒粒"],steps:"粉丝泡软铺扇贝壳底。扇贝肉洗净放粉丝上。蒜蓉炒香淋在扇贝上，大火蒸5分钟。撒葱花淋热油。"},
{id:364,name:"烤扇贝",category:"meat",ingredients:["扇贝","蒜蓉","黄油","盐","胡椒粉","柠檬","葱花"],steps:"扇贝处理干净。蒜蓉、黄油和调料混合。扇贝上铺蒜蓉黄油，烤箱180度烤8分钟。挤柠檬汁。"},
{id:365,name:"清蒸鲍鱼",category:"meat",ingredients:["鲍鱼","姜丝","葱丝","生抽","花生油","红椒丝"],steps:"鲍鱼刷洗干净刻花刀。大火蒸5分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和生抽。"},
{id:366,name:"蒜蓉蒸鲍鱼",category:"meat",ingredients:["鲍鱼","蒜蓉","葱花","生抽","蚝油","花生油"],steps:"鲍鱼处理干净。蒜蓉炒香铺鲍鱼上，大火蒸5分钟。撒葱花淋热油和生抽蚝油。"},
{id:367,name:"红烧鲍鱼",category:"meat",ingredients:["鲍鱼","姜","葱","生抽","老抽","蚝油","糖","料酒","高汤"],steps:"鲍鱼处理干净切花刀。煎至两面金黄。加姜葱和调料翻炒，加高汤焖5分钟。"},
{id:368,name:"清蒸鳜鱼",category:"meat",ingredients:["鳜鱼","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"鱼处理干净划花刀，铺姜丝。水开上锅大火蒸8-10分钟。倒掉腥水，铺葱丝红椒丝，淋热油和蒸鱼豉油。"},
{id:369,name:"松鼠鳜鱼",category:"meat",ingredients:["鳜鱼","番茄酱","白醋","糖","盐","淀粉","姜丝","葱丝"],steps:"鱼去骨切花刀，裹淀粉炸至定型呈松鼠形状。糖醋汁：番茄酱+白醋+糖+盐+水煮开。淋在鱼上。"},
{id:370,name:"干烧鳜鱼",category:"meat",ingredients:["鳜鱼","五花肉","冬笋","香菇","姜蒜末","豆瓣酱","生抽","老抽","糖"],steps:"鱼处理干净煎至两面金黄。五花肉冬笋香菇切丁。爆香姜蒜末和豆瓣酱，下配料翻炒。加调料和水，放鱼大火烧开转小火焖。"},
{id:371,name:"清蒸石斑鱼",category:"meat",ingredients:["石斑鱼","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"鱼处理干净划花刀。水开上锅大火蒸8-10分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和蒸鱼豉油。"},
{id:372,name:"红烧石斑鱼",category:"meat",ingredients:["石斑鱼","姜","蒜","葱","生抽","老抽","蚝油","糖","料酒"],steps:"鱼处理干净煎至两面金黄。爆香姜葱蒜，下鱼加调料和少许水，大火烧开转小火焖10分钟。"},
{id:373,name:"清蒸鲈鱼",category:"meat",ingredients:["鲈鱼","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"鱼处理干净划花刀。水开上锅大火蒸8-10分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和蒸鱼豉油。"},
{id:374,name:"豆豉鲈鱼",category:"meat",ingredients:["鲈鱼","豆豉","姜丝","葱丝","蒜蓉","生抽","蚝油","糖","料酒"],steps:"鱼处理干净铺盘。豆豉剁碎加蒜蓉姜丝铺鱼身上，淋调料。大火蒸10分钟，撒葱丝淋热油。"},
{id:375,name:"香煎鲈鱼",category:"meat",ingredients:["鲈鱼","盐","姜片","黑胡椒","柠檬","花生油"],steps:"鲈鱼切厚片，用盐和黑胡椒腌制10分钟。平底锅热油，中火煎至两面金黄。挤柠檬汁。"},
{id:376,name:"清蒸黄鱼",category:"meat",ingredients:["黄鱼","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"黄鱼处理干净。水开上锅大火蒸8-10分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和蒸鱼豉油。"},
{id:377,name:"干煎黄鱼",category:"meat",ingredients:["黄鱼","盐","姜","花生油","柠檬"],steps:"黄鱼处理干净划花刀，盐和姜腌制15分钟。平底锅热油，中火慢煎至两面金黄酥脆。挤柠檬汁。"},
{id:378,name:"雪菜黄鱼汤",category:"meat",ingredients:["黄鱼","雪菜","笋丝","姜片","葱段","料酒","盐"],steps:"黄鱼煎至两面金黄。加料酒和开水大火煮10分钟至汤白。放入雪菜和笋丝煮5分钟，加盐调味。"},
{id:379,name:"清蒸带鱼",category:"meat",ingredients:["带鱼","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"带鱼处理干净切段。水开上锅大火蒸8分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和蒸鱼豉油。"},
{id:380,name:"红烧带鱼",category:"meat",ingredients:["带鱼","姜","蒜","葱","生抽","老抽","蚝油","糖","醋","料酒"],steps:"带鱼切段煎至两面金黄。爆香姜蒜葱，下带鱼加调料和少许水，大火烧开转小火焖10分钟。"},
{id:381,name:"干煎带鱼",category:"meat",ingredients:["带鱼","盐","姜片","花生油"],steps:"带鱼处理干净切段，盐和姜片腌制15分钟。平底锅热油，中火慢煎至两面金黄酥脆。"},
{id:382,name:"清蒸鲳鱼",category:"meat",ingredients:["鲳鱼","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"鲳鱼处理干净。水开上锅大火蒸8-10分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和蒸鱼豉油。"},
{id:383,name:"红烧鲳鱼",category:"meat",ingredients:["鲳鱼","姜","蒜","葱","生抽","老抽","蚝油","糖","料酒"],steps:"鲳鱼处理干净煎至两面金黄。爆香姜蒜葱，下鱼加调料和少许水，大火烧开转小火焖。"},
{id:384,name:"香煎鲳鱼",category:"meat",ingredients:["鲳鱼","盐","姜","花生油","柠檬"],steps:"鲳鱼处理干净，盐和姜腌制15分钟。平底锅热油，中火煎至两面金黄。挤柠檬汁。"},
{id:385,name:"清蒸鳗鱼",category:"meat",ingredients:["鳗鱼","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"鳗鱼处理干净切段。水开上锅大火蒸10分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和蒸鱼豉油。"},
{id:386,name:"红烧鳗鱼",category:"meat",ingredients:["鳗鱼","姜","蒜","葱","生抽","老抽","蚝油","糖","料酒"],steps:"鳗鱼切段煎至两面金黄。爆香姜蒜葱，下鳗鱼加调料，大火烧开转小火焖15分钟。"},
{id:387,name:"蒜香鳗鱼",category:"meat",ingredients:["鳗鱼","蒜蓉","姜末","葱花","生抽","老抽","蚝油","糖","料酒"],steps:"鳗鱼切段腌制。热油炒香蒜蓉姜末，下鳗鱼煎至金黄。加调料和少许水，焖煮入味。"},
{id:388,name:"清蒸多宝鱼",category:"meat",ingredients:["多宝鱼","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"多宝鱼处理干净。水开上锅大火蒸8-10分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和蒸鱼豉油。"},
{id:389,name:"清蒸老虎斑",category:"meat",ingredients:["老虎斑","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"老虎斑处理干净划花刀。水开上锅大火蒸8-10分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和蒸鱼豉油。"},
{id:390,name:"老鼠斑刺身",category:"meat",ingredients:["老鼠斑","紫苏叶","姜丝","葱丝","柠檬","酱油","芥末"],steps:"老鼠斑处理干净，切薄片。冰镇上桌。配紫苏叶、柠檬、芥末酱油蘸食。"},
{id:391,name:"清蒸龙趸",category:"meat",ingredients:["龙趸","姜丝","葱丝","红椒丝","蒸鱼豉油","花生油","料酒"],steps:"龙趸处理干净切块。水开上锅大火蒸8-10分钟。倒掉汁水，铺葱丝姜丝红椒丝，淋热油和蒸鱼豉油。"},
{id:392,name:"石头鱼汤",category:"meat",ingredients:["石头鱼","嫩豆腐","姜片","葱段","盐","白胡椒粉","料酒"],steps:"石头鱼处理干净煎至两面金黄。加料酒和足量开水，大火煮10分钟至汤白。放入豆腐煮5分钟，加盐和胡椒粉。"},
{id:393,name:"海鳗鱼煲",category:"meat",ingredients:["海鳗","五花肉","姜","蒜","青红椒","生抽","老抽","蚝油","糖","料酒"],steps:"海鳗切段煎至两面金黄。五花肉切片。砂锅爆香姜蒜，下鳗鱼和五花肉，加调料和水焖煮15分钟。"},
{id:394,name:"红烧海鳗",category:"meat",ingredients:["海鳗","姜","葱","蒜","生抽","老抽","蚝油","糖","醋","料酒"],steps:"海鳗切段煎至两面金黄。爆香姜蒜葱，下鳗鱼加调料，大火烧开转小火焖15分钟。"},
{id:395,name:"生炒海鳗",category:"meat",ingredients:["海鳗","青红椒","洋葱","姜丝","蒜","生抽","蚝油","糖","料酒","淀粉"],steps:"海鳗切段腌制。热油滑鳗鱼变色盛出。爆香姜蒜和青红椒，倒回鳗鱼加调料大火翻炒。"},
// ==================== 追加素菜类 ====================
{id:396,name:"素炒麻叶",category:"vegetable",ingredients:["麻叶","蒜","豆酱","盐","花生油"],steps:"麻叶洗净，热油爆香蒜末，放麻叶大火快速翻炒，加盐和豆酱调味。"},
{id:397,name:"苦刺肉丸",category:"vegetable",ingredients:["苦刺","猪肉末","盐","生抽","淀粉"],steps:"苦刺剁碎与肉末混合搅拌上劲，挤丸子下锅煮熟。"},
{id:398,name:"上汤枸杞叶",category:"vegetable",ingredients:["枸杞叶","皮蛋","咸鸭蛋","蒜末","盐","胡椒粉"],steps:"皮蛋咸蛋切块炒香加水煮开，放枸杞叶煮软调味。"},
{id:399,name:"珍珠菜煎蛋",category:"vegetable",ingredients:["珍珠菜","鸡蛋","牛奶","葱花","盐"],steps:"珍珠菜洗净与蛋液混合，加牛奶葱花，平底锅小火煎至两面金黄。"},
{id:400,name:"芋粿",category:"vegetable",ingredients:["芋头","薯粉","花生","干香菇","五香粉","胡椒粉","盐","细砂糖","玉米油"],steps:"芋头切丝，香菇花生切丁爆香，混合加调料和薯粉整形，蒸25分钟。"},
{id:401,name:"坚果榄菜脆瓜",category:"vegetable",ingredients:["西葫芦","熟腰果","橄榄菜","纯净水","茶籽油","盐"],steps:"西葫芦切片，腰果橄榄菜准备好，热油炒西葫芦，加橄榄菜和纯净水煮1分钟，加腰果。"},
{id:402,name:"芥蓝炒香菇腊肠",category:"vegetable",ingredients:["芥蓝","香菇","腊肠","蒜","盐","蚝油"],steps:"芥蓝处理干净切段，香菇腊肠切片，热油爆香蒜，放腊肠香菇翻炒，放芥蓝大火快炒。"},
{id:403,name:"荷塘月色",category:"vegetable",ingredients:["豌豆","藕片","胡萝卜","黑木耳","盐","蚝油"],steps:"所有食材焯水40秒，热锅翻炒加调料。"},
{id:404,name:"西兰花蚝油香菇",category:"vegetable",ingredients:["西兰花","香菇","蒜末","蚝油","生抽","糖"],steps:"西兰花焯水，香菇泡发炒香，加调料翻炒。"},
{id:405,name:"清炒通菜",category:"vegetable",ingredients:["空心菜","蒜蓉","盐","鱼露","花生油"],steps:"空心菜摘段洗净。热油爆香蒜蓉，下空心菜大火快速翻炒。加盐和少许鱼露调味。"},
{id:406,name:"虾酱炒空心菜",category:"vegetable",ingredients:["空心菜","虾酱","蒜蓉","辣椒","蚝油","花生油"],steps:"空心菜摘段洗净。虾酱用少许水调开。热油爆香蒜蓉辣椒，下虾酱炒香。放入空心菜大火爆炒，加蚝油，快速翻炒出锅。"},
{id:407,name:"腐乳炒通菜",category:"vegetable",ingredients:["空心菜","腐乳","蒜蓉","辣椒","糖","花生油"],steps:"空心菜摘段洗净。腐乳压碎加少许水和糖调开。热油爆香蒜蓉辣椒，下空心菜大火爆炒。淋腐乳汁快速翻炒均匀出锅。"},
{id:408,name:"普宁豆酱炒空心菜",category:"vegetable",ingredients:["空心菜","普宁豆酱","蒜蓉","辣椒","花生油"],steps:"空心菜摘段洗净。热油爆香蒜蓉和辣椒，下空心菜大火爆炒。加入普宁豆酱翻炒均匀。"},
{id:409,name:"姜丝炒芥蓝",category:"vegetable",ingredients:["芥蓝","姜丝","盐","蚝油","花生油","料酒"],steps:"芥蓝去老叶，粗茎对剖。热油爆香姜丝，下芥蓝大火翻炒。沿锅边淋少许料酒和水，盖盖焖1分钟。加蚝油和盐调味出锅。"},
{id:410,name:"白灼芥蓝",category:"vegetable",ingredients:["芥蓝","蒜蓉","生抽","蚝油","花生油","盐"],steps:"芥蓝去老叶洗净。水开加油盐，放入芥蓝焯1-2分钟至翠绿。捞出摆盘淋生抽蚝油，铺蒜蓉，淋热油激香。"},
{id:411,name:"清炒菜心",category:"vegetable",ingredients:["菜心","蒜蓉","盐","蚝油","花生油"],steps:"菜心洗净去老叶。热油爆香蒜蓉，下菜心大火翻炒至变软出水。加盐和蚝油调味。"},
{id:412,name:"白灼菜心",category:"vegetable",ingredients:["菜心","蒜蓉","生抽","蚝油","花生油","盐"],steps:"菜心洗净去老叶。水开加油盐，放入菜心焯1-2分钟至翠绿。捞出摆盘淋生抽蚝油，铺蒜蓉，淋热油激香。"},
{id:413,name:"蒜蓉炒菜心",category:"vegetable",ingredients:["菜心","蒜蓉","盐","生抽","花生油"],steps:"菜心洗净切段。热油爆香蒜蓉，下菜心大火翻炒至软。加盐和少许生抽调味。"},
{id:414,name:"清炒春菜",category:"vegetable",ingredients:["春菜","蒜蓉","盐","蚝油","花生油"],steps:"春菜洗净切段。热油大蒜爆香，下春菜大火翻炒至变软出水。加盐和蚝油调味，炒至菜叶软熟即可。"},
{id:415,name:"蒜蓉炒春菜",category:"vegetable",ingredients:["春菜","蒜蓉","盐","生抽","花生油"],steps:"春菜洗净切段。热油爆香蒜蓉，下春菜大火翻炒至软。加盐和生抽调味。"},
{id:416,name:"清炒大芥菜",category:"vegetable",ingredients:["大芥菜","蒜蓉","盐","蚝油","花生油","姜片"],steps:"大芥菜洗净切段。沸水焯1分钟去苦味捞出。热油爆香蒜蓉姜片，下芥菜大火翻炒。加蚝油和盐调味。"},
{id:417,name:"咸酸菜炒大芥菜",category:"vegetable",ingredients:["大芥菜","咸酸菜","蒜蓉","糖","花生油"],steps:"大芥菜切丝，咸酸菜切丝泡水。热油爆香蒜蓉，下芥菜丝翻炒，加咸酸菜丝和糖，大火翻炒均匀。"},
{id:418,name:"清炒菠菜",category:"vegetable",ingredients:["菠菜","蒜蓉","盐","蚝油","花生油"],steps:"菠菜洗净去根。沸水加油盐焯30秒捞出挤干。热油爆香蒜蓉，下菠菜快速翻炒。加蚝油和盐调味出锅。"},
{id:419,name:"蒜蓉炒菠菜",category:"vegetable",ingredients:["菠菜","蒜蓉","盐","鱼露","花生油"],steps:"菠菜洗净。热油爆香蒜蓉，下菠菜大火翻炒至软。加盐和少许鱼露调味。"},
{id:420,name:"白灼菠菜",category:"vegetable",ingredients:["菠菜","蒜蓉","生抽","蚝油","花生油","盐"],steps:"菠菜洗净。沸水加油盐焯30秒捞出过凉水。摆盘铺蒜蓉，淋热油和生抽蚝油。"},
{id:421,name:"清炒莙荙菜",category:"vegetable",ingredients:["莙荙菜","蒜蓉","盐","蚝油","花生油"],steps:"莙荙菜洗净切段。热油爆香蒜蓉，下菜大火翻炒至软。加盐和蚝油调味。"},
{id:422,name:"清炒茼蒿",category:"vegetable",ingredients:["茼蒿","蒜蓉","盐","蚝油","花生油"],steps:"茼蒿洗净切段。热油爆香蒜蓉，下茼蒿大火翻炒至软。加盐和蚝油调味。"},
{id:423,name:"蒜蓉炒茼蒿",category:"vegetable",ingredients:["茼蒿","蒜蓉","盐","生抽","花生油"],steps:"茼蒿洗净。热油爆香蒜蓉，下茼蒿大火翻炒至软。加盐和生抽调味。"},
{id:424,name:"清炒芹菜",category:"vegetable",ingredients:["芹菜","蒜蓉","盐","蚝油","花生油"],steps:"芹菜去筋切段。热油爆香蒜蓉，下芹菜大火翻炒至断生。加盐和蚝油调味。"},
{id:425,name:"西芹炒百合",category:"vegetable",ingredients:["西芹","鲜百合","红椒","蒜蓉","盐","蚝油","花生油"],steps:"西芹去筋切斜段，百合剥片洗净。西芹焯水30秒。热油爆香蒜蓉，下西芹和红椒翻炒。加百合，加盐蚝油快速炒匀。"},
{id:426,name:"清炒豆苗",category:"vegetable",ingredients:["豆苗","蒜蓉","盐","蚝油","花生油","料酒"],steps:"豆苗摘去老茎洗净沥干。热油爆香蒜蓉，下豆苗大火快炒。沿锅边淋料酒，加盐和蚝油翻炒十几秒出锅。"},
{id:427,name:"上汤豆苗",category:"vegetable",ingredients:["豆苗","皮蛋","咸鸭蛋","蒜","高汤","盐"],steps:"皮蛋咸蛋切丁。热油炸香蒜，加高汤煮开。下皮蛋咸蛋煮2分钟，放入豆苗煮软，加盐调味。"},
{id:428,name:"普宁豆酱炒豆苗",category:"vegetable",ingredients:["豆苗","普宁豆酱","蒜蓉","花生油"],steps:"豆苗摘去老茎洗净。热油爆香蒜蓉，下豆苗大火快炒。加普宁豆酱调味，翻炒十几秒出锅。"},
{id:429,name:"清炒紫角叶",category:"vegetable",ingredients:["紫角叶","蒜蓉","盐","蚝油","花生油"],steps:"紫角叶摘嫩尖洗净。热油爆香蒜蓉，下紫角叶大火快速翻炒。加盐和蚝油调味。"},
{id:430,name:"蒜蓉炒紫角叶",category:"vegetable",ingredients:["紫角叶","蒜蓉","盐","生抽","花生油"],steps:"紫角叶摘嫩尖洗净。热油爆香蒜蓉，下紫角叶大火快速翻炒。加盐和生抽调味。"},
{id:431,name:"清炒木耳菜",category:"vegetable",ingredients:["木耳菜","蒜蓉","盐","蚝油","花生油"],steps:"木耳菜摘叶洗净。热油爆香蒜蓉，下木耳菜大火翻炒至软。加盐和蚝油调味。"},
{id:432,name:"蒜蓉炒木耳菜",category:"vegetable",ingredients:["木耳菜","蒜蓉","盐","鱼露","花生油"],steps:"木耳菜摘叶洗净。热油爆香蒜蓉，下木耳菜大火翻炒至软。加盐和少许鱼露调味。"},
{id:433,name:"清炒番薯叶",category:"vegetable",ingredients:["番薯叶","蒜蓉","盐","鱼露","花生油"],steps:"番薯叶摘嫩茎叶洗净。热油爆香蒜蓉，下番薯叶大火快速翻炒。加盐和少许鱼露调味。"},
{id:434,name:"蒜蓉炒番薯叶",category:"vegetable",ingredients:["番薯叶","蒜蓉","盐","蚝油","花生油"],steps:"番薯叶摘嫩茎叶洗净。热油爆香蒜蓉，下番薯叶大火快速翻炒。加盐和蚝油调味。"},
{id:435,name:"炒南瓜藤",category:"vegetable",ingredients:["南瓜藤","蒜蓉","盐","蚝油","花生油","红椒"],steps:"南瓜藤撕去外皮切段。热油爆香蒜蓉和红椒，下南瓜藤大火翻炒。加盐和蚝油调味。"},
{id:436,name:"清炒苦瓜",category:"vegetable",ingredients:["苦瓜","蒜蓉","豆豉","盐","糖","蚝油","花生油"],steps:"苦瓜对剖去瓤切薄片，盐腌10分钟挤去苦水。热油爆香蒜蓉豆豉，下苦瓜大火翻炒。加糖和蚝油调味。"},
{id:437,name:"清炒丝瓜",category:"vegetable",ingredients:["丝瓜","蒜蓉","盐","花生油","枸杞"],steps:"丝瓜去皮切滚刀块。热油爆香蒜蓉，下丝瓜翻炒。加少许水煮2-3分钟至丝瓜变软出水。加盐调味，撒枸杞。"},
{id:438,name:"蒜蓉蒸丝瓜",category:"vegetable",ingredients:["丝瓜","蒜蓉","生抽","蚝油","葱花","花生油"],steps:"丝瓜去皮切段，铺盘。蒜蓉炒香铺丝瓜上。大火蒸5分钟。撒葱花淋热油和生抽蚝油。"},
{id:439,name:"红烧丝瓜",category:"vegetable",ingredients:["丝瓜","生抽","老抽","蚝油","糖","蒜蓉","葱花"],steps:"丝瓜去皮切滚刀块。热油煎丝瓜两面微黄。加生抽老抽蚝油糖和少许水，焖煮3分钟。大火收汁撒葱花。"},
{id:440,name:"清炒冬瓜",category:"vegetable",ingredients:["冬瓜","蒜蓉","盐","蚝油","花生油"],steps:"冬瓜去皮切薄片。热油爆香蒜蓉，下冬瓜翻炒。加少许水煮2-3分钟至冬瓜变软。加盐和蚝油调味。"},
{id:441,name:"红烧冬瓜",category:"vegetable",ingredients:["冬瓜","生抽","老抽","蚝油","糖","蒜蓉","葱花"],steps:"冬瓜去皮切大块。热油煎冬瓜两面微黄。加生抽老抽蚝油糖和少许水，大火煮开转小火焖15分钟至透明。"},
{id:442,name:"蚝油冬瓜",category:"vegetable",ingredients:["冬瓜","蚝油","生抽","蒜蓉","葱花","花生油","高汤"],steps:"冬瓜去皮去瓤切厚片。热油爆香蒜蓉，下冬瓜翻炒。加蚝油、生抽和高汤，大火煮开转中火焖至冬瓜透明软烂。撒葱花。"},
{id:443,name:"清炒南瓜",category:"vegetable",ingredients:["南瓜","蒜蓉","葱","盐","蚝油","花生油"],steps:"南瓜去皮去瓤切薄片。热油爆香蒜蓉，下南瓜片翻炒。加少许水焖3-5分钟至南瓜软糯。加蚝油和盐调味，撒葱花。"},
{id:444,name:"咸蛋黄焗南瓜",category:"vegetable",ingredients:["南瓜","咸蛋黄","盐","淀粉","花生油"],steps:"南瓜去皮切条，焯水至半熟沥干拍淀粉油炸至金黄。咸蛋黄蒸熟碾碎。少许油炒咸蛋黄至起泡，放入南瓜条翻炒均匀裹上蛋黄。"},
{id:445,name:"清炒西葫芦",category:"vegetable",ingredients:["西葫芦","蒜蓉","盐","蚝油","花生油"],steps:"西葫芦切片。热油爆香蒜蓉，下西葫芦大火翻炒至微软。加盐和蚝油调味。"},
{id:446,name:"清炒苦苣",category:"vegetable",ingredients:["苦苣","蒜蓉","盐","蚝油","花生油"],steps:"苦苣摘嫩叶洗净。热油爆香蒜蓉，下苦苣大火快速翻炒。加盐和蚝油调味。"},
{id:447,name:"麻酱拌苦苣",category:"vegetable",ingredients:["苦苣","芝麻酱","生抽","醋","糖","蒜末","香油"],steps:"苦苣洗净摆盘。芝麻酱加生抽、醋、糖、蒜末和香油调成酱汁。淋在苦苣上拌匀。"},
{id:448,name:"清炒油麦菜",category:"vegetable",ingredients:["油麦菜","蒜蓉","盐","蚝油","花生油"],steps:"油麦菜洗净切段。热油爆香蒜蓉，下油麦菜大火快速翻炒。加盐和蚝油调味。"},
{id:449,name:"蒜蓉炒油麦菜",category:"vegetable",ingredients:["油麦菜","蒜蓉","盐","生抽","花生油"],steps:"油麦菜洗净。热油爆香蒜蓉，下油麦菜大火快速翻炒。加盐和生抽调味。"},
{id:450,name:"豆豉鲮鱼炒油麦菜",category:"vegetable",ingredients:["油麦菜","豆豉鲮鱼罐头","蒜蓉","生抽","花生油"],steps:"油麦菜洗净切段。打开豆豉鲮鱼罐头，鲮鱼撕成小块。热油爆香蒜蓉，下油麦菜大火翻炒。加入豆豉鲮鱼和少许生抽翻炒均匀。"},
{id:451,name:"清炒生菜",category:"vegetable",ingredients:["生菜","蒜蓉","盐","蚝油","花生油"],steps:"生菜洗净撕块。热油爆香蒜蓉，下生菜大火快速翻炒至微软。加盐和蚝油调味。"},
{id:452,name:"蚝油生菜",category:"vegetable",ingredients:["生菜","蚝油","生抽","蒜蓉","糖","花生油","淀粉"],steps:"生菜洗净。水开加油盐，生菜焯10秒捞出摆盘。蚝油、生抽、糖、蒜蓉和水煮开，勾薄芡淋在生菜上。"},
{id:453,name:"白灼生菜",category:"vegetable",ingredients:["生菜","蒜蓉","生抽","蚝油","花生油","盐"],steps:"生菜洗净。水开加油盐，生菜焯10秒捞出过凉水。摆盘铺蒜蓉，淋热油和生抽蚝油。"},
{id:454,name:"凉拌生菜",category:"vegetable",ingredients:["生菜","蒜末","陈醋","生抽","糖","香油","辣椒油"],steps:"生菜洗净撕块。所有调料混合成酱汁。浇在生菜上拌匀，腌制10分钟入味。"},
{id:455,name:"清炒娃娃菜",category:"vegetable",ingredients:["娃娃菜","蒜蓉","盐","蚝油","花生油"],steps:"娃娃菜对剖洗净。热油爆香蒜蓉，下娃娃菜大火翻炒。加少许水焖2分钟至软。加蚝油和盐调味出锅。"},
{id:456,name:"蒜蓉粉丝蒸娃娃菜",category:"vegetable",ingredients:["娃娃菜","粉丝","蒜蓉","生抽","蚝油","葱花","花生油"],steps:"粉丝泡软铺盘底。娃娃菜对剖焯水铺粉丝上。蒜蓉炒香加生抽蚝油调汁淋在菜上。大火蒸8分钟，撒葱花淋热油。"},
{id:457,name:"上汤娃娃菜",category:"vegetable",ingredients:["娃娃菜","皮蛋","咸鸭蛋","火腿","蒜蓉","高汤","盐"],steps:"皮蛋咸蛋切丁，火腿切丝。热油炒香蒜蓉，加高汤煮开。放入对剖的娃娃菜煮软。加入皮蛋咸蛋火腿煮2分钟，加盐调味。"},
{id:458,name:"清炒西兰花",category:"vegetable",ingredients:["西兰花","蒜蓉","盐","蚝油","花生油"],steps:"西兰花切小朵，盐水浸泡洗净。沸水加油盐焯1分钟捞出。热油爆香蒜蓉，下西兰花加蚝油盐大火翻炒均匀即可。"},
{id:459,name:"蒜蓉西兰花",category:"vegetable",ingredients:["西兰花","蒜蓉","盐","生抽","花生油"],steps:"西兰花切小朵洗净。热油爆香蒜蓉，下西兰花大火翻炒至断生。加盐和生抽调味。"},
{id:460,name:"蚝油西兰花",category:"vegetable",ingredients:["西兰花","香菇","蒜末","蚝油","生抽","糖"],steps:"西兰花焯水，香菇泡发炒香，加调料翻炒。"},
{id:461,name:"清炒花菜",category:"vegetable",ingredients:["花菜","蒜蓉","盐","蚝油","花生油"],steps:"花菜切小朵洗净。沸水焯1分钟捞出。热油爆香蒜蓉，下花菜大火翻炒。加盐和蚝油调味。"},
{id:462,name:"干锅花菜",category:"vegetable",ingredients:["花菜","五花肉","青红椒","干辣椒","姜蒜","豆瓣酱","生抽","蚝油","糖"],steps:"花菜切小朵炸至微黄。五花肉切片。热油炒香五花肉和豆瓣酱，下花菜和青红椒翻炒。加调料和水，焖煮入味。"},
{id:463,name:"清炒荷兰豆",category:"vegetable",ingredients:["荷兰豆","蒜蓉","盐","蚝油","花生油"],steps:"荷兰豆去筋洗净焯水30秒。热油爆香蒜蓉，下荷兰豆大火翻炒。加盐和蚝油调味。"},
{id:464,name:"荷兰豆炒腊肠",category:"vegetable",ingredients:["荷兰豆","腊肠","蒜蓉","盐","蚝油","花生油"],steps:"荷兰豆去筋洗净焯水。腊肠切片。热油炒腊肠出油，加蒜蓉炒香。下荷兰豆大火翻炒，加蚝油盐调味。"},
{id:465,name:"清炒甜豆",category:"vegetable",ingredients:["甜豆","蒜蓉","盐","蚝油","花生油"],steps:"甜豆去头尾洗净焯水30秒。热油爆香蒜蓉，下甜豆大火翻炒。加盐和蚝油调味。"},
{id:466,name:"清炒豌豆苗",category:"vegetable",ingredients:["豌豆苗","蒜蓉","盐","蚝油","花生油"],steps:"豌豆苗摘嫩尖洗净。热油爆香蒜蓉，下豌豆苗大火快速翻炒。加盐和蚝油调味。"},
{id:467,name:"清炒四季豆",category:"vegetable",ingredients:["四季豆","蒜蓉","干辣椒","盐","蚝油","花生油"],steps:"四季豆去筋掰段。沸水焯至断生。热油爆香蒜蓉干辣椒，下四季豆大火翻炒。加盐和蚝油调味。"},
{id:468,name:"干煸四季豆",category:"vegetable",ingredients:["四季豆","猪肉末","蒜蓉","干辣椒","生抽","盐","花椒"],steps:"四季豆去筋掰段。热油煸炒四季豆至表面起皱盛出。炒香肉末、蒜蓉、干辣椒和花椒。倒回四季豆，加生抽和盐翻炒均匀。"},
{id:469,name:"榄菜炒四季豆",category:"vegetable",ingredients:["四季豆","橄榄菜","蒜蓉","盐","花生油"],steps:"四季豆去筋切粒。沸水焯至断生捞出。热油爆香蒜蓉，下四季豆翻炒。加橄榄菜翻炒均匀。"},
{id:470,name:"清炒豆角",category:"vegetable",ingredients:["豆角","蒜蓉","盐","蚝油","花生油"],steps:"豆角去头尾掰段，焯水至断生。热油爆香蒜蓉，下豆角翻炒。加盐和蚝油调味。"},
{id:471,name:"豆酱炒豆角",category:"vegetable",ingredients:["豆角","普宁豆酱","蒜蓉","花生油"],steps:"豆角去头尾掰段，焯水至断生。热油爆香蒜蓉，下豆角翻炒。加普宁豆酱调味，翻炒均匀。"},
{id:472,name:"干煸豆角",category:"vegetable",ingredients:["豆角","干辣椒","花椒","蒜","姜","盐","生抽","香油"],steps:"豆角去筋掰段，炸至虎皮皱捞出。锅留底油炒香干辣椒花椒姜蒜，倒回豆角加盐和生抽翻炒均匀。"},
{id:473,name:"清炒土豆丝",category:"vegetable",ingredients:["土豆","青椒","干辣椒","蒜","白醋","盐","花椒"],steps:"土豆去皮切细丝泡水去淀粉沥干。热油爆香蒜、干辣椒和花椒。下土豆丝大火爆炒，沿锅边淋白醋。加青椒丝和盐，翻炒至断生即可。"},
{id:474,name:"酸辣土豆丝",category:"vegetable",ingredients:["土豆","干辣椒","花椒","蒜","白醋","盐","葱段"],steps:"土豆切细丝泡水去淀粉沥干。热油爆香花椒干辣椒蒜。下土豆丝大火爆炒。沿锅边淋白醋，加盐和葱段。翻炒至断生出锅。"},
{id:475,name:"红烧土豆",category:"vegetable",ingredients:["土豆","生抽","老抽","蚝油","糖","蒜","葱","姜"],steps:"土豆去皮切滚刀块，煎至两面金黄。爆香蒜姜，加生抽老抽蚝油糖和少许水，放土豆焖煮15分钟。"},
{id:476,name:"地三鲜",category:"vegetable",ingredients:["茄子","土豆","青椒","蒜","姜","豆瓣酱","生抽","老抽","糖","淀粉"],steps:"茄子、土豆、青椒分别切块炸或煎至金黄。爆香蒜姜豆瓣酱，下所有材料翻炒。加调料和水，焖煮入味，勾芡。"},
{id:477,name:"清炒藕片",category:"vegetable",ingredients:["莲藕","蒜","盐","白醋","葱花","花生油"],steps:"莲藕去皮切薄片泡水防氧化。沸水加白醋焯30秒捞出。热油爆香蒜，下藕片大火翻炒。加盐和少许白醋，撒葱花出锅。"},
{id:478,name:"糖醋藕片",category:"vegetable",ingredients:["莲藕","番茄酱","白醋","糖","盐","淀粉","葱花"],steps:"莲藕去皮切薄片，焯水后拍淀粉炸至金黄。糖醋汁煮开：番茄酱+白醋+糖+盐+水。倒入藕片翻炒均匀，撒葱花。"},
{id:479,name:"清炒莲藕",category:"vegetable",ingredients:["莲藕","姜丝","葱花","盐","白醋","花生油"],steps:"莲藕去皮切片。热油爆香姜丝，下藕片翻炒。加白醋和盐调味，撒葱花。"},
{id:480,name:"桂花糯米藕",category:"vegetable",ingredients:["莲藕","糯米","红糖","冰糖","桂花蜜","红枣"],steps:"糯米提前泡4小时。莲藕去皮切盖，塞入糯米。放入锅中加红糖、冰糖、红枣和适量水，小火煮2小时至软糯。切片淋桂花蜜。"},
{id:481,name:"清炒胡萝卜",category:"vegetable",ingredients:["胡萝卜","蒜","盐","蚝油","花生油"],steps:"胡萝卜切丝。热油爆香蒜，下胡萝卜丝大火翻炒至软。加盐和蚝油调味。"},
{id:482,name:"凉拌胡萝卜丝",category:"vegetable",ingredients:["胡萝卜","蒜末","香菜","盐","生抽","醋","香油","辣椒油"],steps:"胡萝卜切丝焯水过凉。加蒜末、香菜和所有调料拌匀。"},
{id:483,name:"清炒山药",category:"vegetable",ingredients:["山药","木耳","青红椒","蒜","盐","蚝油","花生油"],steps:"山药去皮切片（戴手套），木耳泡发撕小朵，青红椒切片。热油爆香蒜，下山药和木耳翻炒。加青红椒和盐蚝油调味。"},
{id:484,name:"蓝莓山药",category:"vegetable",ingredients:["山药","蓝莓酱","蜂蜜","盐","凉白开"],steps:"山药去皮切段蒸熟，压成泥。加蓝莓酱和蜂蜜拌匀，团成球或条形。"},
{id:485,name:"清炒茭白",category:"vegetable",ingredients:["茭白","青红椒","蒜","盐","蚝油","花生油"],steps:"茭白去皮切片，青红椒切丝。热油爆香蒜，下茭白大火翻炒。加青红椒和盐蚝油调味。"},
{id:486,name:"清炒芦笋",category:"vegetable",ingredients:["芦笋","蒜","盐","蚝油","花生油"],steps:"芦笋去老根切段，焯水30秒。热油爆香蒜，下芦笋大火翻炒。加盐和蚝油调味。"},
{id:487,name:"白灼芦笋",category:"vegetable",ingredients:["芦笋","蒜蓉","生抽","蚝油","花生油","盐"],steps:"芦笋去老根洗净。水开加油盐，芦笋焯1分钟捞出过凉水。摆盘铺蒜蓉，淋热油和生抽蚝油。"},
{id:488,name:"清炒莴笋",category:"vegetable",ingredients:["莴笋","蒜蓉","盐","蚝油","花生油","枸杞"],steps:"莴笋去皮切片。沸水加盐焯30秒捞出。热油爆香蒜蓉，下莴笋大火翻炒。加蚝油和盐调味，撒几粒枸杞点缀。"},
{id:489,name:"糖醋莴笋",category:"vegetable",ingredients:["莴笋","胡萝卜","干辣椒","花椒","白醋","糖","盐","淀粉"],steps:"莴笋和胡萝卜切条，焯水。热油炸香花椒干辣椒，捞出。下莴笋胡萝卜，加白醋糖盐快速翻炒，勾芡。"},
{id:490,name:"清炒萝卜",category:"vegetable",ingredients:["白萝卜","蒜","盐","蚝油","花生油","葱花"],steps:"白萝卜去皮切丝。热油爆香蒜，下萝卜丝大火翻炒至软。加盐和蚝油调味，撒葱花。"},
{id:491,name:"红烧萝卜",category:"vegetable",ingredients:["白萝卜","生抽","老抽","蚝油","糖","蒜","葱","高汤"],steps:"白萝卜去皮切块，煎至两面微黄。爆香蒜，加生抽老抽蚝油糖和高汤，放萝卜大火烧开转小火焖20分钟。"},
{id:492,name:"清炒杏鲍菇",category:"vegetable",ingredients:["杏鲍菇","青红椒","蒜","盐","蚝油","花生油"],steps:"杏鲍菇切片焯水挤干。青红椒切片。热油爆香蒜，下杏鲍菇大火翻炒至微黄。加青红椒和盐蚝油调味。"},
{id:493,name:"清炒平菇",category:"vegetable",ingredients:["平菇","青椒","红椒","蒜","蚝油","生抽","盐","花生油"],steps:"平菇撕小朵焯水挤干。青红椒切丝。热油爆香蒜，下平菇大火翻炒至微焦。加青红椒、蚝油、生抽、盐翻炒均匀。"},
{id:494,name:"清炒金针菇",category:"vegetable",ingredients:["金针菇","青红椒","蒜","盐","蚝油","花生油"],steps:"金针菇去根洗净焯水。青红椒切丝。热油爆香蒜，下金针菇大火翻炒。加青红椒丝和盐蚝油调味。"},
{id:495,name:"清炒香菇",category:"vegetable",ingredients:["香菇","青红椒","蒜","盐","蚝油","生抽","花生油"],steps:"香菇泡发切片（也可用新鲜香菇）。热油爆香蒜，下香菇大火翻炒。加青红椒和调料翻炒均匀。"},
{id:496,name:"蚝油香菇",category:"vegetable",ingredients:["香菇","蚝油","生抽","糖","蒜末","葱花","花生油"],steps:"香菇泡发切片。热油爆香蒜末，下香菇翻炒。加蚝油、生抽、糖和少许水，焖煮2分钟，撒葱花。"},
{id:497,name:"清炒口蘑",category:"vegetable",ingredients:["口蘑","青红椒","蒜","盐","蚝油","花生油"],steps:"口蘑切片。热油爆香蒜，下口蘑大火翻炒至出水变软。加青红椒和盐蚝油调味。"},
{id:498,name:"清炒草菇",category:"vegetable",ingredients:["草菇","青红椒","蒜","盐","蚝油","花生油"],steps:"草菇对半切开焯水。热油爆香蒜，下草菇大火翻炒。加青红椒和盐蚝油调味。"},
{id:499,name:"清炒茶树菇",category:"vegetable",ingredients:["茶树菇","青红椒","蒜","盐","蚝油","生抽","花生油"],steps:"茶树菇泡发去根切段。热油爆香蒜，下茶树菇大火翻炒至软。加青红椒和调料翻炒均匀。"},
{id:500,name:"杂菌煲",category:"vegetable",ingredients:["鲜香菇","金针菇","杏鲍菇","蟹味菇","蒜蓉","蚝油","生抽","葱"],steps:"各种菇类洗净。砂锅热油爆香蒜蓉，码入所有菇类。淋蚝油生抽和少许水，盖盖焖8分钟。开盖撒葱花。"},
{id:501,name:"砂锅金针菇",category:"vegetable",ingredients:["金针菇","五花肉","青红椒","蒜","豆瓣酱","生抽","蚝油","糖"],steps:"金针菇去根洗净，五花肉切片。砂锅热油炒香五花肉和豆瓣酱，下金针菇和青红椒翻炒。加调料和水，盖盖焖煮入味。"},
{id:502,name:"油炸花生米",category:"vegetable",ingredients:["花生米","盐","五香粉","花椒粉"],steps:"花生米洗净晾干。冷油下锅，小火慢慢炸至金黄酥脆。捞出趁热撒盐和五香粉拌匀。"},
{id:503,name:"老醋花生",category:"vegetable",ingredients:["花生米","黄瓜","洋葱","生抽","老醋","糖","盐","香油"],steps:"花生米炸至金黄。黄瓜和洋葱切丁。调料混合成醋汁，浇在花生米和蔬菜丁上拌匀。"},
{id:504,name:"凉拌花生",category:"vegetable",ingredients:["花生米","芹菜","胡萝卜","八角","香叶","盐","生抽","香油","陈醋"],steps:"花生米加八角香叶煮熟。芹菜和胡萝卜切丁焯水。所有材料混合，加调料拌匀。"},
{id:505,name:"凉拌腐竹",category:"vegetable",ingredients:["腐竹","木耳","黄瓜","胡萝卜","蒜末","生抽","醋","糖","香油","辣椒油"],steps:"腐竹和木耳泡发洗净切段焯水。黄瓜胡萝卜切丝。所有材料混合，加调料拌匀。"},
{id:506,name:"凉拌豆皮",category:"vegetable",ingredients:["豆皮","黄瓜","胡萝卜","香菜","蒜末","生抽","醋","糖","香油","辣椒油"],steps:"豆皮切丝焯水，黄瓜胡萝卜切丝，香菜切段。所有材料混合，加调料拌匀。"},
{id:507,name:"凉拌豆芽",category:"vegetable",ingredients:["豆芽","黄瓜","胡萝卜","蒜末","香菜","盐","生抽","醋","香油","辣椒油"],steps:"豆芽去根洗净焯水过凉，黄瓜胡萝卜切丝。所有材料混合，加调料拌匀。"},
{id:508,name:"黄瓜拌粉皮",category:"vegetable",ingredients:["黄瓜","粉皮","蒜末","香菜","芝麻酱","生抽","醋","糖","盐","香油"],steps:"粉皮泡软焯水过凉，黄瓜切丝。芝麻酱加调料调成酱汁。材料混合拌匀。"},
{id:509,name:"凉拌黄瓜",category:"vegetable",ingredients:["黄瓜","蒜末","陈醋","生抽","糖","香油","辣椒油","香菜"],steps:"黄瓜拍碎切段。所有调料混合成酱汁。浇在黄瓜上拌匀，腌制10分钟入味。"},
{id:510,name:"糖醋黄瓜",category:"vegetable",ingredients:["黄瓜","干辣椒","花椒","白醋","糖","盐","姜丝"],steps:"黄瓜切条，用盐腌制10分钟去水。热油炸香花椒干辣椒，捞出。加白醋糖和姜丝煮开，冷却后倒在黄瓜上腌制入味。"},
{id:511,name:"酱黄瓜",category:"vegetable",ingredients:["黄瓜","蒜","姜","小红椒","生抽","老抽","蚝油","糖","香油","八角"],steps:"黄瓜切条用盐腌制1小时去水。调料混合煮开冷却。黄瓜条浸入酱汁中腌制过夜。"},
{id:512,name:"拍黄瓜",category:"vegetable",ingredients:["黄瓜","蒜末","盐","生抽","醋","香油","辣椒油","花椒油"],steps:"黄瓜拍碎切段，撒盐腌制10分钟去水分。加蒜末和所有调料拌匀。"},
{id:513,name:"凉拌西红柿",category:"vegetable",ingredients:["西红柿","黄瓜","洋葱","香菜","蒜末","盐","糖","醋","香油"],steps:"西红柿切块，黄瓜切片，洋葱切丝，香菜切段。加蒜末和调料拌匀。"},
{id:514,name:"糖拌西红柿",category:"vegetable",ingredients:["西红柿","白糖","盐"],steps:"西红柿切块，撒上白糖和少许盐，拌匀冷藏后食用。"},
{id:515,name:"西红柿炒蛋",category:"vegetable",ingredients:["番茄","鸡蛋","葱花","盐","糖","番茄酱","花生油"],steps:"鸡蛋打散炒熟盛出。番茄切块入锅炒出汁，加番茄酱和糖。倒回鸡蛋翻炒均匀，撒葱花。"},
{id:516,name:"番茄炒蛋",category:"vegetable",ingredients:["番茄","鸡蛋","盐","糖","葱花","花生油"],steps:"鸡蛋打散炒熟盛出。番茄切块炒出汁，倒回鸡蛋。加盐糖葱花翻炒均匀。"},
{id:517,name:"西红柿烧茄子",category:"vegetable",ingredients:["西红柿","茄子","蒜","盐","糖","生抽","蚝油","葱花"],steps:"茄子切条蒸软。番茄切块炒出汁，下茄子翻炒。加调料和水焖煮入味，撒葱花。"},
{id:518,name:"茄子烧豆角",category:"vegetable",ingredients:["茄子","豆角","蒜","干辣椒","豆瓣酱","生抽","老抽","蚝油","糖"],steps:"茄子和豆角分别炸至软。爆香蒜和豆瓣酱，下茄子和豆角翻炒。加调料和少许水，焖煮入味。"},
{id:519,name:"鱼香茄子",category:"vegetable",ingredients:["茄子","猪肉末","蒜蓉","姜末","豆瓣酱","生抽","陈醋","糖","葱花"],steps:"茄子切条过油或干煸。炒肉末至变色，加豆瓣酱炒出红油。加姜蒜末、生抽、陈醋、糖调成鱼香味。放入茄子翻炒入味，撒葱花。"},
{id:520,name:"红烧茄子",category:"vegetable",ingredients:["茄子","青椒","红椒","蒜","姜","豆瓣酱","生抽","老抽","蚝油","糖"],steps:"茄子切块炸至金黄。爆香蒜姜豆瓣酱，下茄子和青红椒翻炒。加调料和少许水，焖煮入味。"},
{id:521,name:"蒜蓉蒸茄子",category:"vegetable",ingredients:["茄子","蒜蓉","生抽","蚝油","糖","葱花","花生油","辣椒"],steps:"茄子洗净整条蒸10分钟至软。取出撕成条摆盘。蒜蓉炒香加生抽蚝油糖调汁淋上。撒葱花辣椒，淋热油激香。"},
{id:522,name:"凉拌茄子",category:"vegetable",ingredients:["茄子","蒜末","香菜","小米辣","生抽","醋","糖","盐","香油","辣椒油"],steps:"茄子蒸熟撕成条。加蒜末、香菜、小米辣和所有调料拌匀。"},
{id:523,name:"擂茄子",category:"vegetable",ingredients:["茄子","蒜末","葱花","香菜","生抽","醋","糖","盐","香油","辣椒油"],steps:"茄子蒸熟，用筷子撕成条或捣碎。加蒜末、葱花、香菜和所有调料拌匀。"},
{id:524,name:"香煎茄子",category:"vegetable",ingredients:["茄子","鸡蛋","面粉","盐","胡椒粉","花生油"],steps:"茄子切片，裹蛋液和面粉。平底锅热油，中火煎至两面金黄。撒盐和胡椒粉。"},
{id:525,name:"煎酿茄子",category:"vegetable",ingredients:["茄子","猪肉末","香菇","葱花","生抽","蚝油","淀粉","盐"],steps:"茄子切夹刀片。肉末加香菇碎和调料拌匀酿入茄子。平底锅煎至两面金黄。加少许水生抽焖3分钟，勾芡出锅。"},
{id:526,name:"煎酿豆腐",category:"vegetable",ingredients:["老豆腐","猪肉末","香菇","葱花","生抽","蚝油","淀粉","盐"],steps:"豆腐切三角块中间挖小洞。肉末加香菇碎和调料拌匀酿入豆腐。平底锅煎至两面金黄。加少许水生抽焖3分钟，勾芡出锅。"},
{id:527,name:"红烧豆腐",category:"vegetable",ingredients:["老豆腐","木耳","胡萝卜","葱段","生抽","老抽","蚝油","糖","蒜蓉"],steps:"豆腐切三角块煎至两面金黄。木耳泡发撕小朵，胡萝卜切片。爆香蒜蓉，加豆腐、木耳、胡萝卜，加水调料焖10分钟。勾芡撒葱段。"},
{id:528,name:"家常豆腐",category:"vegetable",ingredients:["老豆腐","木耳","青椒","红椒","豆瓣酱","姜蒜末","生抽","老抽","糖","淀粉"],steps:"豆腐切片煎至两面金黄。爆香豆瓣酱和姜蒜，下木耳青红椒翻炒。放豆腐，加调料和水淀粉，焖煮入味。"},
{id:529,name:"麻婆豆腐",category:"vegetable",ingredients:["嫩豆腐","猪肉末","郫县豆瓣酱","花椒粉","豆豉","蒜末","姜末","葱花","生抽","糖"],steps:"豆腐切块焯水。炒肉末至变色，加豆瓣酱、豆豉、姜蒜末炒出红油。加豆腐和调料，小火焖入味，勾芡撒花椒粉和葱花。"},
{id:530,name:"宫保豆腐",category:"vegetable",ingredients:["老豆腐","花生米","干辣椒","花椒","葱段","姜蒜末","生抽","老抽","醋","糖","淀粉"],steps:"豆腐切丁炸至金黄。调宫保汁：生抽+老抽+醋+糖+淀粉+水。热油炸香花椒干辣椒，下豆腐和葱姜蒜，淋汁加花生米。"},
{id:531,name:"锅塌豆腐",category:"vegetable",ingredients:["老豆腐","鸡蛋","面粉","盐","胡椒粉","葱姜末","生抽","蚝油","高汤"],steps:"豆腐切片裹蛋液面粉煎至两面金黄。葱姜末爆香，加生抽、蚝油和高汤，放豆腐小火焖入味。"},
{id:532,name:"溜豆腐",category:"vegetable",ingredients:["老豆腐","青椒","红椒","木耳","豆瓣酱","姜蒜末","生抽","老抽","糖","醋","淀粉"],steps:"豆腐切块炸至金黄。爆香豆瓣酱和姜蒜，下青红椒木耳翻炒。放豆腐，加调料和水淀粉溜炒均匀。"},
{id:533,name:"家常烧豆腐",category:"vegetable",ingredients:["老豆腐","木耳","蘑菇","青椒","豆瓣酱","姜蒜末","生抽","老抽","糖","葱花"],steps:"豆腐切片煎至金黄。爆香豆瓣酱和姜蒜，下木耳蘑菇青椒翻炒。放豆腐，加生抽老抽糖和少许水，焖入味撒葱花。"},
{id:534,name:"素炒豆腐",category:"vegetable",ingredients:["嫩豆腐","葱花","蒜末","盐","蚝油","生抽","香油"],steps:"嫩豆腐切块。热油爆香蒜末，下豆腐轻轻翻炒。加盐、蚝油和生抽调味，撒葱花淋香油。"},
{id:535,name:"清炒豆腐",category:"vegetable",ingredients:["嫩豆腐","豌豆","玉米粒","胡萝卜丁","盐","蚝油","花生油"],steps:"嫩豆腐切小块焯水。热油炒香蔬菜丁，下豆腐轻轻翻炒。加盐和蚝油调味。"},
{id:536,name:"红烧素鸡",category:"vegetable",ingredients:["素鸡","生抽","老抽","蚝油","糖","八角","桂皮","姜","蒜"],steps:"素鸡切厚片煎至两面金黄。爆香姜蒜八角桂皮，下素鸡翻炒。加生抽老抽蚝油糖和少许水，焖煮入味。"},
{id:537,name:"糖醋素鸡",category:"vegetable",ingredients:["素鸡","番茄酱","白醋","糖","盐","淀粉","葱花"],steps:"素鸡切厚片炸至金黄。糖醋汁煮开：番茄酱+白醋+糖+盐+水。倒入素鸡翻炒均匀，撒葱花。"},
{id:538,name:"红烧腐竹",category:"vegetable",ingredients:["腐竹","木耳","香菇","青红椒","生抽","老抽","蚝油","糖","姜蒜"],steps:"腐竹泡软切段，木耳香菇泡发。热油爆香姜蒜，下腐竹木耳香菇翻炒。加调料和少许水，焖煮入味。"},
{id:539,name:"凉拌粉丝",category:"vegetable",ingredients:["粉丝","黄瓜","胡萝卜","蛋皮","蒜末","香菜","生抽","醋","糖","盐","香油","辣椒油"],steps:"粉丝泡软焯水过凉，黄瓜胡萝卜蛋皮切丝。所有材料混合，加调料拌匀。"},
{id:540,name:"蚂蚁上树",category:"vegetable",ingredients:["粉丝","香菇","胡萝卜","青椒","豆瓣酱","姜蒜末","生抽","老抽","糖","葱花"],steps:"粉丝泡软。热油炒香姜蒜末豆瓣酱，下香菇胡萝卜青椒翻炒。加粉丝和调料翻炒均匀，撒葱花。"},
{id:541,name:"酸辣粉",category:"vegetable",ingredients:["红薯粉","黄豆","花生米","榨菜","香菜","葱花","蒜末","生抽","醋","辣椒油","花椒粉","高汤"],steps:"红薯粉煮熟。碗底放榨菜、黄豆、花生米。粉条放入，浇调料和高汤，撒香菜葱花。"},
{id:542,name:"鸭血粉丝汤",category:"vegetable",ingredients:["粉丝","鸭血","鸭肠","鸭肝","豆腐泡","香菜","蒜末","生抽","醋","盐","胡椒粉"],steps:"鸭血切块焯水，粉丝泡软。锅中煮高汤，下粉丝和鸭血、鸭肠、鸭肝煮熟。加调料调味，撒香菜。"},
{id:543,name:"牛肉丸紫菜汤",category:"soup",ingredients:["牛肉丸","紫菜","芹菜末","蒜头油","盐","胡椒粉"],steps:"清水煮开，下牛肉丸煮至浮起。紫菜撕碎放入煮1分钟。加盐、胡椒粉调味，撒芹菜末和蒜头油。"},
{id:544,name:"肉丸汤",category:"soup",ingredients:["猪肉丸","生菜","芹菜末","蒜头油","盐","胡椒粉"],steps:"清水煮开，下肉丸煮至浮起。生菜洗净撕块放入烫软。加盐、胡椒粉调味，撒芹菜末和蒜头油。"},
{id:545,name:"紫菜肉末汤",category:"soup",ingredients:["紫菜","猪肉末","芹菜末","蒜头油","盐","胡椒粉","鱼露"],steps:"肉末加鱼露、胡椒粉拌匀捏成小丸。水开将肉丸下锅煮熟。紫菜撕碎放入，加盐调味，撒芹菜末和蒜头油。"},
// ==================== 追加汤品类 ====================
{id:546,name:"茼蒿肉丸汤",category:"soup",ingredients:["猪前腿肉","茼蒿","姜片","红薯淀粉","盐","白胡椒粉","冰水","香油"],steps:"肉剁糜加淀粉调料搅拌摔打上劲，挤丸子下锅煮浮起，放茼蒿烫软，调味出锅。"},
{id:547,name:"沙参玉竹猪筒骨汤",category:"soup",ingredients:["猪筒骨","沙参","玉竹","麦冬","枸杞","蜜枣","姜片","盐","料酒"],steps:"筒骨焯水，所有材料入锅加水大火煮开转小火煲1.5-2小时。"},
{id:548,name:"鸡骨草猪横脷汤",category:"soup",ingredients:["猪横脷","鸡骨草","薏米","莲子","芡实","蜜枣","姜片","盐"],steps:"猪横脷切厚片焯水。鸡骨草洗净装纱布袋。所有材料入锅加水大火煮开转小火煲2小时。"},
{id:549,name:"马齿苋瘦肉汤",category:"soup",ingredients:["马齿苋","猪瘦肉","姜片","盐","花生油"],steps:"瘦肉切片，马齿苋摘嫩叶洗净。水开加姜片和瘦肉煮5分钟。放入马齿苋烫软，加盐和少许油调味。"},
{id:550,name:"莲藕玉米排骨汤",category:"soup",ingredients:["莲藕","玉米","排骨","胡萝卜","姜片","盐","蜜枣"],steps:"排骨焯水，莲藕玉米胡萝卜切块。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:551,name:"银耳莲子红枣羹",category:"soup",ingredients:["银耳","莲子","红枣","枸杞","冰糖"],steps:"银耳泡发撕小朵，莲子去芯。锅中加水，放银耳莲子红枣大火煮开转小火煲1小时至胶质浓稠。加枸杞和冰糖。"},
{id:552,name:"冬瓜排骨汤",category:"soup",ingredients:["冬瓜","排骨","薏米","姜片","盐","蜜枣"],steps:"排骨焯水，薏米泡水，冬瓜去瓤连皮切块。所有材料入锅加水煲1.5小时。加盐调味。"},
{id:553,name:"莲藕排骨汤",category:"soup",ingredients:["莲藕","排骨","花生","姜片","盐","蜜枣"],steps:"排骨焯水，莲藕去皮切厚块，花生泡水。所有材料入锅加水煲2小时。"},
{id:554,name:"海带排骨汤",category:"soup",ingredients:["海带","排骨","姜片","盐","蜜枣","白醋"],steps:"海带泡发洗净切条，排骨焯水。所有材料入锅加水煲1.5小时。加几滴白醋促钙溶出。"},
{id:555,name:"土豆排骨汤",category:"soup",ingredients:["土豆","排骨","胡萝卜","玉米","姜片","盐","蜜枣"],steps:"排骨焯水，土豆胡萝卜玉米切块。所有材料入锅加水煲1.5小时。"},
{id:556,name:"番茄排骨汤",category:"soup",ingredients:["番茄","排骨","土豆","胡萝卜","姜片","盐","糖"],steps:"排骨焯水，番茄土豆胡萝卜切块。热油炒番茄出汁，加水放排骨煮1小时。"},
{id:557,name:"白萝卜排骨汤",category:"soup",ingredients:["白萝卜","排骨","姜片","枸杞","盐","芹菜末"],steps:"排骨焯水，白萝卜去皮切滚刀块。材料入锅加水煲1小时至萝卜透明。加盐和枸杞，撒芹菜末。"},
{id:558,name:"玉米排骨汤",category:"soup",ingredients:["甜玉米","排骨","胡萝卜","姜片","盐","蜜枣"],steps:"排骨焯水，玉米切段，胡萝卜切滚刀块。所有材料入锅加水煲1.5小时。"},
{id:559,name:"胡萝卜排骨汤",category:"soup",ingredients:["胡萝卜","排骨","玉米","姜片","盐","蜜枣"],steps:"排骨焯水，胡萝卜玉米切块。所有材料入锅加水煲1.5小时。"},
{id:560,name:"莲子排骨汤",category:"soup",ingredients:["莲子","排骨","百合","芡实","姜片","盐","蜜枣"],steps:"排骨焯水，莲子去芯，百合芡实洗净。所有材料入锅加水煲1.5小时。"},
{id:561,name:"花生排骨汤",category:"soup",ingredients:["花生","排骨","眉豆","红枣","姜片","盐"],steps:"排骨焯水，花生眉豆泡水。所有材料入锅加水煲2小时。"},
{id:562,name:"黄豆排骨汤",category:"soup",ingredients:["黄豆","排骨","姜片","盐","蜜枣"],steps:"排骨焯水，黄豆提前泡2小时。所有材料入锅加水煲1.5小时。"},
{id:563,name:"红豆排骨汤",category:"soup",ingredients:["红豆","排骨","莲藕","陈皮","姜片","盐"],steps:"排骨焯水，红豆莲藕陈皮处理好。所有材料入锅加水煲2小时。"},
{id:564,name:"绿豆排骨汤",category:"soup",ingredients:["绿豆","排骨","姜片","盐"],steps:"排骨焯水，绿豆洗净。所有材料入锅加水煲1.5小时至绿豆开花。"},
{id:565,name:"苦瓜排骨汤",category:"soup",ingredients:["苦瓜","排骨","黄豆","咸菜","姜片","盐"],steps:"黄豆提前泡2小时，排骨焯水，苦瓜去瓤切块。所有材料入锅加水煲1.5-2小时。"},
{id:566,name:"冬瓜排骨薏米汤",category:"soup",ingredients:["冬瓜","排骨","薏米","姜片","盐","蜜枣"],steps:"排骨焯水，薏米泡水，冬瓜去瓤连皮切大块。所有材料入锅加水煲1.5小时。"},
{id:567,name:"酸菜排骨汤",category:"soup",ingredients:["酸菜","排骨","姜片","盐","胡椒粉"],steps:"排骨焯水，酸菜切丝泡水。排骨加姜片煲1小时，加入酸菜再煲20分钟。"},
{id:568,name:"枸杞排骨汤",category:"soup",ingredients:["枸杞","排骨","红枣","姜片","盐"],steps:"排骨焯水。所有材料入锅加水煲1.5小时，加枸杞再煲10分钟。"},
{id:569,name:"当归排骨汤",category:"soup",ingredients:["当归","排骨","红枣","枸杞","姜片","料酒","盐"],steps:"排骨焯水。当归切片。所有材料入锅加水煲1.5小时。"},
{id:570,name:"党参排骨汤",category:"soup",ingredients:["党参","排骨","黄芪","红枣","枸杞","姜片","盐"],steps:"排骨焯水。所有材料入锅加水煲1.5小时。"},
{id:571,name:"莲藕猪蹄汤",category:"soup",ingredients:["莲藕","猪蹄","花生","章鱼干","姜片","盐","蜜枣"],steps:"莲藕去皮切厚块，猪蹄焯水，花生泡水，章鱼干泡软。所有材料入锅加水煲2小时至猪蹄软烂。"},
{id:572,name:"黄豆猪蹄汤",category:"soup",ingredients:["黄豆","猪蹄","红枣","姜片","盐"],steps:"猪蹄焯水，黄豆提前泡2小时。所有材料入锅加水煲2小时至软烂。"},
{id:573,name:"花生猪蹄汤",category:"soup",ingredients:["花生","猪蹄","眉豆","红枣","姜片","盐"],steps:"猪蹄焯水，花生眉豆泡水。所有材料入锅加水煲2小时至软烂。"},
{id:574,name:"猪蹄莲藕花生汤",category:"soup",ingredients:["猪蹄","莲藕","花生","姜片","盐","蜜枣"],steps:"莲藕去皮切厚块，猪蹄焯水，花生泡水。所有材料入锅加水煲2小时。"},
{id:575,name:"猪尾花生汤",category:"soup",ingredients:["猪尾","花生","黄豆","红枣","姜片","盐"],steps:"猪尾斩段焯水，花生黄豆泡水。所有材料入锅加水煲2小时。"},
{id:576,name:"猪尾莲藕汤",category:"soup",ingredients:["猪尾","莲藕","花生","红枣","姜片","盐"],steps:"猪尾斩段焯水，莲藕去皮切块，花生泡水。所有材料入锅加水煲2小时。"},
{id:577,name:"猪骨莲藕汤",category:"soup",ingredients:["莲藕","猪骨","花生","章鱼干","姜片","盐","蜜枣"],steps:"莲藕去皮切厚块，猪骨焯水，花生泡水，章鱼干泡软。所有材料入锅加水煲2小时。"},
{id:578,name:"猪骨玉米汤",category:"soup",ingredients:["猪骨","玉米","胡萝卜","姜片","盐","蜜枣"],steps:"猪骨焯水，玉米胡萝卜切块。所有材料入锅加水煲1.5小时。"},
{id:579,name:"猪骨萝卜汤",category:"soup",ingredients:["猪骨","白萝卜","胡萝卜","玉米","姜片","盐","蜜枣"],steps:"猪骨焯水。萝卜去皮切块，玉米切段。所有材料入锅加水煲1.5小时。"},
{id:580,name:"猪骨土豆汤",category:"soup",ingredients:["猪骨","土豆","胡萝卜","姜片","盐","芹菜末"],steps:"猪骨焯水，土豆胡萝卜切块。所有材料入锅加水煲1.5小时。"},
{id:581,name:"猪骨海带汤",category:"soup",ingredients:["猪骨","海带","黄豆","姜片","盐","蜜枣"],steps:"猪骨焯水，海带泡发切条，黄豆泡水。所有材料入锅加水煲1.5小时。"},
{id:582,name:"猪骨冬瓜汤",category:"soup",ingredients:["猪骨","冬瓜","薏米","姜片","盐","蜜枣"],steps:"猪骨焯水，薏米泡水，冬瓜去瓤连皮切大块。所有材料入锅加水煲1.5小时。"},
{id:583,name:"猪骨苦瓜汤",category:"soup",ingredients:["猪骨","苦瓜","黄豆","咸菜","姜片","盐"],steps:"猪骨焯水，苦瓜去瓤切块，黄豆泡水。所有材料入锅加水煲1.5-2小时。"},
{id:584,name:"牛肉丸紫菜汤",category:"soup",ingredients:["牛肉丸","紫菜","芹菜末","蒜头油","盐","胡椒粉"],steps:"清水煮开，下牛肉丸煮至浮起。紫菜撕碎放入煮1分钟。加盐、胡椒粉调味，撒芹菜末和蒜头油。"},
{id:585,name:"牛肉丸萝卜汤",category:"soup",ingredients:["牛肉丸","白萝卜","姜片","盐","芹菜末","香菜"],steps:"白萝卜切块加水煮开，下牛肉丸煮至浮起。加姜片和盐煮10分钟，撒芹菜末香菜。"},
{id:586,name:"牛肉丸西红柿汤",category:"soup",ingredients:["牛肉丸","番茄","土豆","胡萝卜","姜片","盐","葱花"],steps:"番茄土豆胡萝卜切块。锅中加水煮开，放牛肉丸和蔬菜煮30分钟。加盐调味撒葱花。"},
{id:587,name:"牛肉丸冬瓜汤",category:"soup",ingredients:["牛肉丸","冬瓜","姜片","盐","香菜"],steps:"冬瓜去皮切块加水煮开，下牛肉丸煮至浮起。加盐调味撒香菜。"},
{id:588,name:"牛肉丸紫菜蛋花汤",category:"soup",ingredients:["牛肉丸","紫菜","鸡蛋","芹菜末","盐","胡椒粉"],steps:"水开下牛肉丸煮至浮起。紫菜撕碎放入，鸡蛋打散淋入成蛋花。加盐胡椒粉调味，撒芹菜末。"},
{id:589,name:"羊肉汤",category:"soup",ingredients:["羊肉","白萝卜","当归","姜片","料酒","盐","香菜"],steps:"羊肉切块焯水。白萝卜切块。所有材料入锅加水煲2小时至羊肉软烂。"},
{id:590,name:"羊肉胡萝卜汤",category:"soup",ingredients:["羊肉","胡萝卜","白萝卜","姜片","料酒","盐","香菜"],steps:"羊肉切块焯水，胡萝卜白萝卜切块。所有材料入锅加水煲2小时。"},
{id:591,name:"羊排萝卜汤",category:"soup",ingredients:["羊排","白萝卜","姜片","葱段","料酒","盐","香菜"],steps:"羊排斩段焯水，白萝卜切块。所有材料入锅加水煲1.5小时。"},
{id:592,name:"鸡汤",category:"soup",ingredients:["鸡肉","姜片","葱段","料酒","盐","枸杞"],steps:"鸡肉斩块焯水。加姜片葱段料酒，大火煮开转小火煲1.5小时。加盐和枸杞调味。"},
{id:593,name:"香菇鸡汤",category:"soup",ingredients:["鸡肉","干香菇","红枣","枸杞","姜片","盐","料酒"],steps:"香菇泡发去蒂，鸡肉焯水。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:594,name:"茶树菇鸡汤",category:"soup",ingredients:["鸡肉","干茶树菇","红枣","枸杞","姜片","盐"],steps:"茶树菇泡发去根，鸡肉焯水。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:595,name:"板栗鸡汤",category:"soup",ingredients:["鸡肉","板栗","红枣","枸杞","姜片","盐"],steps:"鸡肉斩块焯水，板栗去壳。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:596,name:"山药鸡汤",category:"soup",ingredients:["鸡肉","山药","红枣","枸杞","姜片","盐"],steps:"鸡肉斩块焯水，山药去皮切段。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:597,name:"莲子鸡汤",category:"soup",ingredients:["鸡肉","莲子","百合","红枣","枸杞","姜片","盐"],steps:"鸡肉斩块焯水，莲子去芯。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:598,name:"红枣鸡汤",category:"soup",ingredients:["鸡肉","红枣","枸杞","黄芪","姜片","盐"],steps:"鸡肉斩块焯水。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:599,name:"当归鸡汤",category:"soup",ingredients:["鸡肉","当归","红枣","枸杞","姜片","料酒","盐"],steps:"鸡肉斩块焯水，当归切片。所有材料入锅加料酒和水大火煮开转小火煲1.5小时。"},
{id:600,name:"黄芪枸杞鸡汤",category:"soup",ingredients:["鸡肉","黄芪","枸杞","红枣","姜片","盐"],steps:"鸡肉斩块焯水。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:601,name:"党参黄芪鸡汤",category:"soup",ingredients:["鸡肉","党参","黄芪","红枣","枸杞","姜片","盐"],steps:"鸡肉斩块焯水。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:602,name:"首乌红枣鸡汤",category:"soup",ingredients:["鸡肉","何首乌","红枣","枸杞","姜片","盐"],steps:"鸡肉斩块焯水，何首乌切片。所有材料入锅加水大火煮开转小火煲1.5小时。"},
{id:603,name:"鹿茸鸡汤",category:"soup",ingredients:["鸡肉","鹿茸","红枣","枸杞","姜片","盐","料酒"],steps:"鸡肉斩块焯水，鹿茸切片。所有材料入锅加料酒和水大火煮开转小火煲1.5小时。"},
{id:604,name:"乌鸡汤",category:"soup",ingredients:["乌鸡","红枣","枸杞","姜片","料酒","盐"],steps:"乌鸡处理干净斩块焯水。所有材料入锅加料酒和水大火煮开转小火煲2小时。"},
{id:605,name:"黑豆乌鸡汤",category:"soup",ingredients:["乌鸡","黑豆","红枣","枸杞","姜片","盐"],steps:"乌鸡斩块焯水，黑豆提前泡2小时。所有材料入锅加水大火煮开转小火煲2小时。"},
{id:606,name:"红枣乌鸡汤",category:"soup",ingredients:["乌鸡","红枣","枸杞","黄芪","姜片","盐"],steps:"乌鸡斩块焯水。所有材料入锅加水大火煮开转小火煲2小时。"},
{id:607,name:"当归乌鸡汤",category:"soup",ingredients:["乌鸡","当归","红枣","枸杞","姜片","料酒","盐"],steps:"乌鸡斩块焯水，当归切片。所有材料入锅加料酒和水大火煮开转小火煲2小时。"},
{id:608,name:"首乌乌鸡汤",category:"soup",ingredients:["乌鸡","何首乌","红枣","枸杞","姜片","盐"],steps:"乌鸡斩块焯水，何首乌切片。所有材料入锅加水大火煮开转小火煲2小时。"},
{id:609,name:"鸭汤",category:"soup",ingredients:["鸭肉","姜片","葱段","料酒","盐","枸杞"],steps:"鸭肉斩块焯水。加姜片葱段料酒，大火煮开转小火煲1.5小时。"},
{id:610,name:"冬瓜老鸭汤",category:"soup",ingredients:["老鸭","冬瓜","薏米","陈皮","姜片","盐","蜜枣"],steps:"老鸭斩块焯水。冬瓜连皮去瓤切大块，薏米泡水。所有材料入锅加水煲2小时。"},
{id:611,name:"茶树菇老鸭汤",category:"soup",ingredients:["老鸭","干茶树菇","红枣","枸杞","姜片","盐","料酒"],steps:"茶树菇泡发，老鸭斩块焯水。所有材料入锅加料酒和水煲2小时。"},
{id:612,name:"笋干老鸭汤",category:"soup",ingredients:["老鸭","笋干","火腿","姜片","葱段","料酒","盐"],steps:"笋干提前泡发切段，老鸭斩块焯水。所有材料入锅加料酒和水煲2小时。"},
{id:613,name:"莲子老鸭汤",category:"soup",ingredients:["老鸭","莲子","芡实","百合","姜片","料酒","盐"],steps:"老鸭斩块焯水，莲子去芯。所有材料入锅加料酒和水煲2小时。"},
{id:614,name:"酸萝卜老鸭汤",category:"soup",ingredients:["老鸭","酸萝卜","姜片","葱段","料酒","盐"],steps:"老鸭斩块焯水。锅中加水、姜片、葱段和料酒，放鸭肉大火烧开转小火煲1.5小时。加入酸萝卜再煲30分钟。"},
{id:615,name:"冬瓜排骨汤",category:"soup",ingredients:["冬瓜","排骨","薏米","姜片","盐","蜜枣"],steps:"排骨焯水，薏米泡水，冬瓜去瓤连皮切块。所有材料入锅加水煲1.5小时。"},
{id:616,name:"苦瓜排骨汤",category:"soup",ingredients:["苦瓜","排骨","黄豆","咸菜","姜片","盐"],steps:"黄豆提前泡2小时，排骨焯水，苦瓜去瓤切块。所有材料入锅加水煲1.5-2小时。"},
{id:617,name:"黄豆排骨汤",category:"soup",ingredients:["黄豆","排骨","姜片","盐","蜜枣"],steps:"排骨焯水，黄豆提前泡2小时。所有材料入锅加水煲1.5小时。"},
{id:618,name:"紫菜蛋花汤",category:"soup",ingredients:["紫菜","鸡蛋","葱花","盐","胡椒粉","香油"],steps:"水烧开，紫菜撕碎放入煮1分钟。鸡蛋打散沿筷子缓缓倒入锅中形成蛋花。加盐、胡椒粉和香油调味，撒葱花。"},
{id:619,name:"番茄蛋花汤",category:"soup",ingredients:["番茄","鸡蛋","葱花","盐","糖","花生油","姜丝"],steps:"番茄切块热油炒出汁。加开水煮开，加姜丝煮3分钟。鸡蛋打散倒入锅中形成蛋花。加盐和少许糖调味，撒葱花。"},
{id:620,name:"紫菜虾皮汤",category:"soup",ingredients:["紫菜","虾皮","葱花","盐","胡椒粉","香油","生抽"],steps:"水烧开，紫菜撕碎放入煮1分钟。放入虾皮煮30秒。加盐、胡椒粉、生抽和香油调味，撒葱花。"}
];